/* 七訣鬥法題庫 · 國中版 300 題（2026-07-08 五選項制改版）
   h=習慣索引0-6；每題五選項 q 0(最佳·全額攻擊)/1(次佳·半額)/2(常人直覺不符柯維)/3(柯維概念但離題)/4(錯誤) 各一，tag=柯維講評
   舊 236 題四選項版備份：/tmp/duel_bank/questions_v236_backup.js */
window.DUEL_QS_JR=[{"h":0,"text":"月考成績發下來，你的分數比預期低很多，下課時同學圍在一起抱怨題目太刁、老師教得爛，還拉你一起罵，你握著考卷心裡悶悶的。","c":[{"t":"跟著大家一起罵題目，先求心裡痛快","q":2,"tag":"罵完痛快一時，分數原封不動——你把力氣全花在管不動的關注圈。"},{"t":"翻開考卷找出錯因，列弱點排進複習","q":0,"tag":"✓ 主動積極：不怪環境，把力氣收回影響圈——錯因是你唯一能改變的部分。"},{"t":"把考卷藏起來，聯絡簿簽名自己仿造","q":4,"tag":"⚠ 仿造簽名是欺騙，逃過一時卻賠上信任，問題還會加倍回來找你。"},{"t":"先寫下人生大目標，成績以終為始再說","q":3,"tag":"☯ 以終為始是好概念，但眼前的問題是先弄懂錯在哪，不是重寫人生目標。"},{"t":"告訴自己下次加油，但沒排任何計畫","q":1,"tag":"◐ 心態對了但沒落地，主動是現在就做一件具體的事，不是只喊口號。"}]},{"h":0,"text":"午休走廊上，有人故意撞你肩膀還嗆「不會走路喔」，圍觀同學起鬨等著看好戲，你的火氣一下衝上來，對方還挑釁地盯著你。","c":[{"t":"先傾聽他為何撞人，知彼解己再回應","q":3,"tag":"☯ 知彼解己用在溝通，但面對挑釁當下要先管好自己的回應，不是先訪談他。"},{"t":"當下忍住不吭聲，整天悶悶不樂想著","q":1,"tag":"◐ 忍住是好的開始，但情緒仍被他綁架一整天，真正的主動是放下再行動。"},{"t":"深呼吸不動怒，事後循正當管道處理","q":0,"tag":"✓ 刺激與回應之間有空隙，那裡住著你的選擇權——這就是主動積極。"},{"t":"放學約人堵他，讓他知道惹你的下場","q":4,"tag":"⚠ 以暴制暴看似出氣，卻把小事鬧成大禍，最後賠進去的是自己。"},{"t":"當場回嗆回去，氣勢上絕對不能輸他","q":2,"tag":"回嗆看似不吃虧，其實你的反應由他決定，主動權已拱手讓人。"}]},{"h":0,"text":"自然課分組報告下週一要交，你負責的部分一個字都還沒動，每天回家都想「明天再寫」，回神過來已經是星期四晚上了。","c":[{"t":"排好完整計畫表，但今天仍沒動筆寫","q":1,"tag":"◐ 計畫是準備不是行動，再美的表格沒有第一個字，都還停在原地。"},{"t":"週日深夜直接抄網路文章交差了事","q":4,"tag":"⚠ 抄襲賭的是不被抓到，賠上的是誠信和真正學會的機會。"},{"t":"今晚先寫開頭十分鐘，破除拖延慣性","q":0,"tag":"✓ 主動不必等情緒到位，先動起來，動力往往是做了之後才出現的。"},{"t":"等比較有靈感的那天，再一口氣寫完","q":2,"tag":"把開工鑰匙交給靈感，等於把結果交給運氣——主動的人創造心情。"},{"t":"先去運動放鬆更新自己，回來再面對","q":3,"tag":"☯ 不斷更新是長期保養，拖了四天的報告需要的是現在動筆，不是先去放鬆。"}]},{"h":0,"text":"第三節下課，教室地上散著紙屑和飲料罐，值日生請假沒掃，老師下一節要來檢查教室整潔，大家都當作沒看見繼續聊天。","c":[{"t":"把垃圾踢到別班走廊，先眼不見為淨","q":4,"tag":"⚠ 眼前乾淨了，品格髒了——把麻煩丟給別人，這種聰明是陷阱。"},{"t":"抱怨值日生太混，等他回來再跟他算","q":2,"tag":"力氣花在指責，地還是髒的——你困在關注圈，沒踏進能動手的影響圈。"},{"t":"心想該有人去弄，自己卻也站著沒動","q":1,"tag":"◐ 看見了也認同該做，卻停在念頭——主動的最後一哩是身體真的動起來。"},{"t":"自己先動手撿，再邀大家一起快整理","q":0,"tag":"✓ 不糾結是誰的責任，先做自己當下能做的——在影響圈裡先動起來。"},{"t":"提議先開會訂雙贏的打掃公約再處理","q":3,"tag":"☯ 雙贏公約是好制度，但老師五分鐘後就到，現在需要的是先彎腰動手。"}]},{"h":0,"text":"中午合作社大排長龍，你排了十分鐘快輪到時，有個學長大剌剌插到你前面，還一臉無所謂地滑手機，後面同學都在看你怎麼辦。","c":[{"t":"不出聲但越想越氣，整頓飯都不開心","q":1,"tag":"◐ 沒爆發是好的，但情緒被他牽動一整餐——主動是把氣轉成平靜的處理。"},{"t":"平靜提醒他請排隊，不動怒也不退讓","q":0,"tag":"✓ 刺激與回應之間你有選擇——既不爆氣也不委屈，穩穩守住分際。"},{"t":"從後面推他一把，開口罵給他難看","q":4,"tag":"⚠ 動手把小事鬧成大事，看似出了氣，卻可能惹上更大的麻煩。"},{"t":"想成雙贏：讓他先買，自己改吃別的","q":3,"tag":"☯ 雙贏不是單方退讓，遇到不合理的事，先勇敢守住界線才談得上雙贏。"},{"t":"也擠到別人前面，把時間扳回這一城","q":2,"tag":"用別人的錯合理化自己的錯，你的行為就被對方決定了。"}]},{"h":0,"text":"數學你連續三次段考都不及格，開始覺得「我就是沒有數學細胞」，看到習題就想闔上課本，補習班同學卻好像一聽就懂。","c":[{"t":"安慰自己這科本來就難，低分很正常","q":2,"tag":"替放棄找體面的藉口，聽來合理，其實是把改變的機會推開。"},{"t":"乾脆整科放棄，考試全部用猜的就好","q":4,"tag":"⚠ 一句沒天分就棄械投降，等於提早關門——放棄會變成習慣。"},{"t":"換讀書方法、找老師問，多練能改的","q":0,"tag":"✓ 不被「天分」這頂帽子定義，把注意力放在自己能調整的方法上。"},{"t":"嘴上說要加油，方法卻還是一成不變","q":1,"tag":"◐ 喊加油卻用同一套無效方法，結果不會變——主動是真的換一個做法。"},{"t":"先想像會考放榜那天，以終為始激勵","q":3,"tag":"☯ 以終為始能給方向，但你現在卡的是方法無效，先換做法比想像未來急。"}]},{"h":0,"text":"放學掃地時間，你看到隔壁班幾個人圍著一個同學，用難聽的綽號輪流嘲笑他，他低著頭不敢說話，周圍沒有任何人出聲。","c":[{"t":"先同理霸凌者，聽懂他為什麼要罵人","q":3,"tag":"☯ 知彼解己是溝通功夫，但有人正在受傷，當下先保護人比理解加害者急。"},{"t":"在能力內出聲緩頰，或私下告訴師長","q":0,"tag":"✓ 不必逞英雄，但在能力範圍內負起責任——這正是影響圈裡該做的事。"},{"t":"想說又不關我的事，轉頭繼續掃地","q":2,"tag":"用「不關我事」把自己摘乾淨，沉默其實也是一種選擇。"},{"t":"怕被那群人針對，跟著笑兩聲自保","q":4,"tag":"⚠ 為自保加入欺負的一方，是把恐懼變成幫凶，也丟了自己的底線。"},{"t":"心裡很不忍，卻始終沒有做任何事","q":1,"tag":"◐ 於心不忍是良知，但只停在心裡，被欺負的人感受不到你的善意。"}]},{"h":0,"text":"班際籃球賽最後一秒，隊友傳球失誤讓你們輸了冠軍，全隊沉默走回教室，他紅著眼眶不敢看大家，你剛好走在他旁邊。","c":[{"t":"拍拍他說沒關係別想太多，就結束了","q":1,"tag":"◐ 心意是暖的，但少了「我們能改什麼」那一步，安慰才會變成力量。"},{"t":"回家先寫使命宣言，想清打球的目的","q":3,"tag":"☯ 使命宣言是習慣二的功課，此刻隊友需要的是被接住，不是人生哲學。"},{"t":"說「下次我們補位再快點」一起檢討","q":0,"tag":"✓ 把焦點放回「我們能改什麼」的影響圈——這就是主動積極的語言。"},{"t":"當眾說「傳那什麼球」讓他記取教訓","q":4,"tag":"⚠ 當眾補刀出了氣，卻踩碎隊友的心，下次沒人敢跟你同隊。"},{"t":"嘆氣說「都怪裁判最後那顆吹太爛」","q":2,"tag":"怪裁判最輕鬆，但比分不會改變——力氣花在管不動的關注圈。"}]},{"h":0,"text":"早自習你被臨時抽到支援打掃外掃區，一到現場發現滿地落葉還有前一天的垃圾，其他支援的同學都還沒到，只有你一個人。","c":[{"t":"先動手清一塊，等人到了再分工合作","q":0,"tag":"✓ 不等條件完美才行動——先做能做的那一塊，就是主動積極。"},{"t":"心想又不是我弄髒的，站著滑手機等","q":2,"tag":"「不是我的錯」跟「不是我的事」是兩回事——站著等不會讓地變乾淨。"},{"t":"把落葉掃到隔壁班區域，眼前先乾淨","q":4,"tag":"⚠ 眼前乾淨了，品格髒了——把麻煩丟給別班，這種聰明是陷阱。"},{"t":"站著等大家到齊，再一起開始打掃","q":1,"tag":"◐ 肯掃是好的，但把「開始」的權力交給了別人，你其實現在就能動。"},{"t":"先列打掃優先順序表，要事第一再動","q":3,"tag":"☯ 要事第一用在排程，眼前就一件事：掃地。列表反而成了不動手的藉口。"}]},{"h":0,"text":"四天連假第一天早上，你攤開聯絡簿發現作業有七項，還有一張數學考卷要訂正，弟弟在旁邊打電動，你越看越覺得煩躁。","c":[{"t":"先抱怨老師出太多，今天耍廢再說","q":2,"tag":"抱怨是把遙控器交給別人，你的假期正被情緒接管。"},{"t":"訂好完美讀書計畫，決定明天開始","q":1,"tag":"◐ 計畫很好，但「明天開始」常常是拖延穿的外衣，今天先做一小項吧。"},{"t":"列出作業清單，挑今天能做的先動工","q":0,"tag":"✓ 化整為零、立刻開始——主動的人先動手，動完通常就不用抱怨了。"},{"t":"先跟同學借作業來抄，最節省時間","q":4,"tag":"⚠ 抄來的省時，是用你的學習和誠信去換的——這是高利貸。"},{"t":"找弟弟統合綜效，先一起打電動再說","q":3,"tag":"☯ 統合綜效是合作創造第三方案，不是幫「一起耍廢」找漂亮的名字。"}]},{"h":0,"text":"你這學期已經遲到五次，每次都怪鬧鐘、怪公車、怪媽媽沒叫你。今晚睡前你還在滑手機，明天又是要早自習考試的日子。","c":[{"t":"打算乾脆翹掉早自習，直接睡到飽","q":4,"tag":"⚠ 用逃避解決遲到，等於用大洞補小洞，還多一筆缺考紀錄。"},{"t":"先寫一份晨型人使命宣言貼在牆上","q":3,"tag":"☯ 使命宣言管方向，治不了明早的賴床——今晚需要的是具體的環境設計。"},{"t":"心裡發誓明天鬧鐘一響就立刻起床","q":1,"tag":"◐ 有決心沒設計，意志力在被窩面前常常敗陣，要靠環境幫自己一把。"},{"t":"鬧鐘放遠一點，現在就放下手機睡","q":0,"tag":"✓ 改變上游條件，比早上跟意志力硬拚聰明——這是對自己的人生負責。"},{"t":"交代媽媽明天一定要記得挖你起床","q":2,"tag":"把自己的責任外包給別人，遲到的劇本不會改。"}]},{"h":0,"text":"上課時你低頭趕別科作業，沒聽到老師點名，老師當著全班念你「上課都不專心」，全班都轉頭看你，一股火直衝喉嚨。","c":[{"t":"立刻舉手要求雙贏協商上課的規則","q":3,"tag":"☯ 雙贏協商是好工具，但當眾談判只會火上加油，先冷靜才有協商空間。"},{"t":"小聲嗆回「又不是只有我沒在聽」","q":2,"tag":"嗆回去的瞬間，你把今天一整天的心情交給了老師的一句話。"},{"t":"深呼吸先吞下這口氣，下課再去說明","q":0,"tag":"✓ 你在刺激與回應之間按下暫停鍵——那半秒的空隙就是你的自由。"},{"t":"故意把筆袋重重一摔，表達你的不爽","q":4,"tag":"⚠ 摔得很大聲，全班都看到了——看到的是你輸給了那句話。"},{"t":"低頭不說話，整節課都在心裡罵老師","q":1,"tag":"◐ 表面沒事，但腦袋被那句話租走一整節課——而且租金是你付的。"}]},{"h":0,"text":"被老師當眾誤會上課不專心之後，下課鐘響了，老師還站在講桌前收東西，同學在門口等你去打球，你猶豫要不要走過去說清楚。","c":[{"t":"走過去質問「老師您憑什麼念我」","q":4,"tag":"⚠ 你走對了方向卻帶錯武器，「討公道」一開口，台階就變成戰場。"},{"t":"心想反正講了也沒用，轉身去打球了","q":1,"tag":"◐ 「反正沒用」是最省力的台詞，但你根本還沒講過，怎麼知道沒用？"},{"t":"決定回家寫週計畫，把讀書排進要事","q":3,"tag":"☯ 要事第一排的是時間，解不開誤會——眼前該做的是先把話說開。"},{"t":"走過去平靜說明剛在趕作業，非故意","q":0,"tag":"✓ 主動說明不是認錯比賽——你拿回了這個故事的解釋權。"},{"t":"回座位跟同學抱怨老師根本針對你","q":2,"tag":"「針對我」三個字一出口，所有改變的可能都被關掉了。"}]},{"h":0,"text":"段考數學考卷發下來，鮮紅的五十八分躺在桌上，前後同學都在互相報分數，你盯著考卷，各種念頭一下子全部冒了出來。","c":[{"t":"怪這次題目太難，老師又教得超爛","q":2,"tag":"也許有部分是真的，但這句話講完，你的五十八分有動嗎？沒有。"},{"t":"把考卷塞進抽屜最深處，眼不見為淨","q":1,"tag":"◐ 考卷不會咬你，但下一次段考會——躲得過今天躲不過下次。"},{"t":"偷改分數再拿回家給爸媽簽名了事","q":4,"tag":"⚠ 改分數是欺騙，被拆穿賠上的信任，比五十八分難補一百倍。"},{"t":"先訂完整複習時程表，其他之後再說","q":3,"tag":"☯ 排時程是習慣三，但還沒弄清錯在哪就排表，複習只會複習到寂寞。"},{"t":"翻開看錯的是粗心、不會還是沒讀到","q":0,"tag":"✓ 把力氣花在「我能動的事」上面——這個圈，就叫做影響圈。"}]},{"h":0,"text":"訂正考卷時你發現，錯的題目裡有六題全是同一種函數題型，今晚還有補習班的作業要寫，時間看起來不太夠用，你得做選擇。","c":[{"t":"嘆氣說自己天生就沒有數學細胞","q":2,"tag":"這句話把「暫時還不會」偷偷改寫成「永遠都不行」——最毒的合約。"},{"t":"決定直接背答案，這題型放棄算了","q":4,"tag":"⚠ 放棄一個題型省了今晚，賠掉的是往後它每次出現的分數。"},{"t":"打算下週找一天，再一次全部補齊","q":1,"tag":"◐ 「下週的我」是個很會躲的傢伙，你大概率找不到他。"},{"t":"圈起來，今晚先把這一種題型弄懂","q":0,"tag":"✓ 不是「我要發憤圖強」的大話，是今晚就做得到的小承諾——最有力。"},{"t":"先去運動更新身心，讀書效率更好","q":3,"tag":"☯ 不斷更新是好習慣，但此刻弱點就攤在眼前，先補洞再談保養。"}]},{"h":0,"text":"分組報告你被分到都不熟的一組，心裡覺得倒楣，討論時卻發現平常超安靜的組員做簡報超強，版面排得像設計師做的一樣。","c":[{"t":"心想還好有人會做，自己可以輕鬆了","q":1,"tag":"◐ 從「被分到爛組」變成「搭便車」，方向對了一半，可惜只有一半。"},{"t":"酸他「這麼厲害，整份都你做囉」","q":4,"tag":"⚠ 別人的強被你一句酸話推開，你親手把隊友變成對手。"},{"t":"還是悶悶想著跟好友一組會更高分","q":2,"tag":"你在用「如果當初」折磨現在的自己，那個平行宇宙不存在。"},{"t":"直接請教他版面怎麼排，跟他學一手","q":0,"tag":"✓ 主動的人永遠先看到別人的好——這一組沒你想的差。"},{"t":"提議先訂小組使命宣言再開始分工","q":3,"tag":"☯ 使命宣言用在長期團隊，眼前更該做的是把握身邊現成的高手。"}]},{"h":0,"text":"午休鬥牛最後一球你漏接，輸掉比賽，隊友當著大家的面說「就是那球啦」，那句話還懸在空中，所有人的眼神都看向你。","c":[{"t":"把球往地上一砸，說不打了隨便你們","q":4,"tag":"⚠ 你砸的不是球，是隊友的信任——氣消之後，那一砸還在大家心裡。"},{"t":"回嗆「你上半場漏接幾顆要不要算」","q":2,"tag":"互相翻舊帳，球場上瞬間誕生兩個被情緒操控的人。"},{"t":"承認那球該接的，說下次會站前面點","q":0,"tag":"✓ 認下自己的那一份、只認自己的那一份——這比嗆回去難十倍。"},{"t":"悶著頭走掉，整個午餐都吃不下飯","q":1,"tag":"◐ 你沒有回嗆，但你讓那句話在肚子裡繼續發酵，悶著不等於消化。"},{"t":"提議賽後開檢討會，統合綜效找戰術","q":3,"tag":"☯ 統合綜效是好方向，但當下大家在氣頭上，先接住情緒才開得成會。"}]},{"h":0,"text":"下午，那個當眾怪你漏接的隊友跑來，搔著頭說「剛剛我講太大聲，歹勢啦」，附近同學都在偷看你們，你手上還拿著掃把。","c":[{"t":"先要求他寫檢討，以終為始避免再犯","q":3,"tag":"☯ 以終為始不是拿來刁難道歉的人，別人伸出手，先接住比較重要。"},{"t":"說沒事，順口約他下次午休練接球","q":0,"tag":"✓ 把一場衝突變成一個邀請——這是主動積極的進階技巧。"},{"t":"回他「現在才道歉？早幹嘛去了」","q":4,"tag":"⚠ 他鼓起勇氣走過來被你噎回去，下次他寧可不道歉——你教會他的。"},{"t":"哼一聲別過頭，暫時不想理這個人","q":2,"tag":"他遞出來的台階，你一腳踢掉了——爽三秒，虧三週。"},{"t":"嘴上說沒事，心裡決定再也不同隊","q":1,"tag":"◐ 「沒事」如果是假的，心結就還在——只是改成在心裡慢慢打。"}]},{"h":0,"text":"你放學回家累癱在沙發上滑手機，才十分鐘媽媽就開始念「一回來就滑手機，作業寫了沒」，那把熟悉的火又衝了上來。","c":[{"t":"回嘴「我才剛回來欸，你每次都這樣」","q":2,"tag":"「每次」「都」一出口，戰爭正式開打，今晚家裡不會有好空氣。"},{"t":"戴上耳機假裝沒聽到，看她能念多久","q":4,"tag":"⚠ 你用沉默宣戰，她用音量回擊——十分鐘休息賠上一整晚低氣壓。"},{"t":"一句話也不說，起身甩門走進房間","q":1,"tag":"◐ 門關上了，但火還在房間裡燒——燒的是你自己。"},{"t":"說「我滑十分鐘，七點開始寫可以嗎」","q":0,"tag":"✓ 你沒有否認自己需要休息——只是把它變成一個可以被同意的計畫。"},{"t":"反問媽媽的教養目標，請她以終為始","q":3,"tag":"☯ 概念聽起來高級，其實是把矛頭丟回媽媽身上——先管好自己的回應。"}]},{"h":0,"text":"你跟媽媽約好七點開始寫作業，她也答應讓你先休息。七點整鬧鐘響起，手遊剛好打到一半，隊友還在語音裡等你推塔。","c":[{"t":"說再打完這場就好，七點十五才放下","q":1,"tag":"◐ 晚十五分鐘不會死，但「我說到做到」的存款少了一筆。"},{"t":"改列今晚時間矩陣，重新排要事順序","q":3,"tag":"☯ 時間矩陣是習慣三的工具，此刻的考題只有一個：守住自己說過的話。"},{"t":"裝忘記約定，硬是繼續打到被抓包","q":4,"tag":"⚠ 下次你再說「七點開始」的時候，這句話已經不值錢了。"},{"t":"跟隊友說聲先退，然後闔上手機寫字","q":0,"tag":"✓ 對自己的小承諾說到做到——這就是三十天挑戰的第一天。"},{"t":"心想媽媽沒在看，多打半小時沒差","q":2,"tag":"說到做到從來不是做給別人看的——沒人看的時候，才是真章。"}]},{"h":0,"text":"你回房發現最寶貝的耳機被讀幼兒園的弟弟拆了，線扯斷、耳罩裂開，他還坐在地上玩零件，你的怒氣值瞬間衝到滿格。","c":[{"t":"什麼都不說，默默弄壞他最愛的玩具","q":4,"tag":"⚠ 以壞還壞，你贏了一回合，輸掉的是「哥哥」兩個字的分量。"},{"t":"先離開現場倒杯水，冷靜了再來處理","q":0,"tag":"✓ 最強的暫停鍵不是「忍住」，是「先走開」——空隙自己創造。"},{"t":"衝去吼他，把上月弄壞的帳一起算","q":2,"tag":"吼完，耳機會復活嗎？不會。但你們的關係多斷了一邊。"},{"t":"先同理傾聽弟弟，了解他拆耳機動機","q":3,"tag":"☯ 傾聽是習慣五，但怒氣滿格時先處理自己的情緒，才輪得到理解別人。"},{"t":"直接衝去跟媽媽告狀，吵著要他賠","q":1,"tag":"◐ 告狀合理，但你把處理權連同情緒一起外包出去了。"}]},{"h":0,"text":"爸爸上週答應這週六帶你去看電影，你期待了一整週，週五晚上他卻說公司臨時加班要取消，失望沉沉地壓了下來。","c":[{"t":"體諒說沒關係，工作本來就是爸爸要事","q":3,"tag":"☯ 體諒很好，但吞掉需求不是要事第一——你的感受也值得被說出來。"},{"t":"大喊「你每次都這樣，說話都不算話」","q":2,"tag":"失望是真的，但「每次」兩個字把它變成了攻擊。"},{"t":"淡淡「喔」了一聲，整晚擺一張臭臉","q":1,"tag":"◐ 你有失望的權利，但臭臉是要他自己猜——大人通常猜不到，真的。"},{"t":"冷冷說「反正我早就習慣了」就走開","q":4,"tag":"⚠ 這句話比生氣更傷——它是把刀，捅人之前先捅自己一刀。"},{"t":"說出自己很期待，提議改約下週六場次","q":0,"tag":"✓ 說出失望＋提出新方案——你把「被取消的人」升級成「重新安排的人」。"}]},{"h":0,"text":"爸爸愧疚地補了一句「下週六一定帶你去看」。到了下週五晚上，他還沒提起這件事，正在客廳邊吃水果邊看股票新聞。","c":[{"t":"什麼都不講，心想他最好自己記得","q":1,"tag":"◐ 你偷偷出了一張他不知道的考卷，然後等他不及格——沒有人會贏。"},{"t":"故意不提醒，等他忘了證明他不在乎","q":4,"tag":"⚠ 你設了一個陷阱，只為贏一句「我早就說了」——贏了道理輸了週末。"},{"t":"傳訊「明天兩點半那場我查好了喔」","q":0,"tag":"✓ 與其賭他記不記得，不如讓他想忘都忘不掉——影響圈玩家的標準操作。"},{"t":"寫張家庭公約要爸爸簽名，雙贏保障","q":3,"tag":"☯ 雙贏協議用在長期合作，一場電影要的只是一句提醒，別把家人當談判方。"},{"t":"先跟同學預告「我爸八成又會放鳥」","q":2,"tag":"事情還沒發生，你已經先寫好受害劇本在那邊等了。"}]},{"h":0,"text":"過年圍爐，阿姨當著全桌親戚說「表哥這次又是全校前十喔，你呢？」那三個字懸在空中，全桌的眼神一下子都飄向你。","c":[{"t":"臭著臉滑手機，整頓飯都不再講話","q":2,"tag":"你的心情遙控器現在在阿姨手上，她按一個鍵，你癱一頓飯。"},{"t":"笑笑說表哥真強，聊起自己在練籃球","q":0,"tag":"✓ 你沒有接「比較」這顆球，你丟回了一顆自己的球——接得漂亮。"},{"t":"認真報告下學期讀書計畫給全桌聽","q":3,"tag":"☯ 有計畫很好，但急著在飯桌自證，等於承認人生考卷該由阿姨來改。"},{"t":"酸回「那阿姨您兒子怎麼沒考第一」","q":4,"tag":"⚠ 嗆贏了餐桌，輸掉了整晚——比較這顆球你不但接了還砸回去。"},{"t":"小聲說「哦還好」，內心翻騰不舒服","q":1,"tag":"◐ 場面守住了，但那句話鑽進心裡住下了——之後記得把它請出去。"}]},{"h":0,"text":"圍爐結束回家的車上，阿姨那句「你呢？」還在腦中重播，你盯著窗外越想越悶，媽媽在前座問你怎麼一路都不說話。","c":[{"t":"以終為始訂目標：下次段考贏過表哥","q":3,"tag":"☯ 以終為始沒錯，但終點設成「贏過表哥」，方向盤還是交在別人手上。"},{"t":"跟媽媽抱怨「阿姨真的有夠煩的欸」","q":1,"tag":"◐ 可以抱怨，這很正常——抱怨完，記得把球撿回來就好。"},{"t":"問自己在意的是表哥，還是想要的樣子","q":0,"tag":"✓ 表哥的成績在關注圈，你想成為的樣子在影響圈——球回到你手上。"},{"t":"躺回椅背滑限動，看大家的完美生活","q":2,"tag":"拿別人的精選輯比自己的幕後花絮，這場比賽地球上沒人贏得了。"},{"t":"遷怒媽媽「都你要帶我去吃這頓的」","q":4,"tag":"⚠ 阿姨的話刺傷你，你卻把刀轉向媽媽——傷口沒好，又多劃一道。"}]},{"h":0,"text":"你傳訊息問好友週末要不要一起去圖書館讀書，他已讀兩小時沒回，你已經點開那個「已讀」看了第十次，越看越心慌。","c":[{"t":"去問別的同學「他是不是說我壞話」","q":4,"tag":"⚠ 你把還沒發生的劇情傳染給第三個人——腦補不但沒停還開了分店。"},{"t":"開始腦補他是不是討厭我、記上次仇","q":2,"tag":"你正在用「猜出來的劇情」，懲罰「真實的自己」。"},{"t":"再連傳三個問號過去，逼他快點回","q":1,"tag":"◐ 壓力是傳過去了，但答案不會比較快回來——催促只是自己更焦躁。"},{"t":"蓋上手機，他可能在忙，先做自己的事","q":0,"tag":"✓ 別人何時回訊息＝關注圈，等待時做什麼＝影響圈——教科書級劃分。"},{"t":"反省自己沒做到知彼解己才會被冷落","q":3,"tag":"☯ 知彼解己是面對面的功夫，人家可能只是在補習，別急著給自己定罪。"}]},{"h":0,"text":"晚上九點好友終於回了：「哈哈剛在補習啦，圖書館可以啊」。你盯著這行字，想起自己焦慮了整整三小時的樣子。","c":[{"t":"回「你也太晚回了吧，我等超久欸」","q":1,"tag":"◐ 一根小刺，他下次已讀你時會想起，然後更不敢隨便回。"},{"t":"跟他約法三章訊息必須半小時內回","q":3,"tag":"☯ 有點像雙贏協議，但拿規則綁朋友的生活，贏了條款輸了自在。"},{"t":"回「我就猜你在補習，那週六見囉」","q":0,"tag":"✓ 三小時的腦補劇場，下檔只需一秒——記住這感覺，下次會好過很多。"},{"t":"故意已讀不回，先跟他扯平了再說","q":2,"tag":"你們開始玩「誰比較不在乎」大賽——冠軍獎品是失去一個朋友。"},{"t":"回「還以為你不想理我了」讓他愧疚","q":4,"tag":"⚠ 把自己的腦補變成他的虧欠，壓力久了會推走人。"}]},{"h":0,"text":"班群突然跳出一張你上課打瞌睡流口水的照片，配字「本日最佳」，訊息數狂飆，大家瘋狂笑倒，你的手指懸在鍵盤上。","c":[{"t":"在群裡開罵「誰拍的？是很好笑嗎」","q":2,"tag":"你一炸，這張照片就從「好笑三分鐘」升級成「事件一星期」。"},{"t":"截圖傳給爸媽說同學都是這樣欺負你","q":4,"tag":"⚠ 一張玩笑照被你升級成霸凌通報，明天的尷尬會比照片大一百倍。"},{"t":"先判斷是玩笑還惡意，幽默回一句","q":0,"tag":"✓ 幽默是最高級的暫停鍵——照片的重量被你親手調成羽量級。"},{"t":"私下找拍照的人傾聽他拍照的初衷","q":3,"tag":"☯ 傾聽初衷太繞遠了——先分清玩笑或惡意，再決定回應才是重點。"},{"t":"二話不說，直接退出整個班級群組","q":1,"tag":"◐ 退群擋得了通知，擋不了明天的教室——問題只是延到早自習。"}]},{"h":0,"text":"笑鬧過後你發現自己其實真的不舒服——被拍醜照放上群組，怎麼想都不對勁。這不是玻璃心，但你不知道該怎麼開口。","c":[{"t":"發限動「原來我在你們眼裡這麼好笑」","q":4,"tag":"⚠ 把不舒服變成公演，台下看戲，台上的你把小事演成大事。"},{"t":"忍下來假裝沒事，當作沒發生過就好","q":1,"tag":"◐ 真的沒事就好，但「假裝沒事」的疙瘩，會在心裡越積越厚。"},{"t":"私訊拍照的人請他刪掉，語氣平靜","q":0,"tag":"✓ 不舒服就說，這不是玻璃心，是界線——主動積極包含選擇說不。"},{"t":"在群組宣導雙贏，呼籲大家互相尊重","q":3,"tag":"☯ 公開喊話聽來正義，但你的需求其實一句私訊就能解決，別繞遠路。"},{"t":"翻出他以前的醜照，傳上群組反擊","q":2,"tag":"以照片還照片，你等於宣布這種玩笑在班上完全合法。"}]},{"h":0,"text":"國小就認識的好友升上國中後跟新同學越走越近，你們已經兩週沒講話，又一個自己吃午餐的中午，你滑著跟他的舊對話。","c":[{"t":"傳訊約他週五放學一起去買手搖飲","q":0,"tag":"✓ 友情在你影響圈裡的部分只有一塊：你願不願意主動——你剛剛動了。"},{"t":"心想是他先不理我的，要主動也該他","q":2,"tag":"「誰先」是最古老的陷阱，堅持等對方先動的人，通常等到的是結束。"},{"t":"去跟別的同學說他壞話，先拉好陣營","q":4,"tag":"⚠ 你怕失去一個朋友，做法卻是再賠掉好幾個——壞話傳回去更難收。"},{"t":"發限動「呵，有些人真的變了呢」","q":1,"tag":"◐ 這種限動只有一個功能：讓事情更難收拾——而且他看得懂。"},{"t":"先擬好見面的談話腳本，知彼解己","q":3,"tag":"☯ 知彼解己是見了面才用得上的功夫，第一步是先傳出那則邀請。"}]},{"h":0,"text":"好友答應了你的邀約，週五一起買了手搖飲。但聊著聊著你發現，你們的共同話題真的變少了，中間空氣安靜了好幾次。","c":[{"t":"提議每週固定聚會，把友情排進要事","q":3,"tag":"☯ 排時間是形式，感情靠的是當下真誠的好奇，不是行事曆上的格子。"},{"t":"心裡確定他變了，這段友情完蛋了","q":2,"tag":"一次尷尬＝完蛋？多年友情你只給它一次五十分鐘的重審機會？"},{"t":"整場努力裝熱絡，笑得用力回家累垮","q":1,"tag":"◐ 硬撐場面不是主動，是表演——誠實一點，反而輕鬆一點。"},{"t":"承認有點感傷，還是問他最近迷什麼","q":0,"tag":"✓ 主動積極不保證結局，它只保證你不會留下「連試都沒試」的遺憾。"},{"t":"乾脆挑明「你是不是不想跟我好了」","q":4,"tag":"⚠ 你想要一個答案，卻問出了一個結局——逼到牆角的關係只會後退。"}]},{"h":0,"text":"早上鬧鐘沒響，你醒來已經七點四十，怎麼趕都一定會遲到。你抓起書包衝出門，公車還剛好開走，只能用走的到學校。","c":[{"t":"一路狂罵鬧鐘，越想越覺得日子超衰","q":1,"tag":"◐ 罵鬧鐘的這十分鐘，鬧鐘沒感覺，你血壓倒是上來了。"},{"t":"邊走邊想：能動的只剩到校後的態度","q":0,"tag":"✓ 開局就分圈，高手——遲到已在外圈，態度還在內圈。"},{"t":"邊走邊規劃完美晨間流程，以終為始","q":3,"tag":"☯ 規劃晨間流程是今晚的功課，現在腳下的每一步才是眼前的考題。"},{"t":"傳訊請同學幫忙騙老師說你肚子痛","q":4,"tag":"⚠ 為了躲十分鐘編一個謊，謊要用更多謊去圓——越纏越多。"},{"t":"反正都遲到了，乾脆慢慢走買個早餐","q":2,"tag":"「反正都」三個字一出，遲到十分鐘正在變成遲到三十分鐘。"}]},{"h":0,"text":"你趕到學校，在校門口被學務處記了遲到，進教室後導師又當著全班補念兩句「最近很混喔」，同學都在看你會有什麼反應。","c":[{"t":"頂回去「又不是我願意遲到的」","q":2,"tag":"這句話的意思是「我對我的人生沒有控制權」——你確定要這樣宣告？"},{"t":"認定老師找碴，整節課不抄筆記抗議","q":4,"tag":"⚠ 你以為在懲罰老師，其實在懲罰自己的成績——只有你一個人受傷。"},{"t":"說「是我鬧鐘問題，今晚會多設一個」","q":0,"tag":"✓ 承認＋方案，五秒講完——老師最吃這套，不是因為乖，是因為罕見。"},{"t":"低頭不語，擺出全世界對不起我的臉","q":1,"tag":"◐ 受難者面具戴久了會長在臉上——早上快過完了，你打算幾點摘？"},{"t":"回「老師，我遲到但有把要事做完」","q":3,"tag":"☯ 要事第一不是遲到的擋箭牌，此刻該面對的就是遲到這件事本身。"}]},{"h":0,"text":"放學回家，媽媽已經接到學校的遲到通知，你一進門她就開始念，今天在學校累積的委屈一下子全部湧了上來，快要炸開。","c":[{"t":"請媽媽先知彼解己，聽完委屈再念你","q":3,"tag":"☯ 知彼解己是先聽懂別人，不是要求別人先聽你——順序反了就變情勒。"},{"t":"「嗯、嗯、好」一路敷衍到她講完","q":1,"tag":"◐ 今天是混過去了，但同一場戲下週還會重播——什麼都沒被解決。"},{"t":"甩頭進房大喊「這個家沒人懂我」","q":4,"tag":"⚠ 門一甩，今天所有的壞全被打包成「都是別人的錯」。"},{"t":"搶先說「是鬧鐘問題，我已多設一個」","q":0,"tag":"✓ 方案先行，火就燒不長——這一天最後一波壞情緒被你一刀斬斷。"},{"t":"爆炸大喊「我今天夠衰了你還要念」","q":2,"tag":"最後一關破功，所有委屈剛剛全變成媽媽繼續念的理由。"}]},{"h":0,"text":"園遊會前一天放學，你們班攤位的海報和價目表都還沒做，負責的同學臨時請假，班上同學互相觀望，沒有人想接手這件事。","c":[{"t":"提議明天現場擺爛，反正法不責眾","q":4,"tag":"⚠ 擺爛拉全班陪葬，你逃掉的工作會變成整班的難堪。"},{"t":"在群組抱怨請假的同學實在太不負責","q":2,"tag":"抱怨完，海報還是空白的——力氣花在管不到的關注圈上了。"},{"t":"主動接下海報，再找兩個同學分工做","q":0,"tag":"✓ 影響圈的第一條守則：與其等人負責，不如先成為那個負責的人。"},{"t":"心想總會有人做，先回家等群組消息","q":1,"tag":"◐ 你沒扯後腿，但「總會有人」的那個人，常常最後誰也不是。"},{"t":"提案先開班會凝聚共識，明天再製作","q":3,"tag":"☯ 凝聚共識很柯維，但明天就是園遊會，現在需要的是動手不是開會。"}]},{"h":0,"text":"你補了一學期數學，這次段考反而退步五分，回家路上媽媽問「補習費是白繳的嗎」，你心裡也悶：到底是哪裡出了問題。","c":[{"t":"怪補習班老師教太快，跟學校不同步","q":2,"tag":"也許是真的，但講完這句，你的五分回來了嗎？"},{"t":"回去翻筆記找漏洞，調整自己的用法","q":0,"tag":"✓ 補習是資源，怎麼用在自己手上——主動的人先檢查自己能動的部分。"},{"t":"偷改成績單分數，先躲過這一波再說","q":4,"tag":"⚠ 改分數是拿信任去換一週安寧，被拆穿後連解釋的資格都沒了。"},{"t":"背誦刺激與回應名言，安慰媽媽消氣","q":3,"tag":"☯ 背金句不等於做到，媽媽要的不是名言，是你面對問題的具體行動。"},{"t":"跟媽媽保證下次會進步，但沒想方法","q":1,"tag":"◐ 保證是心意不是方法，沒有新做法的下一次，通常長得跟這次一樣。"}]},{"h":0,"text":"你原本打算九點開始寫作業，只是想先躺著滑一下短影音，回神已經十點半，作業一個字沒動，你懊惱地盯著天花板發呆。","c":[{"t":"立刻坐起來寫，但手機還放在枕頭邊","q":1,"tag":"◐ 肯動起來很好，但誘惑還在手邊，十分鐘後你大概又會躺回去。"},{"t":"先做四象限分析，研究滑手機屬哪類","q":3,"tag":"☯ 四象限是排優先順序的工具，現在的問題不是分類，是立刻脫離手機。"},{"t":"怪演算法太強，設計得讓人停不下來","q":2,"tag":"演算法確實很強，但按下去的手指是你的——遙控器別交出去。"},{"t":"承認失控，把手機放客廳先寫三十分","q":0,"tag":"✓ 主動的人不跟意志力硬拚，直接改變環境——手機離手，行動就近了。"},{"t":"乾脆滑到睡著，作業明早到校再抄","q":4,"tag":"⚠ 抄作業是把今晚的懶，換成明天的險，還賠上真正練習的機會。"}]},{"h":0,"text":"九年級下學期，班上氣氛越來越緊繃，你每次模擬考完都睡不好，一直想著「考不上前三志願，人生是不是就完了」。","c":[{"t":"熬夜苦讀到半夜，犧牲睡眠拚要事","q":3,"tag":"☯ 看似要事第一，其實犧牲睡眠是拿刀砍自己的產能，越拚越低效。"},{"t":"跟好友互吐苦水，聊完繼續照舊過","q":1,"tag":"◐ 吐苦水能舒壓，是好的開始，但聊完記得把力氣接回行動上。"},{"t":"把焦慮寫下來，圈出自己能做的部分","q":0,"tag":"✓ 焦慮的解藥不是不想，是分圈——放榜在關注圈，複習在影響圈。"},{"t":"開始擺爛不讀，反正考差是遲早的事","q":4,"tag":"⚠ 用「提早放棄」躲「可能失敗」，等於保證了那個你最怕的結局。"},{"t":"覺得都是體制的錯，考試制度害死人","q":2,"tag":"體制或許可以討論，但那在你的關注圈——分數不會因抱怨而改變。"}]},{"h":0,"text":"熱音社幹部改選，你準備了兩週的自我介紹，最後卻落選，當選的是人緣好但很少來練團的同學，你心裡覺得很不服氣。","c":[{"t":"認定選舉就是比人氣，努力根本沒用","q":2,"tag":"也許人氣有影響，但這句話一說，你連能改進的部分也一起丟了。"},{"t":"從此不去練團，讓大家後悔沒選你","q":4,"tag":"⚠ 用消失懲罰大家，最後只懲罰到自己——你失去的是舞台和練習。"},{"t":"安慰自己盡力了，之後照常參加就好","q":1,"tag":"◐ 心態健康，但少了「我能從中學什麼」那一步，機會就只是路過。"},{"t":"找社長請教落選原因，看下次怎麼補","q":0,"tag":"✓ 落選在關注圈，落選的原因裡藏著影響圈——主動的人去把它找出來。"},{"t":"揪不服的社員統合綜效，另組新社團","q":3,"tag":"☯ 統合綜效是合作創造價值，不是拿來包裝賭氣分裂的漂亮說法。"}]},{"h":0,"text":"班群在討論班費用途，你打了一句開玩笑的話，卻被總務股長誤會是在酸他亂花錢，他丟下一句「不然你來管」就下線了。","c":[{"t":"截圖他的話傳小群，笑他惱羞成怒","q":4,"tag":"⚠ 把誤會加工成笑柄，小事變公審，你也從無心變成了故意。"},{"t":"在群組打「開玩笑的啦」就當結束了","q":1,"tag":"◐ 群組一句帶過是止血，但他心裡的疙瘩，需要一對一的誠意才解。"},{"t":"在群組發長文分析雙贏的班費制度","q":3,"tag":"☯ 制度分析再漂亮，也蓋不掉該先說的那句「對不起」——順序錯了。"},{"t":"私訊他道歉說明是玩笑，並謝他辛苦","q":0,"tag":"✓ 誤會發生後，先修補關係的人不是輸家，是把主動權拿回來的人。"},{"t":"心想他也太玻璃心，懶得理他就算了","q":2,"tag":"怪對方玻璃心最省事，但裂痕不會因為你懶得理就自己癒合。"}]},{"h":0,"text":"體育課自由分隊打排球，兩邊隊長挑人挑到最後都沒叫你的名字，老師說「那你先當裁判好了」，你站在場邊有點尷尬。","c":[{"t":"心裡難過，但站上裁判位隨便吹吹","q":1,"tag":"◐ 你沒逃走已經不容易，但敷衍的裁判，只是把難過換個姿勢站著。"},{"t":"覺得大家就是排擠你，越想越委屈","q":2,"tag":"也許有落差是真的，但「排擠」這標籤一貼，你就更不敢上場了。"},{"t":"認真當好裁判，下課後留下來練球","q":0,"tag":"✓ 被挑剩是別人的決定，球技變好是你的決定——影響圈永遠有事可做。"},{"t":"假裝肚子痛去保健室，眼不見為淨","q":4,"tag":"⚠ 逃了這節課，逃不了下一節——尷尬不會消失，只會利息越滾越多。"},{"t":"跟老師申論裁判也是團隊統合綜效","q":3,"tag":"☯ 名詞用得很熟，但問題不在說服老師，在你想不想讓自己變強。"}]},{"h":0,"text":"早自習全班在傳「你跟隔壁班某人告白被拒」的八卦，根本沒這回事，連好友都跑來問你是不是真的，你又好氣又好笑。","c":[{"t":"以終為始寫澄清長文，貼在班群自白","q":3,"tag":"☯ 長文自白看似負責，實際把小八卦升級成頭條——概念對但場合錯。"},{"t":"淡定澄清「沒這回事」，不多做戲","q":0,"tag":"✓ 謠言的燃料是反應——你越平靜，它燒得越短，主導權在你手上。"},{"t":"氣得追查是誰造謠，一定要揪出來","q":2,"tag":"全面搜捕造謠者，八卦反而加倍延燒——你在幫它添柴火。"},{"t":"跟好友解釋清楚，其他人隨便他們說","q":1,"tag":"◐ 對在乎的人說清楚就夠了，方向對，只是別忘了自己也真的放下。"},{"t":"順勢編更誇張的版本，看大家能傳多扯","q":4,"tag":"⚠ 玩笑越滾越大，哪天傳回當事人耳裡，尷尬的還是你自己。"}]},{"h":0,"text":"暑假科學營第一天，你被分到全是陌生人的小隊，其他人好像都有伴有說有笑，破冰時間你一個人站在旁邊滑手機裝忙。","c":[{"t":"心想自己就是內向，交不到朋友正常","q":2,"tag":"「我就是內向」把暫時的緊張改寫成永久的設定——這份合約別簽。"},{"t":"等別人先來搭話，有人問再好好聊","q":1,"tag":"◐ 願意聊是好事，但把破冰的鑰匙放在別人口袋，可能等完五天。"},{"t":"傳訊跟媽媽吵著要提早退營回家去","q":4,"tag":"⚠ 一遇到不舒服就撤退，五天的營隊和可能的新朋友一起賠掉。"},{"t":"收起手機，主動找旁邊的人自我介紹","q":0,"tag":"✓ 「有沒有伴」在關注圈，「要不要開口」在影響圈——先開口就贏了。"},{"t":"先觀察每個人特質，構思雙贏的隊規","q":3,"tag":"☯ 想隊規想得很遠，但連名字都還沒交換——先當朋友，再談規則。"}]},{"h":1,"text":"開學社團博覽會，好朋友揪你一起加入最熱鬧的熱舞社，但你其實一直想學攝影，兩個社團時間衝堂，報名單明天就要交，你正拿著筆猶豫要填哪一個。","c":[{"t":"朋友多就選熱舞社，至少不會孤單","q":2,"tag":"以「熱鬧」為準而非以終點為準——熱鬧散場後，你離想成為的自己又遠了一步。"},{"t":"先想這一年想學會什麼，再決定填哪個","q":0,"tag":"✓ 以終為始：先看見一年後想成為的自己，再回推今天該填哪張單，每一步才走在自己的路上。"},{"t":"先跟朋友雙贏協商，各退一步輪流參加","q":3,"tag":"☯ 雙贏是處理人際衝突的好概念，但衝堂不是談判問題——你真正要先回答的是自己的終點在哪。"},{"t":"填了攝影社，但心裡想著不合就退","q":1,"tag":"◐ 方向選對了，卻先留好退路——沒有承諾的終點，遇到第一個挫折就會鬆手。"},{"t":"兩個都亂填，之後看心情翹掉一個","q":4,"tag":"⚠ 什麼都想留，等於什麼都沒選；翹掉的不只是社課，還有別人被你占走的名額。"}]},{"h":1,"text":"你每天放學就進房間唸書，行程排得滿滿，段考成績卻總是普通。今晚你又坐在書桌前，翻開課本卻突然愣住：我到底在為什麼念？接下來該怎麼調整讀書方式。","c":[{"t":"知道該設目標，但想先念完這章再說","q":1,"tag":"◐ 你已察覺缺了終點，卻又拖回慣性——目標不定下來，念完這章還是一樣迷航。"},{"t":"照原本進度表繼續念，念久總會進步","q":2,"tag":"有行程不等於有方向——沒有終點的努力像划船不看岸，划得越久偏得越遠。"},{"t":"乾脆先不念了，反正念再多也沒有用","q":4,"tag":"⚠ 從「沒方向」直接跳到「放棄」，是把問題丟給明天的自己，霧只會更濃。"},{"t":"先定出這學期的具體目標再安排讀法","q":0,"tag":"✓ 以終為始：先確立想抵達的終點，努力才有羅盤，每一分力氣都用在刀口上。"},{"t":"先去運動放鬆磨利鋸子，回來再念","q":3,"tag":"☯ 不斷更新是好習慣，但你缺的不是體力，是終點——鋸子再利，沒有方向也不知道砍哪棵樹。"}]},{"h":1,"text":"你存了三個月零用錢，本來想買一台二手相機學拍片。逛街時看到偶像的限定周邊只剩最後兩個，價格剛好會把存款花掉一大半，店員說今天不買就沒了。","c":[{"t":"限定不買會後悔，先買了再慢慢存","q":2,"tag":"被「限定」兩個字綁架，正是衝動消費的圈套——你買的常是焦慮，不是真需要。"},{"t":"跟同學借錢兩個都買，之後再想辦法","q":4,"tag":"⚠ 透支未來換當下快感，看似豪爽，實則親手挖了一個更深的坑給自己。"},{"t":"心裡想著相機，還是先買了小的周邊","q":1,"tag":"◐ 終點看得清，卻被眼前的衝動咬掉一角——以終為始，難在抵住「現在就要」的拉力。"},{"t":"主動積極想辦法多賺零用錢兩個都要","q":3,"tag":"☯ 主動積極是為選擇負責，不是替衝動找出路——先問哪個終點是你的，再談怎麼賺。"},{"t":"想想這筆錢要成就哪個未來，再決定","q":0,"tag":"✓ 以終為始：讓今天的每一筆花費，都服務於你心裡更想望的那個未來。"}]},{"h":1,"text":"結業式結束，兩個月的暑假正式開始。爸媽白天都要上班，家裡只有你一個人，手機、電腦都在旁邊，你躺在床上想著：這個暑假到底要怎麼過才不會白費。","c":[{"t":"先想開學時想變成什麼樣，再回推安排","q":0,"tag":"✓ 以終為始：先在心裡看見假期結束時的自己，再回推今天該怎麼安排，兩次創造缺一不可。"},{"t":"先把暑假作業列成清單，要事第一做完","q":3,"tag":"☯ 要事第一是排優先順序，但你連暑假的終點都還沒定——沒有方向，排序無從談起。"},{"t":"先耍廢幾天再說，反正假期還很長呢","q":2,"tag":"沒有終點的日子最容易蒸發——「還很長」說著說著，兩個月就晃過去了。"},{"t":"列了想做的事，但沒排什麼時候去做","q":1,"tag":"◐ 有清單是看見了終點，但沒排進時間，它就只是願望，不會自己發生。"},{"t":"整個暑假拿來打電動，想這麼多幹嘛","q":4,"tag":"⚠ 連想都拒絕想，等於把兩個月直接交給慣性——開學那天的空白，就是這句話的帳單。"}]},{"h":1,"text":"國文老師出了一篇作文「我的十五歲」，下週一要交。你打開稿紙急著動筆，寫了兩行卻卡住，因為你根本不知道這篇文章想表達什麼，時間一分一秒過去。","c":[{"t":"先拚命湊字數，內容寫到哪算到哪","q":2,"tag":"只追求「寫滿」卻沒有方向，寫得再多也是一盤散沙——量填不了沒有終點的空。"},{"t":"上網抄一篇範文，改幾個字就交差","q":4,"tag":"⚠ 抄來的是空殼，看似交差了，你什麼也沒練到——還賠上了誠實。"},{"t":"先定下最想傳達的一句話，再動筆寫","q":0,"tag":"✓ 以終為始：先確立最想說的核心，每一段才會朝同一個終點走，文章才有力量。"},{"t":"腦中想好主旨，沒寫下來就直接開寫","q":1,"tag":"◐ 有方向是好的，但沒釘住它，寫著寫著就偏掉——終點要寫下來才抓得住。"},{"t":"先找同學統合綜效，一起腦力激盪","q":3,"tag":"☯ 綜效能激出好點子，但作文要的是你的核心思想——別人給不了你「最想說的那句話」。"}]},{"h":1,"text":"新學期班會選幹部，你其實想試試學藝股長，練習辦活動的能力，但聽說很累。這時同學起鬨提名你當輕鬆的器材股長，導師問你的意願，全班都在看你。","c":[{"t":"選最涼的器材股長，輕鬆過一學期","q":2,"tag":"用「輕鬆」當標準，而不是「我想長成什麼樣」——選了最涼的，也錯過了想要的歷練。"},{"t":"有點想選學藝，但怕麻煩先不表態","q":1,"tag":"◐ 心裡其實有目標，卻被「怕麻煩」蓋過——以終為始，難在抵住當下退縮的拉力。"},{"t":"隨便答應下來，之後擺爛給別人收","q":4,"tag":"⚠ 沒想清楚就接、接了又敷衍，既誤了班務也壞了信用——這是雙輸的開場。"},{"t":"先知彼解己，問每個同學希望我當什麼","q":3,"tag":"☯ 傾聽是溝通的好習慣，但幹部是你的選擇——用別人的期待導航，走不到自己的終點。"},{"t":"想清楚想從職位學到什麼，再舉手爭取","q":0,"tag":"✓ 以終為始：先看自己想藉這個位子練到什麼能力，再決定要不要伸手。"}]},{"h":1,"text":"你學吉他半年，最近卡在封閉和弦一直按不好，練習變得很痛苦，看著同期入門的同學都彈得比你順，你開始想：要不要乾脆退掉課程，把時間拿去做別的。","c":[{"t":"知道該設目標，卻一直沒具體訂出來","q":1,"tag":"◐ 認同要有終點，卻遲遲不肯訂下來——沒釘住的目標，撐不住低潮時的動搖。"},{"t":"重定一個清楚的階段目標，一步步練","q":0,"tag":"✓ 以終為始：把模糊的「變強」拆成看得見的小終點，用它帶你撐過撞牆期。"},{"t":"直接放棄，反正當初也只是玩玩而已","q":4,"tag":"⚠ 一遇瓶頸就喊「只是玩玩」收場，半途而廢會慢慢長成習慣，什麼都學不深。"},{"t":"沒目標地隨便練，練到膩了就停掉","q":2,"tag":"沒有階段終點的練習，最容易在低谷時放棄——不知道往哪走，自然撐不久。"},{"t":"先知彼解己，問彈得順的同學怎麼練","q":3,"tag":"☯ 請教方法是好事，但你的問題不是不會練，是看不見終點——方法救不了迷航的心。"}]},{"h":1,"text":"距離段考只剩一週，五科範圍都不小，你打開書包把課本全部堆在桌上，卻不知道從哪裡開始。時間有限，每一科的熟練度也不一樣，第一步該怎麼下手。","c":[{"t":"打開課本從第一頁開始慢慢往下看","q":2,"tag":"沒有終點的複習像沒有地圖的旅行，走到哪算哪，時間先用完的永遠是你。"},{"t":"從最喜歡的科目讀起，先有個開始","q":1,"tag":"◐ 有開始很好，但喜歡的通常不是最需要的——差了「終點回推」那一層。"},{"t":"只背補習班的猜題，賭它這次壓中","q":4,"tag":"⚠ 把終點外包給猜題，賭贏一次，輸掉的是讀書的能力和底氣。"},{"t":"先看範圍和目標分數，再回推排讀法","q":0,"tag":"✓ 先立終點再排路線——複習是為了抵達，不是為了安心。"},{"t":"先主動積極穩住心態，告訴自己別慌","q":3,"tag":"☯ 心態是習慣一的功課，但眼前缺的是路線圖——不慌卻沒方向，還是在原地打轉。"}]},{"h":1,"text":"班會表決讓你負責規劃這學期的班遊，一日行程、五十個人、預算有限。放學後你打開電腦準備開工，腦中卻一片空白，不知道規劃的第一步要從哪裡開始。","c":[{"t":"先想大家想留下什麼回憶，再排行程","q":0,"tag":"✓ 心中先有那張「回來後的合照」，行程自然知道怎麼排——這就是第一次創造。"},{"t":"先要事第一，把交通和保險最先訂好","q":3,"tag":"☯ 排優先順序沒錯，但終點還沒定就先訂車，是把第二次創造搬到第一次前面。"},{"t":"先查網路上最熱門的景點清單來排","q":1,"tag":"◐ 方法對了一半——熱門是別人的答案，不一定是你們班要的回憶。"},{"t":"直接抄別班的行程交差，最省事了","q":4,"tag":"⚠ 省了力氣，也放棄了「這是我們的班遊」——複製不出專屬回憶，也辜負了託付。"},{"t":"不排了，到了再說，隨興走才好玩","q":2,"tag":"隨興很浪漫，但一車五十個人的期待，需要一個先想好的方向。"}]},{"h":1,"text":"考完模擬考的傍晚，隔壁班好友陪你走路回家，突然問你：「欸，你有想過我們每天這樣讀書，到底是為了什麼嗎？」他看起來是認真的，等著你的答案。","c":[{"t":"「爸媽要我們讀的啊，不然咧」","q":2,"tag":"人生劇本讓別人執筆，是最可惜的以「別人的終」為始。"},{"t":"「為了考上理想高中啊，不然呢」","q":1,"tag":"◐ 是目標，但只是中繼站——過了這站呢？終點要接得住整個你。"},{"t":"說出自己想成為的樣子和讀書的關係","q":0,"tag":"✓ 心中有使命宣言的人，讀的每一頁都有座標——連回答別人都不會心虛。"},{"t":"「就為了贏過別人啊，輸了就完了」","q":4,"tag":"⚠ 把人生設成排位賽，贏了名次，輸了方向——而且永遠有下一個要贏的人。"},{"t":"「別想那麼多，先顧好影響圈啦」","q":3,"tag":"☯ 影響圈是習慣一的好概念，但朋友問的是人生方向——拿它擋掉思考，是誤用。"}]},{"h":1,"text":"選社時間，你對吉他社有點心動，但聽說學期末要上台成果發表，光想就緊張；好朋友則揪你去輕鬆的桌遊社。報名單就在桌上，放學前一定要交出去。","c":[{"t":"怕上台，還是跟朋友去桌遊社好了","q":1,"tag":"◐ 避開可怕是人之常情，但要誠實：你選的是桌遊，還是「逃跑」？結局不一樣。"},{"t":"先不交，明天被老師催了再隨便填","q":2,"tag":"不選也是一種選——而且是把方向盤丟給「截止日」的那一種。"},{"t":"兩個都勾，到時候看哪個爽就去哪個","q":4,"tag":"⚠ 什麼都想留等於什麼都沒選，還占了別人的名額——最後常是一個都不剩。"},{"t":"先雙贏協調，說服朋友陪我進吉他社","q":3,"tag":"☯ 雙贏用在利益衝突的談判，但這題的關卡是你的恐懼——朋友陪不陪，都替代不了你面對它。"},{"t":"想像期末想成為哪個自己，再填單子","q":0,"tag":"✓ 以終為始：先看見學期末的自己，再決定今天填哪張單——怕，可以帶著怕去。"}]},{"h":1,"text":"段考前導師發下讀書計畫表，第一格是「本次段考目標」。你盯著空白的目標欄，隔壁同學隨手寫了「進步就好」三個字交差，你想寫一個真的幫得到自己的目標。","c":[{"t":"抄隔壁的「進步就好」，快速交出去","q":2,"tag":"抄來的目標，風一吹就散——三天後你就會忘記自己寫過它。"},{"t":"先想這次想當怎麼準備的學生，再回推","q":0,"tag":"✓ 分數是結果，「我想成為哪種準備者」才是你能直接動手的終點。"},{"t":"亂寫一個目標應付，反正沒人會檢查","q":4,"tag":"⚠ 騙過老師容易，騙不過段考——你放掉的是一次幫自己導航的機會。"},{"t":"寫下「這次不要再被爸媽念了」","q":1,"tag":"◐ 「不要被念」是逃避型目標——它的終點在別人的嘴，不在你身上。"},{"t":"寫「統合綜效，跟全班一起進步」","q":3,"tag":"☯ 綜效很美，但目標欄要的是你自己的終點——群體口號代替不了個人座標。"}]},{"h":1,"text":"你寫下「數學考好一點」當段考目標，導師看了搖搖頭，說這個目標太模糊，要你放學前改成一個「明天早上就知道第一步做什麼」的版本，你重新拿起筆。","c":[{"t":"改成「數學要進步，加油加油」","q":2,"tag":"「好一點」換成「加油」還是霧做的目標——沒有形狀，到了也不知道到了。"},{"t":"改成「全科都要進步，這次拼了」","q":1,"tag":"◐ 氣勢滿分，座標零分——「拼了」的隔天早上，要從哪一步開始拼？"},{"t":"覺得老師找碴，隨便畫兩筆就交回去","q":4,"tag":"⚠ 賭氣敷衍，虧的是自己——老師退回的不是你的字，是沒有導航的段考。"},{"t":"改成「每晚八點算例題，錯題本翻兩遍」","q":0,"tag":"✓ 這個目標自帶地圖——每天晚上八點，你都知道下一步往哪走。"},{"t":"改成「先跟同學雙贏，組讀書會互相罩」","q":3,"tag":"☯ 讀書會是好方法，但老師要的是你的終點座標——先有目標，讀書會才有東西可罩。"}]},{"h":1,"text":"班會上老師徵求下個月英語日的主持人，全班一片安靜。你心裡其實很想試，手抬到一半又想到萬一講錯會被笑，衝動和害怕在打架，老師的目光掃了過來。","c":[{"t":"問自己：畢業時想當試過還是旁觀的人","q":0,"tag":"✓ 把鏡頭拉到終點再回頭看——這一看，眼前的「可怕」忽然變小了。"},{"t":"先觀察有沒有別人舉，有人舉就算了","q":1,"tag":"◐ 你把選項交給「有沒有人先舉」——方向盤又悄悄遞出去了。"},{"t":"先主動積極炒熱氣氛，幫想上的人助陣","q":3,"tag":"☯ 幫別人喝采很好，但主動積極的真義是為自己的選擇負責——你想試的心被晾在原地。"},{"t":"想到全班會怎麼看我，默默把手放下","q":2,"tag":"這個問題的答案在別人腦袋裡，你永遠查不到——拿它做決定，等於讓霧導航。"},{"t":"起鬨推最內向的同學上去，轉移焦點","q":4,"tag":"⚠ 用別人的尷尬掩護自己的退縮，既傷了同學，也離你想試的那個自己更遠。"}]},{"h":1,"text":"你鼓起勇氣報名了校內英語演講比賽，回到座位卻開始後悔：萬一上台忘詞、發音被笑怎麼辦？比賽在三週後，你得決定接下來用什麼心態面對這件事。","c":[{"t":"寫逐字稿背到一字不差才敢站上台","q":1,"tag":"◐ 準備是好事，但「不容許任何意外」這個終點，本身就是個意外製造機。"},{"t":"越想越怕，開始認真考慮找理由退賽","q":2,"tag":"你讓「想像中的失敗」否決了「真實的想要」——霧最愛這一招。"},{"t":"把終點設在「敢上台」，搞砸也算練到","q":0,"tag":"✓ 終點設對了，連失敗都變成路上的風景，而不是路的盡頭。"},{"t":"先不練，比賽當天真不行就裝病請假","q":4,"tag":"⚠ 你握著的是一張「之後再逃」的票——不練又不退，把自己堵在最糟的位置。"},{"t":"先照顧身心不斷更新，緊張就去跑步","q":3,"tag":"☯ 運動紓壓是好習慣，但它治標——真正要換的是你對「搞砸」的終點設定。"}]},{"h":1,"text":"八年級生涯課發下「未來志願初探單」，第一格要填最想就讀的方向。你聽同學說哪間學校最有名，也知道自己的分數落點，但筆懸在半空不知道怎麼下。","c":[{"t":"大家都說那間最好，跟著填準沒錯","q":1,"tag":"◐ 「大家都說」是別人的地圖——能參考，但你要去的地方得自己標。"},{"t":"覺得現在想太早，乾脆空白交出去","q":2,"tag":"九年級的霧，是八年級的空白養大的——現在不必決定，但可以開始看。"},{"t":"亂填一個唬過老師，反正以後會變","q":4,"tag":"⚠ 「反正會變」不是亂填的理由——你騙過的不是老師，是那個想被認識的自己。"},{"t":"先問爸媽想要什麼，知彼解己最重要","q":3,"tag":"☯ 理解爸媽是溝通的功課，但這張單子的終點是「認識自己」——順序別顛倒了。"},{"t":"從做什麼最忘記時間開始想，再下筆","q":0,"tag":"✓ 「忘記時間」是興趣留下的腳印——沿著腳印找，比沿著排名找更接近你的終點。"}]},{"h":1,"text":"填生涯試探單時，你想到自己每次做簡報、排版面最起勁，很想寫設計相關的學校，但爸媽以前說過那條路不穩定。單子明天要交，還要給家長簽名。","c":[{"t":"覺得反正最後爸媽決定，想了也白想","q":2,"tag":"這句話一說完，方向盤就完全不在你手上了——而且是你自己鬆手的。"},{"t":"誠實寫下來，這只是初探，回家再聊","q":0,"tag":"✓ 這張單子的終點是「更認識自己」，不是「討好誰」——誠實的座標才能導航。"},{"t":"偽造簽名交出去，避免在家裡吵起來","q":4,"tag":"⚠ 躲過一晚的爭執，賠上的是信任——被發現那天，連好好談的機會都沒了。"},{"t":"寫一個爸媽會滿意的，想要的放心裡","q":1,"tag":"◐ 可以理解，但小心：放在心裡又不拿出來看的東西，會被霧慢慢收走。"},{"t":"先查哪科最好賺，要事第一顧現實","q":3,"tag":"☯ 務實不是錯，但要事第一的前提是先有使命——「最好賺」是別人的排序，不是你的。"}]},{"h":1,"text":"晚餐吃到一半，媽媽宣布已經幫你報好每週三晚上的數學補習班，完全沒有先問過你。你的數學確實不太穩，但你有自己想補強的方式，筷子停在半空。","c":[{"t":"摔筷子抗議「為什麼都不先問過我」","q":2,"tag":"你抗議的是「沒被問」，聽在媽媽耳裡卻變成「不想學好」——兩邊都迷航。"},{"t":"心裡狂翻白眼，嘴上還是說「喔，好」","q":1,"tag":"◐ 你上了一台別人設定目的地的車——之後每個週三的不甘願，都是這聲「喔」付的利息。"},{"t":"大喊「我就是不去，你逼我也沒用」","q":4,"tag":"⚠ 純拒絕沒有地圖，只有對抗——媽媽看到的不是你的方向，是你的叛逆。"},{"t":"先說出自己的計畫：數學想補哪一塊","q":0,"tag":"✓ 你沒有拒絕補習，你拿出了自己的地圖——有地圖的人，才有得談。"},{"t":"先同理媽媽工作辛苦，這次就順著她","q":3,"tag":"☯ 同理是知彼解己的起點，但它是為了溝通，不是無限退讓——你的方向還是要自己說出口。"}]},{"h":1,"text":"你跟媽媽說想先自己讀數學，她皺眉反問：「你自己讀有用的話，還需要我幫你報名嗎？」這句話有點刺，但也不是完全沒道理，你想了想該怎麼接下去。","c":[{"t":"提檢查點：這次沒到七十五分就去補","q":0,"tag":"✓ 你把「不想去」升級成有終點、有期限、可驗收的提案——這已經是大人的談法了。"},{"t":"說「好，我去，但去了我也不會聽」","q":4,"tag":"⚠ 用「人到心不到」報復，罰到的是自己的時間——賭氣的座標通往的全是浪費。"},{"t":"說「隨便啦，你們要我去我就去」","q":2,"tag":"「隨便」一出口，方向盤就交出去了——之後的不甘願，都是現在省下的思考。"},{"t":"反駁「班上補習的人也考很爛啊」","q":1,"tag":"◐ 也許是事實，但這是攻擊她的地圖，不是展示你的——吵贏論點，輸掉信任。"},{"t":"說「先擴大影響圈，你別管我怎麼讀」","q":3,"tag":"☯ 影響圈是拿來要求自己，不是拿來擋媽媽的——概念用反了，溝通也斷了。"}]},{"h":1,"text":"跟媽媽為了補習吵完架，你躺在床上睡不著，腦中一直重播剛剛互嗆的話，越想越氣，手機就在枕頭邊，而明天早上你還是得跟她一起坐在餐桌吃早餐。","c":[{"t":"把她的難聽話記下來，下次吵回去","q":1,"tag":"◐ 你在為下一場戰爭備戰——也就是說，你已經把終點設在「再吵一次」了。"},{"t":"決定明天開始冷戰，看誰先受不了","q":2,"tag":"冷戰的終點是什麼？沒有終點的戰爭可以打很久——耗掉的是你們兩個。"},{"t":"先問自己：半年後想跟媽媽什麼關係","q":0,"tag":"✓ 在最氣的晚上問「我要去哪」，是最高難度的動作——你做到了。"},{"t":"傳訊息跟朋友罵媽媽，罵到睡著為止","q":4,"tag":"⚠ 罵爽了，問題還在原地——出口從來不在別人的安慰裡，明早的霧只會更濃。"},{"t":"打開行事曆排讀書計畫，要事第一","q":3,"tag":"☯ 排程是好工具，但此刻真正的要事是關係的終點——逃進計畫表，只是換個地方躲。"}]},{"h":1,"text":"冷靜下來後你發現，自己其實希望能跟媽媽像朋友一樣說話，而不是每次都用吵的。如果那就是你想要的終點，明天早餐桌上，你打算怎麼踏出第一步。","c":[{"t":"先觀察她臉色，她先示好我才示好","q":1,"tag":"◐ 你把第一步外包給她的臉色了——如果她也在等你的臉色，兩個人就一起站在原地。"},{"t":"什麼都不做，時間久了自然就會好","q":2,"tag":"「自然就好」的意思是：讓霧決定你們的關係往哪漂——有時漂回來，有時漂走。"},{"t":"表面裝沒事，心裡記帳並慢慢疏遠她","q":4,"tag":"⚠ 表面和平、暗中記帳——關係沒斷，只是被你悄悄設定成「往遠方漂」。"},{"t":"留張紙條寫「我以後會主動積極讀書」","q":3,"tag":"☯ 口號拋得漂亮，卻迴避了該修復的關係本身——她要的不是保證書，是你這個人。"},{"t":"為昨天的口氣道歉，再聊自己的想法","q":0,"tag":"✓ 只認自己的那一份，再把話題帶回想法而不是輸贏——這一步正踩在通往終點的路上。"}]},{"h":1,"text":"你為了買相機學拍片，存了半年的紅包和零用錢。今晚手遊跳出通知：「限定卡池最後四十八小時」，你最愛的角色機率提升，儲值的手指已經懸在螢幕上。","c":[{"t":"先不想了，錢放著再說，好糾結啊","q":2,"tag":"不決定的錢最危險——它會在某個更小的衝動裡，一百、兩百地蒸發掉。"},{"t":"比一下終點：有角色和開拍片，選哪個","q":0,"tag":"✓ 這不是「存錢就是乖」的說教題，是「哪個終點是你的」——用終點挑，就對了。"},{"t":"先抽這一次就好，相機之後再存回來","q":1,"tag":"◐ 注意「之後再存」四個字——每次都有一個最後四十八小時，「之後」永遠不會來。"},{"t":"把明年的紅包先預支下去，兩個都要","q":4,"tag":"⚠ 把未來的錢先花掉，是霧的記帳法——明年的錢有明年的用途，不是衝動的提款機。"},{"t":"先跟朋友統合綜效，看大家抽不抽","q":3,"tag":"☯ 綜效是共創方案，不是集體衝動的壯膽——大家都抽，也抽不出你的相機。"}]},{"h":1,"text":"你認真想過之後，發現自己真的超想要那個限定角色，抽卡確實會讓你快樂，但相機的夢想也是真的。兩邊都想要的情況下，你決定怎麼處理這一筆錢。","c":[{"t":"全梭下去，快樂最重要想那麼多幹嘛","q":1,"tag":"◐ 快樂是真的，只是抽完的第三天，那個想拍片的你會輕輕問一句：那我呢？"},{"t":"邊抽邊罪惡，抽完更想再抽一次補償","q":2,"tag":"錢花了，快樂卻被罪惡感折半，再用更多花費去補——這是霧的完美循環。"},{"t":"抽不夠就偷動相機基金，先爽再說","q":4,"tag":"⚠ 防線一旦破一次就沒有防線了——基金少一塊，那個終點就遠一步。"},{"t":"設一條線：這次花一千，其餘進基金","q":0,"tag":"✓ 以終為始不是禁慾——是知道自己要去哪，然後有意識地決定在路邊停留多久。"},{"t":"先知彼解己問爸媽意見，他們說了算","q":3,"tag":"☯ 聽取意見是好事，但「他們說了算」是交出方向盤——這筆錢的終點該由你來定。"}]},{"h":1,"text":"開學第一天，老師要大家分享暑假收穫，你才驚覺整整兩個月好像什麼都沒留下，只記得每天睡醒就滑手機。回想這個暑假，它到底是怎麼消失不見的。","c":[{"t":"承認每天醒來沒想過要幹嘛，才被滑走","q":0,"tag":"✓ 賓果，兇手不是手機，是「沒有任何一天知道自己要幹嘛」——承認這個，是改變的第一步。"},{"t":"怪爸媽整個暑假都沒幫我安排活動","q":2,"tag":"等等，你的假期要別人來規劃？方向盤交出去，就別怪車開錯路。"},{"t":"怪自己沒不斷更新，早該去學新才藝","q":3,"tag":"☯ 更新是好習慣，但真正的病灶是沒有終點——不是少學一樣，是沒想過要去哪。"},{"t":"覺得暑假本來就是拿來耍廢的，正常","q":1,"tag":"◐ 耍廢完全合法！但「選擇耍廢」跟「醒來只剩耍廢」是兩種假期——前者爽，後者空。"},{"t":"覺得時間過太快，這誰也沒辦法的事","q":4,"tag":"⚠ 時間對每個人都一樣快——差別在有人留下了東西，有人只剩「咻」一聲。"}]},{"h":1,"text":"寒假前一週，你想起上個暑假整個蒸發的教訓，決定這次要讓假期過得不一樣。你拿出紙筆準備規劃，但也知道自己以前訂的計畫，常常三天就變成廢紙。","c":[{"t":"排一張精確到每小時的作息表貼牆上","q":1,"tag":"◐ 氣勢可嘉，但這種表通常活不過三天，然後你會因為破表而整個放棄——終點太多等於沒有終點。"},{"t":"不計畫了，反正計畫了也不會照做","q":4,"tag":"⚠ 你直接在假期第一天，幫整個假期蓋了「繞圈」的章——連出發都省了。"},{"t":"只定一個終點：開學帶一個作品回教室","q":0,"tag":"✓ 一個終點、每天一小步——這種計畫殺不死；學會一首歌、剪一支影片都算。"},{"t":"等過幾天有靈感了，再來想要做什麼","q":2,"tag":"「等有靈感」是霧的拖字訣——靈感不會自己敲門，它只回應已經出發的人。"},{"t":"先把七個習慣抄一遍貼牆，天天複誦","q":3,"tag":"☯ 背口訣不等於有終點——柯維要你寫的是自己的使命，不是他的目錄。"}]},{"h":1,"text":"你花三小時畫了一張圖，發上自己的創作帳號，這是你朝插畫夢想跨出的第一步。隔天一個陌生帳號留言：「畫這什麼，好醜。」你盯著那行字，心臟揪了一下。","c":[{"t":"告訴自己別理他，但整晚反覆點開看","q":1,"tag":"◐ 你知道不該讓他導航，卻還沒真的放下——他不值得你的一整個晚上。"},{"t":"氣不過，跟他在留言區對罵一整晚","q":2,"tag":"你今晚的三小時，從「畫下一張」變成「跟陌生人吵架」——誰偷走的？"},{"t":"刪掉整個帳號，從此不再發任何作品","q":4,"tag":"⚠ 一個陌生人的一句話，就沒收了你的夢想帳號——牠在霧裡笑了。"},{"t":"先反省是不是雙輸，主動私訊他求教","q":3,"tag":"☯ 向真前輩求教是好事，但對純惡意套用雙贏思維，是把導航讓給不相干的人。"},{"t":"想他在不在我的終點裡，不在就封鎖","q":0,"tag":"✓ 「他在不在我要去的地方裡」是過濾噪音最快的篩子——不在的，連生氣額度都不用給。"}]},{"h":1,"text":"週五晚上班群跳出訊息，八個同學約明天下午去唱歌，但你原本排好要去聽老師加開的數學檢討課，數學正是你最弱的一科。你的手指放在鍵盤上。","c":[{"t":"大家都去，不去多掃興，先答應再說","q":1,"tag":"◐ 「大家都」是最濃的霧之一——八個人有八個理由，但你還沒找到你的。"},{"t":"把兩條路走到底：各得到什麼錯過什麼","q":0,"tag":"✓ 兩條路都走到終點再回頭看——這個動作不到一分鐘，卻讓選擇變成你的。"},{"t":"不敢去也不敢拒絕，先已讀不回再說","q":2,"tag":"已讀不回不是選項，是把選擇權交給最後一刻的壓力——那時的你選得最差。"},{"t":"翹掉檢討課去唱歌，課改天再補就好","q":4,"tag":"⚠ 「改天補」跟「之後再存」是同一團霧——改天有改天的事，這次的洞補不回來。"},{"t":"先聚焦影響圈，別人約不約我管不著","q":3,"tag":"☯ 影響圈是拿來聚焦行動的，不是拿來迴避選擇的——邀約已經來了，你得選。"}]},{"h":1,"text":"你想清楚了，明天的數學檢討課對你真的重要，決定不去唱歌。但這群朋友最常笑誰誰誰「最不乾脆」，你盯著群組的輸入框，想著要怎麼回覆才不傷感情。","c":[{"t":"嘆氣回「好啦好啦我去」，免得被嫌","q":2,"tag":"你用自己的終點換一句「夠意思」——這種交易做多了，方向盤上全是別人的手。"},{"t":"回「我看看啦，明天再說」先拖著","q":1,"tag":"◐ 模糊的回答買到一晚安寧，但明天你要嘛被連環call，要嘛真的被說不乾脆。"},{"t":"回「我媽不准」，把媽媽推出去擋","q":4,"tag":"⚠ 借別人當擋箭牌，練的是「不敢為自己的選擇負責」——下次還是會被困住。"},{"t":"回「明天我得上課，下週換我開團」","q":0,"tag":"✓ 拒絕一次邀約不等於拒絕朋友——座標清楚的人，連說「不」都不心虛。"},{"t":"回「要事第一懂嗎」，教育大家一番","q":3,"tag":"☯ 概念沒錯，但拿柯維語錄訓朋友，既沒說清自己的選擇，還順手傷了關係。"}]},{"h":1,"text":"生涯課的最後一個活動，老師要你們閉上眼睛想像：十年後的同學會上，老同學笑著問你「這幾年都在忙什麼啊」。你希望那個時候的自己，最想給出哪種回答。","c":[{"t":"「我在做一件自己選的事，做得不錯」","q":0,"tag":"✓ 注意到了嗎？你最在意的不是「多厲害」，是「自己選的」——這就是你的羅盤針。"},{"t":"「就還行吧，跟大家都差不多啦」","q":2,"tag":"連想像中的自己都拿不出答案——這就是霧住進心裡的樣子；再想一次，不限時。"},{"t":"「考上不錯的學校，之後走一步算一步」","q":1,"tag":"◐ 前半有座標，後半又交還給霧——中繼站之後的路，才是這題真正要問的。"},{"t":"「賺很多錢啊，其他的我都沒在管」","q":4,"tag":"⚠ 錢可以是終點的一部分，但如果是全部，這場同學會你會聊得很大聲、很空。"},{"t":"「我都先傾聽別人需要，配合大家」","q":3,"tag":"☯ 知彼解己是溝通習慣，不是人生劇本——把配合當終點，方向盤永遠在別人手上。"}]},{"h":1,"text":"美術老師宣布下個月有校內漫畫比賽，自由報名，要交三頁完稿。你畫畫不錯，也一直說想走創作這條路，但三頁完稿得花掉好幾個週末，你有一點猶豫。","c":[{"t":"問同學要不要報，他報名我就跟著報","q":1,"tag":"◐ 又把鏡子借給別人照了——他的終點裡有沒有漫畫，跟你的是兩件事。"},{"t":"想說再看看，反正離截止還有一個月","q":2,"tag":"「再看看」等於讓截止日替你選——一個月後的「來不及」不是選擇，是霧的安排。"},{"t":"照著終點想：這比賽在不在我的方向上","q":0,"tag":"✓ 答案不重要，「照鏡子」這個動作才重要——報或不報，只要是對著終點選的都好。"},{"t":"嫌麻煩直接跳過，這種比賽不差這一次","q":4,"tag":"⚠ 用「麻煩」當篩子，你會篩掉所有需要花力氣、卻會讓你長大的事。"},{"t":"先運動保養身體不斷更新，比賽隨緣","q":3,"tag":"☯ 更新是為了走更遠的路，不是「隨緣」的遮羞布——你的方向還是得自己回答。"}]},{"h":1,"text":"週四晚上九點，功課寫完還有一小時才要睡覺，手機在桌上發著光，而你抽屜裡躺著畫到一半的參賽漫畫稿。這一小時要怎麼用，完全由你自己來決定。","c":[{"t":"想說滑一下就好，回神已經十一點","q":1,"tag":"◐ 沒有罪，但請誠實記帳：這是「你選擇的休息」，還是「被收走的時間」？"},{"t":"覺得今天好累明天再畫，連續第四天","q":2,"tag":"累是真的，「連續第四天」也是真的——霧不搶時間，只是每天輕聲說「明天再說」。"},{"t":"乾脆熬夜通宵趕稿，明天上課再補眠","q":4,"tag":"⚠ 用整晚的睡眠換一夜熱血，隔天的課和精神一起賠進去——終點不是這樣換的。"},{"t":"先列七天計畫表要事第一，今晚休息","q":3,"tag":"☯ 排程是好事，但「先計畫、今晚不動」常是精緻的拖延——終點靠動工靠近，不靠表格。"},{"t":"先分三十分鐘給漫畫稿，剩下的再滑","q":0,"tag":"✓ 三十分鐘看起來很小，但終點是由一百個星期四的三十分鐘鋪成的，不是一次熱血。"}]},{"h":1,"text":"週日早上你打算徹底耍廢一整天，追劇和手遊都排好了。這時媽媽轉達阿嬤打電話來，想找你回去一起吃午飯，阿嬤最近常唸說很久沒有看到你了。","c":[{"t":"跟阿嬤說下次啦，反正她常常打來","q":1,"tag":"◐ 可以，只是「下次」這個詞你已經認得了——它常常是霧的另一個名字。"},{"t":"去吃午飯，耍廢挪到晚上照樣很爽","q":0,"tag":"✓ 十年後的你會記得這頓午飯，不會記得那天少滑的三小時——你已經會用終點換算價值了。"},{"t":"已讀媽媽轉達的訊息，假裝沒看到","q":2,"tag":"連「下次」都不肯說，是因為說了會內疚吧——你心裡其實有鏡子，只是不敢照。"},{"t":"回嗆「我的假日憑什麼被你們安排」","q":4,"tag":"⚠ 把邀請當侵犯，推開的是十年後你最想留住的人——這一嗆，代價比一天大。"},{"t":"傳張長輩圖給阿嬤，情感帳戶存一筆","q":3,"tag":"☯ 情感帳戶要用真實的陪伴存——一張貼圖，抵不了她想見你的那頓飯。"}]},{"h":1,"text":"自然課分組報告，主題是水資源，三週後要上台。第一次小組討論，組員急著把工作切一切就各自回家做，你隱約覺得少了什麼，老師走過來問你們的進度。","c":[{"t":"跟著分工就好，大家都是這樣做報告","q":2,"tag":"大家都這樣，不代表這樣會好——沒對過終點的分工，拼起來常是四不像。"},{"t":"先分工，細節等做下去再邊做邊喬","q":1,"tag":"◐ 有行動力，但「邊做邊喬」的成本是重工——先花十分鐘對終點，能省三個晚上。"},{"t":"反正到時再熬夜拼裝，先聊天再說","q":4,"tag":"⚠ 把三週的任務押在最後一夜，賠上的是全組的成績和你的信用。"},{"t":"先確認成品長怎樣、想讓全班帶走什麼","q":0,"tag":"✓ 先有第一次創造（心中的成品），第二次創造（分工執行）才不會各拼各的。"},{"t":"先輪流傾聽每個人的近況，增進感情","q":3,"tag":"☯ 感情好是綜效的土壤，但此刻該對的是報告的終點——先看終點，再談感情不遲。"}]},{"h":1,"text":"園遊會兩週後登場，班會上大家為了要賣雞蛋糕還是飲料吵成一團，兩派人馬互不相讓，你是活動股長，導師把主持權交給你，全班安靜下來等你開口。","c":[{"t":"先帶大家定目標：想賺多少、留下什麼","q":0,"tag":"✓ 先立終點，選項才有裁判——目標一清楚，賣什麼常常自己就有答案了。"},{"t":"喊統合綜效：兩種都賣，大家別吵了","q":3,"tag":"☯ 綜效不是各給一半的和稀泥——沒先定終點就兩種都賣，只會兩頭忙、兩頭虧。"},{"t":"直接投票表決，少數服從多數最快","q":1,"tag":"◐ 表決能收場，但沒對過目標的多數決，選的常是「人氣」不是「適合」。"},{"t":"誰吵贏就聽誰的，反正我不想得罪人","q":4,"tag":"⚠ 把決定讓給音量大的人，你交出的不只是主持權，還有全班的園遊會。"},{"t":"看隔壁班賣什麼賺錢，我們就跟著賣","q":2,"tag":"別班的答案長在別班的條件上——照抄座標，走的是他們的路，不是你們的。"}]},{"h":1,"text":"會考倒數一百天，班群每天都有人轉貼補習班衝刺班的廣告，同學一窩蜂報名，也有人開始天天刷題到半夜。你看著自己的成績單，思考這一百天該怎麼走。","c":[{"t":"大家都報衝刺班，跟著報比較安心","q":2,"tag":"你買的是「安心」不是「路線」——別人的衝刺班，治不了你的弱科。"},{"t":"先跟著同學進度刷題，有動總比沒動好","q":1,"tag":"◐ 有動是好的，但跟著別人的進度動，練到的常是他的弱點，不是你的。"},{"t":"先定目標校和各科差距，再回推排法","q":0,"tag":"✓ 以終為始：終點（目標校）減現況（成績單）等於路線——一百天才不會白忙。"},{"t":"焦慮到乾脆擺爛，反正努力也來不及","q":4,"tag":"⚠ 一百天能翻的牌其實很多——「來不及」是霧的話術，擺爛才是真的來不及。"},{"t":"先安頓身心天天冥想，成績只是身外物","q":3,"tag":"☯ 照顧身心是不斷更新的功課，但拿它躲掉「定目標」這一步，就成了漂亮的逃避。"}]},{"h":1,"text":"你是籃球校隊的二年級球員，賽季開始前，教練把每個人輪流叫去談話，問你：「這個賽季，你自己想達成什麼？」你愣了一下，過去你只是照表操課地練球。","c":[{"t":"說「想變強」，具體的還沒想那麼多","q":1,"tag":"◐ 「變強」是霧做的目標——它沒有形狀，練到季末也不知道到了沒有。"},{"t":"說「教練排什麼我練什麼」，最安全","q":2,"tag":"聽話不是壞事，但教練正在把方向盤遞給你——你又原封不動推了回去。"},{"t":"隨便掰一個目標應付，講完自己就忘","q":4,"tag":"⚠ 敷衍過教練，敷衍不了賽季——沒有座標的球員，上場只是在陪別人打球。"},{"t":"說「我會主動積極，每天最早到球場」","q":3,"tag":"☯ 態度是習慣一的功課，但教練問的是終點——沒有目標的勤奮，只是感動自己。"},{"t":"說出具體目標：拚先發和罰球命中率","q":0,"tag":"✓ 有形狀的目標自帶練習菜單——每天走進球場，你都知道今天要磨哪一塊。"}]},{"h":1,"text":"滑IG時看到同學經營的讀書帳號粉絲破千，另一個同學的舞蹈影片也被瘋狂轉發，你心裡發慌，覺得自己好像什麼都沒有，很想立刻也開一個帳號跟上大家。","c":[{"t":"馬上開帳號跟風，先搶到流量再說","q":2,"tag":"用別人的成功當自己的座標，追到了也只是站在他的終點，不是你的。"},{"t":"先想自己想被記得什麼，再決定開不開","q":0,"tag":"✓ 慌，是因為拿別人的地圖量自己的路——先定自己的終點，開不開帳號都踏實。"},{"t":"先開起來放著，要發什麼內容以後再想","q":1,"tag":"◐ 行動快是優點，但沒有終點的帳號，三篇之後就會斷更——先想再開不遲。"},{"t":"去留言區酸同學的帳號，看了就不爽","q":4,"tag":"⚠ 酸別人的路，長不出自己的路——你的焦慮沒少，還多了一筆壞帳。"},{"t":"先為同學的成功喝采，練習雙贏思維","q":3,"tag":"☯ 不嫉妒很好，但你的焦慮真正在問的是「我的終點是什麼」——喝采沒有回答它。"}]},{"h":1,"text":"你每週存一百元，目標是三個月後買一雙打球用的新球鞋。最近同學天天放學揪團訂飲料，一杯六十，不跟好像不合群，跟了存錢進度就會一直往後延。","c":[{"t":"每次都跟，不跟感覺會被大家排擠","q":2,"tag":"用「合群」付帳，最後常是鞋子沒買到、飲料也不記得喝了哪幾杯。"},{"t":"心裡記得球鞋，但被揪就不好意思拒絕","q":1,"tag":"◐ 終點還在心裡，手卻一直掏錢——沒有防線的目標，會被六十元一杯慢慢喝掉。"},{"t":"跟同學知彼解己，聊大家為何愛喝飲料","q":3,"tag":"☯ 理解別人是溝通功課，但你的課題是守住自己的終點——聊完，錢包還是要你自己顧。"},{"t":"設一週一杯的線，其餘照原計畫存下","q":0,"tag":"✓ 以終為始不是禁慾——設一條線，讓合群和球鞋都在你的地圖上各有位置。"},{"t":"跟爸媽多要錢，兩邊都不需要犧牲","q":4,"tag":"⚠ 用別人的錢繞過選擇，練不到「取捨」這塊肌肉——下次的誘惑只會更大。"}]},{"h":1,"text":"九年級可以報名技藝班，每週半天到高職上課，有餐飲、資訊、設計等類群。好友都選餐飲，說可以吃很飽，你對資訊有點興趣，報名表這週五就截止。","c":[{"t":"先想想要試探什麼方向，再選擇類群","q":0,"tag":"✓ 技藝班的終點是「試探未來」——帶著問題去上課的人，半天能換回一個方向。"},{"t":"跟好友一起選餐飲，有伴又能吃很飽","q":2,"tag":"「有伴」是別人的理由——用它選的課，上到一半你就會開始問自己為什麼在這。"},{"t":"選了資訊，但沒想過想從裡面確認什麼","q":1,"tag":"◐ 方向對了，可惜少帶了問題——沒有想確認的事，試探就只是換個地方上課。"},{"t":"選最容易混的班，把它當翹課半天用","q":4,"tag":"⚠ 把試探未來的門票拿來翹課，省下的半天，九年級選填時要加倍還。"},{"t":"放棄報名，要事第一應該留著補主科","q":3,"tag":"☯ 要事第一被誤用成「只有主科是要事」——生涯試探正是重要而不緊急的事。"}]},{"h":1,"text":"運動會大隊接力下週登場，你是體育股長，要排出二十個棒次。跑得快的同學都想跑最後一棒出風頭，跑得慢的不想跑，已經有人為了棒次在教室吵起來。","c":[{"t":"照座號排最公平，誰也不能有意見","q":2,"tag":"「公平」聽起來安全，其實是放棄思考——座號排不出目標，也排不出士氣。"},{"t":"把快的平均分散，其他就照大家意願","q":1,"tag":"◐ 有策略的雛形了，但還缺一句「我們這場要的是什麼」——目標先立，策略才站得穩。"},{"t":"先定目標：想拚名次還是全班都完賽","q":0,"tag":"✓ 終點不同，排法就不同——先讓全班對準同一個目標，棒次的爭吵自然降溫。"},{"t":"偷偷把慢的同學排掉幾個，找理由換人","q":4,"tag":"⚠ 為了名次犧牲同學的參與，贏了獎狀，輸掉的是被排掉那幾個人的整個運動會。"},{"t":"先開會傾聽每個人心情，聊到大家滿意","q":3,"tag":"☯ 傾聽很好，但沒先定「這場要達成什麼」，聊再久也排不出一張棒次表。"}]},{"h":1,"text":"你跟隔壁班一個同學走得很近，朋友們在群組起鬨，說今天放學就去告白，還幫你想好了台詞，已讀不回又會被虧到爆。你看著訊息，心跳有一點快。","c":[{"t":"先拖著不回，但一直沒想清楚要什麼","q":1,"tag":"◐ 拖住了起鬨，卻沒拖來答案——不面對的問題，下次起鬨時還會回來。"},{"t":"拗不過起鬨，照朋友寫的台詞去告白","q":2,"tag":"用別人的台詞說自己的心事——成不成，這段關係的開頭都不是你寫的。"},{"t":"把對方的聊天截圖丟群組，讓大家評","q":4,"tag":"⚠ 把兩個人的信任攤給全群組看，不管結果如何，你已經先輸掉了人品。"},{"t":"先知彼解己，去調查對方喜歡什麼","q":3,"tag":"☯ 了解對方是好事，但你連自己想要什麼關係都還沒想——先問自己，再問別人。"},{"t":"先想清楚想要什麼關係，再決定行動","q":0,"tag":"✓ 告白是第二次創造——先在心裡想清楚想走向哪種關係，行動才不會被起鬨推著走。"}]},{"h":1,"text":"暑假的家庭旅遊三天兩夜，爸爸說其中一天全權交給你安排，一家三口的行程、交通和預算都由你決定。你打開手機開始查，發現想去的地方多到眼睛都花了。","c":[{"t":"看網紅推薦哪裡就排哪裡，跟著走","q":2,"tag":"網紅的行程是拍給流量看的——你要排的是一家三口的一天，不是別人的腳本。"},{"t":"先想這一天想留下什麼回憶，再排點","q":0,"tag":"✓ 先在心中完成第一次創造——那張「回家後全家都想再看一次」的照片，行程自然成形。"},{"t":"把想去的全塞進去，能跑幾個算幾個","q":1,"tag":"◐ 熱情可嘉，但塞滿的行程沒有呼吸——貪多的一天，常常哪裡都沒真的到過。"},{"t":"只排自己想去的，爸媽反正都會配合","q":4,"tag":"⚠ 把全權當特權，這一天就從「全家的回憶」縮水成「你的行程」——託付被辜負了。"},{"t":"把這一天還給爸媽安排，知彼解己嘛","q":3,"tag":"☯ 尊重別人不等於放棄任務——爸爸交給你，正是要你練習兩次創造。"}]},{"h":1,"text":"暑假前，學校公布了一整面牆的營隊海報：科學營、文學營、籃球營、程式營，日期互相衝突只能選一個，同學各揪各的，報名下週截止，你站在海報前猶豫。","c":[{"t":"哪個朋友多就報哪個，有伴最重要","q":2,"tag":"朋友是加分項，不是座標——用「有伴」選的營隊，常在第二天就開始無聊。"},{"t":"挑海報設計最炫的報，看起來最好玩","q":1,"tag":"◐ 有興趣的直覺是好起點，但海報炫不炫，跟你想去的終點沒有關係。"},{"t":"都不報，整個暑假在家滑手機最實在","q":4,"tag":"⚠ 把所有門都關上，霧就替你安排了兩個月——開學時的空白會來討帳。"},{"t":"先想暑假結束想多會什麼，再挑營隊","q":0,"tag":"✓ 以終為始：先定「開學時想帶回什麼」，一整面牆的海報立刻只剩兩三張需要認真比。"},{"t":"請同學幫我投票選，人多智慧高嘛","q":3,"tag":"☯ 統合綜效是共創方案，不是把自己的選擇外包給別人投票——你的暑假你自己定。"}]},{"h":2,"text":"晚自習後回到家，明天要交的國文作業還沒動，手機卻一直跳出班群訊息和朋友傳的搞笑影片，你坐在書桌前猶豫該先碰哪一個。","c":[{"t":"先想像十年後的自己，寫人生使命","q":3,"tag":"☯ 以終為始是好概念，但此刻要解的是今晚的排序，不是人生藍圖。"},{"t":"關通知先寫完作業，再安心看訊息","q":0,"tag":"✓ 把重要的事排在誘惑前面，娛樂變成獎賞，第二象限就這樣守住。"},{"t":"先把訊息全回完，清空了再開始寫","q":2,"tag":"訊息緊急卻不重要，先清訊息只是把要事往後推，而且永遠清不完。"},{"t":"作業明早再抄同學的，今晚先耍廢","q":4,"tag":"⚠ 抄來的作業騙得過一晚，累積的債會在段考連本帶利討回來。"},{"t":"先寫作業，但手機放旁邊隨時瞄","q":1,"tag":"◐ 方向對了，可惜手機在視線內就是干擾源，專注要連環境一起設計。"}]},{"h":2,"text":"段考剩一週，科展報名表後天截止，媽媽又交代今天要整理房間，三件事同時壓在你身上，你盯著書桌不知道從哪一件開始下手。","c":[{"t":"三件輪流各做十分鐘，看起來都有動","q":1,"tag":"◐ 都有碰不等於都有進度，切換的成本會把你的專注切成碎片。"},{"t":"通通不管，先躺床滑手機逃避一下","q":4,"tag":"⚠ 逃避不會讓事情變少，只會讓三件事在更慌的時刻一起爆炸。"},{"t":"挑最簡單的先做，享受劃掉的快感","q":2,"tag":"用難易而非重要性排序是最甜的陷阱，小事劃了一堆，要事沒動。"},{"t":"分輕重緩急，先處理最關鍵的一兩件","q":0,"tag":"✓ 依重要性而非難易排序，先把最大的石頭放進瓶子，其餘填縫。"},{"t":"先找家人同學開會，凝聚三方共識","q":3,"tag":"☯ 統合綜效用在合作難題，這裡是你自己的排序題，開會解決不了。"}]},{"h":2,"text":"你早就排好今晚要準備明天上台的分組報告，好友突然傳訊揪你去夜市吃新開的雞排店，還說「不來就是不夠朋友」，你握著手機猶豫。","c":[{"t":"回他改約週五，今晚守住報告進度","q":0,"tag":"✓ 對誘人的邀約勇敢說不並給出替代方案，才能對重要的事說是。"},{"t":"想說人情難卻，去一下下就先回來","q":2,"tag":"「就一下下」是最常見的破口，被人情推著走，要事就被擠掉了。"},{"t":"先同理他的感受，聊到他滿意為止","q":3,"tag":"☯ 知彼解己用在化解衝突，這裡該做的是排序與婉拒，不是長談。"},{"t":"去了但提早走，回家熬夜補完報告","q":1,"tag":"◐ 看似兩全，其實熬夜燒掉明天上台的精神，兩邊都只拿到一半。"},{"t":"謊稱生病沒去，也沒心情做報告","q":4,"tag":"⚠ 用謊言換清靜，賠上信任又沒換到進度，是最虧的一條路。"}]},{"h":2,"text":"段考前一晚，你最愛的手遊剛好開限時新版本，班群裡大家都在討論新角色，而你明天第一節就考數學，進度還剩最後兩個單元。","c":[{"t":"整晚都在玩，明天靠考前十分鐘翻書","q":4,"tag":"⚠ 拿一晚痛快換考場慌張，明天的懊悔會把今晚的快樂全討回去。"},{"t":"邊讀邊看群組討論，兩邊都不想漏","q":1,"tag":"◐ 想兩全結果都打折，要事第一的關鍵是一次只專注最重要的一件。"},{"t":"先讀完該複習的，再用剩的時間玩","q":0,"tag":"✓ 先完成重要的事，娛樂就成了獎賞，順序對了玩起來也安心。"},{"t":"先寫下考後檢討計畫，展現主動積極","q":3,"tag":"☯ 主動積極沒錯，但考前最該做的是複習本身，不是規劃考後的事。"},{"t":"先玩限時新版本，書晚一點再讀","q":2,"tag":"被「限時」兩個字綁架，把重要的事讓位給緊急的誘惑，正中圈套。"}]},{"h":2,"text":"園遊會前一天，班上要你顧攤位佈置，社團學姐要你交成果海報，媽媽又要你回家幫忙包水餃，三邊都說很急，你只有一個放學後的晚上。","c":[{"t":"誰催得最大聲，就先去做誰交代的","q":2,"tag":"依音量而非重要性排序，會被最會催的人牽著走，要事反而墊底。"},{"t":"先傾聽三方需求，各聊半小時再說","q":3,"tag":"☯ 傾聽是好習慣，但今晚缺的是排序決斷，聊完三小時就沒了。"},{"t":"三邊都答應，結果每件都做半套","q":1,"tag":"◐ 都想顧的心意是好的，但沒有取捨，心力被撕碎就全部打折。"},{"t":"手機關機躲起來，三邊都裝沒看到","q":4,"tag":"⚠ 消失不會讓事情消失，明天三邊一起找上門，信用全部賠光。"},{"t":"排出輕重順序，婉拒或延後次要的","q":0,"tag":"✓ 分清輕重、對次要的事勇敢說不或改期，才守得住真正關鍵的。"}]},{"h":2,"text":"你的科展作品下個月才交，但需要每週累積實驗數據，今晚你打開紀錄表正要動工，班群和遊戲通知卻響個不停，你的手指在螢幕上懸著。","c":[{"t":"先磨練回訊快手，累積人際情感帳戶","q":3,"tag":"☯ 情感帳戶靠真誠累積，不靠秒回，此刻該守的是自己的專注。"},{"t":"暫時關掉通知，先完成今晚的進度","q":0,"tag":"✓ 主動把干擾擋在門外，守住重要不緊急的事，才不會總在救火。"},{"t":"先回完所有訊息，再開始做實驗紀錄","q":2,"tag":"讓緊急但不重要的訊息插隊，清完之後要事又被推遲了一天。"},{"t":"反正下個月才交，今晚先聊天再說","q":4,"tag":"⚠ 重要不緊急的事最容易被無限延後，最後總在死線前草草補完。"},{"t":"想專心卻忍不住每則訊息都瞄一眼","q":1,"tag":"◐ 每瞄一眼就斷一次思緒，看似沒耽誤，效率其實被切得稀爛。"}]},{"h":2,"text":"下週就是全校英語歌唱比賽，你是班上的主唱，卻整週都在整理筆記封面、排書桌、回同學閒聊訊息，練唱一次都還沒開始，今晚又想先弄小事。","c":[{"t":"知道練唱重要，但還是先被小事黏住","q":1,"tag":"◐ 心裡分得清輕重，行動卻被小事綁架，要事第一要敢先放下次要。"},{"t":"繼續拖，比賽前一天再臨時抱佛腳","q":4,"tag":"⚠ 把要事拖到最後一刻，準備不足又壓力爆表，等於拿班級榮譽去賭。"},{"t":"先清一堆小事，享受劃掉的成就感","q":2,"tag":"用劃掉清單的快感麻痺自己，看似有效率，比賽卻一直沒真正準備。"},{"t":"把練唱排第一，小事塞進零碎空檔","q":0,"tag":"✓ 先把影響最大的事擺最前面，其餘的填進縫隙，這就是要事第一。"},{"t":"先找全班統合綜效，討論隊形分工","q":3,"tag":"☯ 統合綜效是團隊階段的事，你自己的主唱功課沒練，討論也白搭。"}]},{"h":2,"text":"週日下午補完習只剩半天空檔，你想讀段考進度、想剪社團影片、想補眠、朋友又約打球，時間明顯裝不下全部，你攤開行事曆思考先排什麼。","c":[{"t":"先放最重要的大石頭，再用小事填縫","q":0,"tag":"✓ 先放大石頭，碎石自然找得到縫；反過來放，就全部塞不下了。"},{"t":"誰先傳訊息找我，我就先答應誰","q":2,"tag":"把半天交給運氣排程，要事只能撿剩的時間，通常什麼都撿不到。"},{"t":"先寫週記反省上週，鋸子磨利再說","q":3,"tag":"☯ 不斷更新值得做，但半天空檔的當務之急是排序，不是反省大會。"},{"t":"先解決最快完成的小事，累積手感","q":1,"tag":"◐ 勾掉小事很療癒，但療癒不等於前進，大石頭還在原地等你。"},{"t":"全部拿去補眠，醒來再看心情決定","q":4,"tag":"⚠ 休息是要事沒錯，但「全部拿去」是逃避穿著休息的外衣。"}]},{"h":2,"text":"晚上你正在複習後天的段考範圍，班群突然爆出一支超好笑的影片，訊息瞬間累積九十九加，你的手機在桌上亮個不停，你的進度才讀到一半。","c":[{"t":"乾脆闔上課本，跟著群組一路滑到底","q":4,"tag":"⚠ 兩則訊息就棄械投降，你親手把整個複習的晚上送了出去。"},{"t":"「先回個幾句，馬上回來繼續讀」","q":1,"tag":"◐ 「馬上回來」平均要三十五分鐘，切換的代價遠比你想的大。"},{"t":"手機調靜音，讀完進度再當點心看","q":0,"tag":"✓ 你沒有消滅誘惑，你只是替它排了時間，這一招就足夠了。"},{"t":"先雙贏思維，回群提議大家一起讀書","q":3,"tag":"☯ 雙贏用在利益衝突的談判，這裡該做的是守住自己的專注。"},{"t":"「看一下就好，不然明天跟不上話題」","q":2,"tag":"「跟不上話題」是自己嚇自己，點進去四十分鐘後你還在群裡。"}]},{"h":2,"text":"你這週行程已排滿：段考複習、社團成果驗收都在表上，好友臨時傳訊揪你明天放學去逛新開的文具店，說「就這次，錯過就沒了」。","c":[{"t":"直接放掉原本計畫，先陪朋友要緊","q":2,"tag":"誰臨時出現就讓位給誰，你的計畫表形同虛設，時間永遠被別人指揮。"},{"t":"先檢討自己人緣，寫關注圈影響圈","q":3,"tag":"☯ 影響圈是習慣一的功課，眼前這題是行程取捨，寫再多也沒排開。"},{"t":"答應他但提早離開，想說兩邊兼顧","q":1,"tag":"◐ 看似兩全，其實兩邊都只給了一半，計畫也被撕開一道口子。"},{"t":"謊稱被留校查作業，兩邊都不得罪","q":4,"tag":"⚠ 用謊言換和平，利息是信任，這筆帳遲早要連本帶利償還。"},{"t":"對照計畫發現衝突，誠實約改天","q":0,"tag":"✓ 對要事守信就是對自己守信，真朋友聽得懂誠實的「改天」。"}]},{"h":2,"text":"你每天放學進門就先倒在沙發滑手機，常常一躺就到晚餐，功課全擠到深夜。今天你決定認真研究破解法，想找出最有效的一招來改變。","c":[{"t":"先聽懂自己想耍廢的心情再慢慢談","q":3,"tag":"☯ 同理自己沒有錯，但這題缺的是流程改造，不是內心對話。"},{"t":"改流程：手機進門先充電，人先沖澡","q":0,"tag":"✓ 別跟誘惑拔河，繞開它；環境設計得好，意志力根本用不上。"},{"t":"靠意志力硬撐，相信明天忍得住","q":2,"tag":"放學後的意志力是全天最低點，拿最弱的兵去守最危險的關口。"},{"t":"換一張更軟的沙發，躺得更舒服些","q":4,"tag":"⚠ 你不是在破解黑洞，是在升級黑洞，給誘惑鋪了紅地毯。"},{"t":"請媽媽每天五點半準時盯著我讀書","q":1,"tag":"◐ 有效一週，然後你恨被盯、媽媽喊累；自己設計的流程才守得久。"}]},{"h":2,"text":"晚上八點半，遊戲群裡喊「五缺一」等你開團，但你答應媽媽九點前要把垃圾拿去追垃圾車，媽媽今天加班不在家，兩件事撞在一起。","c":[{"t":"狂傳訊息問媽媽能不能明天再倒","q":1,"tag":"◐ 媽媽在加班，你其實只是想把該自己做的決定外包出去而已。"},{"t":"「垃圾明天再倒啦，先打團要緊」","q":4,"tag":"⚠ 直接撕毀承諾去打團，這局你贏了，媽媽的信任被你提領一大筆。"},{"t":"「先進了再說，垃圾應該來得及吧」","q":2,"tag":"垃圾車的音樂不等人，那包垃圾會連同你的承諾一起放到發臭。"},{"t":"「你們先開，我倒完垃圾八點四十進」","q":0,"tag":"✓ 十五分鐘的差距，兩件事都有位子，說到做到的存款又進一筆。"},{"t":"跟隊友雙贏談判，換他們幫你想辦法","q":3,"tag":"☯ 雙贏思維是好工具，但倒垃圾是你的承諾，談判談不掉責任。"}]},{"h":2,"text":"你跟朋友約好八點半上線開團，媽媽卻突然叫你「現在馬上」去買醬油，你知道她燉的湯十點才會用到，你一邊戴耳機一邊猶豫怎麼回。","c":[{"t":"「我九點半下線就去買，來得及嗎？」","q":0,"tag":"✓ 大人的「馬上」有時也是貼紙，確認真正的死線再排位子。"},{"t":"「等一下啦！」先打再說，拖到被罵","q":2,"tag":"「等一下」沒說清楚是多久，在大人耳裡就等於「不想做」。"},{"t":"先放下手把，聽媽媽聊今天的心情","q":3,"tag":"☯ 傾聽很珍貴，但這題要的是確認死線與排程，不是深夜談心。"},{"t":"「好啦！」怒氣沖沖出門，整晚臭臉","q":1,"tag":"◐ 事是做了，但你用受害者模式做的，這是成本最高的做法。"},{"t":"「現在很忙！」頭也不抬繼續開團","q":4,"tag":"⚠ 對家人的請求用無視回應，你示範了「我的遊戲比你重要」。"}]},{"h":2,"text":"晚上十一點，你剛看完一集影集，畫面停在超大懸念，「下一集」按鈕正在發光，明天七點要起床上學，你的手指已經移到播放鍵上。","c":[{"t":"「都到懸念了，整季拚完再睡吧」","q":4,"tag":"⚠ 一集變一季，明天頂著熊貓眼進教室的是被懸念綁架的你。"},{"t":"改成邊滑短影音邊等自己睡著","q":1,"tag":"◐ 從一個黑洞跳進更碎的黑洞，短影音是沒有結尾的流沙。"},{"t":"關掉去睡，明天午休再跟同學討論","q":0,"tag":"✓ 期待明天看也是一種快樂，還免費附贈七小時完整睡眠。"},{"t":"先寫觀後感練文筆，累積寫作實力","q":3,"tag":"☯ 累積實力是好事，但半夜的要事只有一件，叫做睡覺。"},{"t":"「就再一集就好。」然後按了下去","q":2,"tag":"編劇的薪水就是用來讓你按這顆鈕，你在跟一百個專業大人對決。"}]},{"h":2,"text":"週日上午你排好要剪社團成果影片，表妹一家突然來訪，媽媽喊你出來招呼客人，一坐就快中午，你原本的計畫眼看整個被撞歪了。","c":[{"t":"「計畫毀了，算了，剪片下週再說」","q":2,"tag":"計畫被打亂不等於作廢，一次意外就棄船，任何計畫都活不成。"},{"t":"先跟表妹統合綜效，邀她一起剪片","q":3,"tag":"☯ 統合綜效需要對的夥伴與時機，硬拉客人做你的事只會兩頭亂。"},{"t":"全程臭臉滑手機，讓全家都感覺到","q":1,"tag":"◐ 陪也陪了、氣也氣了，兩頭都沒賺到，臭臉是最虧的第三選項。"},{"t":"躲回房間鎖門，假裝自己在寫作業","q":4,"tag":"⚠ 沒陪到人也沒剪到片，還在長輩那裡提了一筆款，三輸收場。"},{"t":"陪完客人重排，改成先剪三分鐘開頭","q":0,"tag":"✓ 計畫被撞歪時，高手縮小石頭，普通人直接把石頭丟掉。"}]},{"h":2,"text":"你正在寫最難進入狀況的數學題本，第十一題演算到一半，手機震動，同學傳來「明天要穿班服嗎」，你的筆停在半空中，思緒開始鬆動。","c":[{"t":"先回他並多聊幾句，經營同窗情誼","q":3,"tag":"☯ 經營情誼要挑時機，深度專注時段被切開，兩邊都沒顧好。"},{"t":"讀書前就設好勿擾，段落結束才看","q":0,"tag":"✓ 不是忍住不回，是打造不需要忍的環境，專注力用守的。"},{"t":"秒回他，然後順便逛了三個群組","q":2,"tag":"三十秒的問題，你付出重想第十一題的五分鐘加群組十五分鐘。"},{"t":"手機放手邊，邊寫邊隨時瞄一眼","q":4,"tag":"⚠ 手機在視線內，注意力就在它身上，你其實在守一顆會叫的炸彈。"},{"t":"不動，寫完這大題再一次回覆","q":1,"tag":"◐ 方向對了，但「記得等下要回」這個念頭本身也在偷偷耗電。"}]},{"h":2,"text":"你決定讀書時不再秒回訊息，心裡卻冒出聲音：「朋友會不會覺得我冷淡？會不會以後就不找我了？」你握著關成靜音的手機發呆。","c":[{"t":"發限動公告「本人以後不秒回見諒」","q":1,"tag":"◐ 立意良善，但昭告天下反而把小事變大，安靜改變就好。"},{"t":"改成每則都秒回貼圖，至少有回","q":4,"tag":"⚠ 為了不冷淡把一天剁成八百段，貼圖三秒、回神要三分鐘。"},{"t":"「會吧……所以還是只能繼續秒回」","q":2,"tag":"你用想像中的差評綁架了真實的一天，受歡迎的人其實很少秒回。"},{"t":"想想看：朋友晚兩小時回，我會絕交嗎","q":0,"tag":"✓ 用自己的真實感受破解想像的恐懼，晚點回但好好回的人評價不差。"},{"t":"先知彼解己，逐一私訊朋友問感受","q":3,"tag":"☯ 知彼解己用在真實衝突，這裡的敵人是想像，問卷解決不了。"}]},{"h":2,"text":"你的手遊每日任務已連續簽到一百四十七天，最近登入只剩「不想斷掉」的義務感，每天要花四十分鐘，你盯著任務清單問自己還要不要繼續。","c":[{"t":"「我是在玩遊戲，還是被遊戲玩？」","q":0,"tag":"✓ 問出這一題鎖鏈就鬆了一半，不想玩卻停不下的已不是娛樂。"},{"t":"「都一百四十七天了，斷掉多可惜」","q":2,"tag":"這叫沉沒成本，用已經花掉的時間，綁架接下來的每一天。"},{"t":"「先揪全班一起玩，發揮團隊綜效」","q":3,"tag":"☯ 綜效用在創造價值，把更多人拖進你想逃的坑不叫合作。"},{"t":"「先做完今天的份，之後再慢慢想」","q":1,"tag":"◐ 可以，但邊做邊想通常做完就忘了想，給自己一個回答期限。"},{"t":"「想那麼多很累，無腦點完就對了」","q":4,"tag":"⚠ 無腦點完正是它設計給你的動作，四十分鐘連快樂都沒換到。"}]},{"h":2,"text":"你認真盤點後發現，這款遊戲帶給你的快樂只剩剛開始的兩成，但班上朋友都還在玩，午休話題也繞著它轉，你考慮要不要改變玩法。","c":[{"t":"「再撐撐看，搞不好改版就好玩了」","q":4,"tag":"⚠ 你在等遊戲公司修好你的快樂，他們忙著修的是讓你離不開。"},{"t":"直接刪掉遊戲，跟過去一刀兩斷","q":1,"tag":"◐ 夠乾脆，但全有全無的戒斷常在一週後加倍反彈，降級走得更遠。"},{"t":"改成想玩才玩，週末朋友開團再上線","q":0,"tag":"✓ 把遊戲從老闆降回朋友，被每日任務追著跑的是無薪員工。"},{"t":"「先以終為始，立志當電競選手吧」","q":3,"tag":"☯ 以終為始要基於真實熱情，拿它替停不下來找藉口就本末倒置。"},{"t":"「大家都在玩，我退出多奇怪啊」","q":2,"tag":"用「大家都在玩」替一個你已經不快樂的習慣續命，最不划算。"}]},{"h":2,"text":"你答應自己每週三傍晚去操場跑三圈練體力，今天正要出門，朋友傳來「限定活動剩最後一小時」揪你上線，紅色的倒數計時在螢幕上閃。","c":[{"t":"「好哇走！」反正下週再跑也沒差","q":2,"tag":"跟自己的約最先被犧牲，因為它不會抗議，但它會默默記帳。"},{"t":"「先幫你打活動，這才是雙贏互惠」","q":3,"tag":"☯ 雙贏是兩邊都贏，放掉自己的承諾去成全對方，你這邊全輸。"},{"t":"「不行，我要跑步。」已讀不再回","q":1,"tag":"◐ 守住了約很好，補一句「跑完找你」只要三秒，關係不留疙瘩。"},{"t":"「限定欸！跑步哪天跑都一樣，先衝」","q":4,"tag":"⚠ 「限定」是最亮的貼紙，它讓永遠可以補的約，永遠補不回來。"},{"t":"「跑完二十分鐘就上，你等我一起」","q":0,"tag":"✓ 誰說只能二選一，你把跟自己的約和朋友的邀排成一條線。"}]},{"h":2,"text":"段考前七天的週一晚上，你攤開一張空白的七日計畫表，要把五科複習、兩份作業和社團收尾全部排進去，筆握在手上思考該怎麼下手。","c":[{"t":"先找讀書會夥伴，七天全部一起讀","q":3,"tag":"☯ 共讀能加分，但你自己的計畫與取捨沒定案，人多只會更亂。"},{"t":"最弱兩科排前三天，每天留彈性格","q":0,"tag":"✓ 困難的趁力氣最多先上，還替意外預留位子，計畫才活得下來。"},{"t":"不排了，反正計畫趕不上變化","q":2,"tag":"沒有地圖的七天，每一天都會被當下最大聲、最會催的事拖著走。"},{"t":"每天都寫「複習全部」，通通都讀","q":4,"tag":"⚠ 每天什麼都沾一點等於什麼都讀不透，沒有取捨就沒有計畫。"},{"t":"排好排滿，每天六格精確到分鐘","q":1,"tag":"◐ 美得像標本，第一個意外撞上來整張表就碎，因為沒有縫。"}]},{"h":2,"text":"讀書計畫執行到週三，數學老師突然加發一張明天要交的複習卷，但你今晚的格子早就排給英文了，你看著計畫表和考卷左右為難。","c":[{"t":"「今晚熬夜把兩個都做完就好了」","q":1,"tag":"◐ 是做完了，但燒掉的是明天的專注力，先想能不能換再想加。"},{"t":"「明天的事明天說，今晚照讀英文」","q":4,"tag":"⚠ 假裝沒看到要交的卷，它明早會變成大火，當著全班燒你。"},{"t":"「先寫卷，咦群組在對答案？看一下」","q":2,"tag":"閒聊假扮成討論功課混了進來，撕開包裝那是聊天不是讀書。"},{"t":"「跟週五的數學格交換，換格不加格」","q":0,"tag":"✓ 這張卷不是額外的事，是換了包裝的原計畫，表格毫髮無傷。"},{"t":"「先主動找老師談，爭取延後繳交」","q":3,"tag":"☯ 主動溝通是好習慣，但明明換個格子就能解，何必動用談判。"}]},{"h":2,"text":"考前最後一夜十點半，你的複習進度完成了八成五，腦中冒出聲音：「再熬一下，把最後一成五拚完！」你看著檯燈和床鋪之間猶豫。","c":[{"t":"收書洗澡十一點睡，讓腦袋上場","q":0,"tag":"✓ 用一成五進度換三成腦力最不划算，考卷考的是明天的腦袋。"},{"t":"熬到兩點，硬是拚到百分之百","q":2,"tag":"你帶著全部的進度和六成的腦袋進考場，考卷不考進度。"},{"t":"先寫自我肯定日記，補滿情感帳戶","q":3,"tag":"☯ 情感帳戶是存給關係用的，考前最後一夜，你該存的是睡眠帳戶。"},{"t":"多讀半小時就好，十一點半前睡","q":1,"tag":"◐ 比通宵聰明，但先問那半小時讀的是重點還是安慰劑。"},{"t":"焦慮到讀不下，滑手機滑到半夜一點","q":4,"tag":"⚠ 沒讀、沒睡、也沒玩，最虧的結局，焦慮連你的體力都拿走了。"}]},{"h":2,"text":"午休你正趕著寫下節要交的作文，好友拜託你陪他去福利社，被婉拒後加碼一句「好朋友欸，連這個都不幫？」語氣裡滿是失望。","c":[{"t":"「好朋友就該幫，走吧！」馬上起身","q":4,"tag":"⚠ 這頂帽子一戴上，你就交出了所有界線，下次他還會拿出同一頂。"},{"t":"完全不理他，低頭繼續寫自己的","q":1,"tag":"◐ 守住了時間，但已讀不回式的拒絕留下疙瘩，多一句話就能買回。"},{"t":"「就因為是好朋友我才敢說我在趕」","q":0,"tag":"✓ 「好朋友」被拿來當武器，你把它拿回來當橋，還約了下課。"},{"t":"「你先講講為什麼非要我陪？」細聊","q":3,"tag":"☯ 傾聽用錯了時機，作文死線就在下節課，先排序再談心。"},{"t":"嘆口氣說「好啦」，放下筆跟他走","q":2,"tag":"那聲嘆氣是你的時間被搬走的聲音，他也學到這招對你有效。"}]},{"h":2,"text":"熱音社成發前兩週，學長問你能不能每天放學留下來練團，但段考也剛好在成發隔週，你既不想放掉舞台，也不敢賭上成績，站在社辦門口。","c":[{"t":"「可以！」先答應，段考到時再想","q":2,"tag":"「到時候再想」的意思，就是把兩顆大石頭疊在同一天砸向自己。"},{"t":"「先跟學長雙贏談判，幫我劃水吧」","q":3,"tag":"☯ 雙贏不是要別人替你扛，排程問題要用計畫解，不是用人情解。"},{"t":"「那我退出成發好了，怕影響成績」","q":1,"tag":"◐ 這是你真心想要的舞台，先別急著丟，先試著替它找位子。"},{"t":"「兩個都放掉，最輕鬆也最乾脆」","q":4,"tag":"⚠ 為了不選而全丟，不是要事第一，是兩顆大石頭一起棄養。"},{"t":"「一三五留下練，二四回家衝進度」","q":0,"tag":"✓ 你沒有丟掉任何一顆大石頭，你給了它們各自的位子。"}]},{"h":2,"text":"計畫執行第三天，練完團朋友揪你去吃宵夜聊天，說「反正都這麼晚了」，但你今晚的格子還排著一回數學題本，書包在肩上突然變重。","c":[{"t":"「先陪你聊心事吧，朋友比較重要」","q":3,"tag":"☯ 重視關係沒錯，但他只是想吃宵夜，你卻拿要事替閒聊買單。"},{"t":"「今天不行，還有一回數學，週五我請」","q":0,"tag":"✓ 計畫不是排好看的，是用來守的，你還附了一個更好的約。"},{"t":"「呃……」被半推半拉走，回家很晚","q":2,"tag":"沒說出口的「不」，等於「好」，你的晚上就這樣被搬走了。"},{"t":"「去啊，明天的進度再補回來就好」","q":4,"tag":"⚠ 「明天再補」是萬用咒語，明天有明天的進度，洞補不回來。"},{"t":"「好啊走！」計畫是死的人是活的","q":1,"tag":"◐ 這句話本身沒錯，但連續說三天，計畫就真的死了。"}]},{"h":2,"text":"普通的下課十分鐘，隔壁同學興奮地揪你去走廊看別班吵架，說「超精彩的快來」，你桌上沒有急著要交的東西，但脖子痠、水壺也空了。","c":[{"t":"「喔走啊。」圍觀十分鐘吸收了零","q":1,"tag":"◐ 偶一為之無罪，但別人的戲永遠精彩，也永遠跟你無關。"},{"t":"衝過去加入戰局，幫其中一邊嗆聲","q":4,"tag":"⚠ 你不只捐了時間，還把自己捲進別人的戰場，可能記過收場。"},{"t":"每節下課都圍觀加滑手機，廁所用衝的","q":2,"tag":"一天七個下課七十分鐘，一學期你捐了多少時間給別人的戲。"},{"t":"去裝水、伸展一下，看看窗外放空","q":0,"tag":"✓ 身體保養永遠重要、永遠不緊急，十分鐘也能搬一顆好石頭。"},{"t":"擠進去勸架，發揮知彼解己的功力","q":3,"tag":"☯ 調解衝突需要授權與時機，路過硬勸常常變成第三個戰場。"}]},{"h":2,"text":"你是分組報告的組長，繳交日在兩週後，今天開小組會議，組員全在聊上週的球賽，沒人提報告的事，你看著空白的分工表想著怎麼開口。","c":[{"t":"當場訂週進度：本週找資料下週合稿","q":0,"tag":"✓ 用一週為單位排里程碑，把大石頭先放進日曆，火災就不會來。"},{"t":"「反正還有兩週，今天先聊天培養感情」","q":2,"tag":"重要不緊急的事就是這樣一路變成火燒屁股的，兩週一眨眼就沒。"},{"t":"先輪流分享球賽心得，累積革命情感","q":3,"tag":"☯ 情感帳戶要存，但開會的要事是分工排程，感情戲留給下課。"},{"t":"口頭喊大家要加油，但沒訂日期分工","q":1,"tag":"◐ 有提醒是好的，但沒有日期與分工的加油，散會就蒸發了。"},{"t":"懶得溝通，乾脆自己熬夜做完全部","q":4,"tag":"⚠ 你墊上健康和時間替全組扛，產能燒完，下次還是一樣。"}]},{"h":2,"text":"掃地時間你負責外掃區，同學拉你躲到樓梯間滑手機，說「衛生股長今天請假，不會有人檢查啦」，你拿著掃把站在原地想了一下。","c":[{"t":"把自己的份丟給同組的人去掃","q":4,"tag":"⚠ 你躲掉的十分鐘，是別人替你多流的汗，帳都記在信用上。"},{"t":"隨便揮兩下裝有掃，趕快去會合","q":1,"tag":"◐ 有做但只做表面，半調子的交差，騙得了別人騙不了地板。"},{"t":"照常十分鐘掃完自己的區域再說","q":0,"tag":"✓ 有沒有人檢查都做好本分，十分鐘做完，剩下的時間才真自由。"},{"t":"先開檢討會，討論打掃分工合理性","q":3,"tag":"☯ 制度可以檢討，但時機是班會，不是拿來當今天落跑的理由。"},{"t":"跟著去躲，反正今天真的沒人查","q":2,"tag":"「沒人看見」是最常見的破口，你在練習一種看人做事的習慣。"}]},{"h":2,"text":"今晚補習班的數學講義和學校明天要交的國文學習單都得完成，估計各要一小時，但你九點半就得睡，時間只夠專心做完一件半，你得先選。","c":[{"t":"先做比較喜歡的數學，國文再看著辦","q":2,"tag":"用喜好排序不是用重要性排序，明天要交的反而被晾在一邊。"},{"t":"先磨鋸子，整理書桌文具提升效率","q":3,"tag":"☯ 不斷更新是投資，但死線前一晚磨鋸子，是精緻的逃避。"},{"t":"兩件輪流各做一半，睡前都沒完成","q":1,"tag":"◐ 都有動工但都沒完成，切換讓你多付了一次又一次的暖機成本。"},{"t":"都不寫了，明天到校再想辦法應付","q":4,"tag":"⚠ 把今晚的責任丟給明早的自己，那個自己只會更慌更沒時間。"},{"t":"先做明天要交的，講義排到明晚","q":0,"tag":"✓ 死線近的先上，另一件立刻給新位子，兩顆石頭都沒被丟掉。"}]},{"h":2,"text":"你正在讀段考範圍，突然想起昨天發的限動有好幾則回覆還沒看，也想發一張讀書的照片，手已經不自覺把手機拿了起來，書頁停在原地。","c":[{"t":"先統計按讚數據，研究受眾喜好","q":3,"tag":"☯ 了解他人是習慣五的事，此刻你的要事在課本裡不在演算法。"},{"t":"限動排到晚上九點休息時段再處理","q":0,"tag":"✓ 社群不是不能玩，是給它一個固定位子，而不是隨時插隊。"},{"t":"「看一下回覆就好」結果滑了半小時","q":2,"tag":"社群沒有「一下」這種單位，每個入口都通往另外十個入口。"},{"t":"先拍照修圖發文，證明自己有在讀","q":4,"tag":"⚠ 讀書的照片騙得了限動，騙不了考卷，你在演讀書不是讀書。"},{"t":"快速瞄一眼就關掉，繼續回來讀","q":1,"tag":"◐ 有守住大局，但每瞄一次思緒就斷一次，不如整段隔離。"}]},{"h":2,"text":"會考倒數一百天，導師發下空白的週計畫表要大家規劃，你看著同學有人密密麻麻排滿整週，有人直接摺起來塞抽屜，你想找出自己的排法。","c":[{"t":"跟著排滿整週，每一格都不留白","q":1,"tag":"◐ 有規劃的心很好，但排好排滿等於沒有彈性，一次意外就全盤崩壞。"},{"t":"抄學霸的計畫表，照著他的過日子","q":4,"tag":"⚠ 別人的強弱科跟你不同，穿別人的鞋跑一百天，會磨出滿腳水泡。"},{"t":"塞進抽屜，反正計畫永遠趕不上變化","q":2,"tag":"不排的人不是自由，是把一百天交給每天最大聲的事去指揮。"},{"t":"先排每週大石頭，再讓小事填空檔","q":0,"tag":"✓ 一週計畫優於每日清單，先定大石頭，日子才不會被瑣事塞滿。"},{"t":"先寫下想考的高中校名，貼在桌上","q":3,"tag":"☯ 以終為始是起點沒錯，但目標貼好之後，路還是要一週一週排。"}]},{"h":2,"text":"為了衝段考，你連續三天熬夜到一點半，今天上課猛打瞌睡，筆記抄不全、小考反而退步，晚上你看著沒讀完的進度，想著今晚還要不要繼續熬。","c":[{"t":"今晚十一點前睡，白天效率換回來","q":0,"tag":"✓ 產出與產能要平衡，砍掉睡眠是殺掉會下金蛋的鵝。"},{"t":"繼續熬，靠奶茶和咖啡硬撐到考完","q":2,"tag":"用咖啡因借來的清醒是高利貸，白天打的每一個瞌睡都是要還的利息。"},{"t":"先訂賞罰契約，考差就罰自己禁玩","q":3,"tag":"☯ 自我要求是好事，但你缺的是睡眠不是懲罰，罰不出專注力。"},{"t":"提早半小時睡，其他照舊不調整","q":1,"tag":"◐ 方向對了但劑量不夠，白天的專注品質才是真正的槓桿。"},{"t":"乾脆放棄複習，反正讀了也記不住","q":4,"tag":"⚠ 從過勞盪到擺爛，兩個極端一樣輸，問題在方法不在放棄。"}]},{"h":2,"text":"班上瘋傳有人被告白的八卦，午休大家圍成一圈更新進度，連讀書群都在討論，月考就在三天後，你的講義才翻開第一頁，同學招手要你加入。","c":[{"t":"主動幫忙打聽細節，當情報中心","q":4,"tag":"⚠ 你不只捐了時間，還捲進別人的私事，哪天火就燒到自己。"},{"t":"邊聽邊翻講義，感覺兩邊都有顧","q":1,"tag":"◐ 耳朵在故事裡，眼睛在課本上，其實兩邊都只拿到殘影。"},{"t":"「考完我再聽完整版，先讀完這回」","q":0,"tag":"✓ 八卦重播不會少，考試不會等，你替熱鬧排了更好的時段。"},{"t":"先去關心當事人，練習同理傾聽","q":3,"tag":"☯ 當事人沒找你傾訴，主動湊上去不是同理，是另一種圍觀。"},{"t":"加入聽完整輪，講義原封不動","q":2,"tag":"別人的故事永遠精彩，也永遠跟你的成績單無關，看戲付的是時間。"}]},{"h":2,"text":"你很想參加暑假的科學營，報名下個月才截止，但要準備自傳和老師推薦函，你每次想到都說「之後再弄」，一轉眼已經過了兩個星期。","c":[{"t":"「還有一個月，等變急了自然會動」","q":2,"tag":"等它真的變急，老師沒空寫推薦函、自傳只能熬夜趕工，品質全打折。"},{"t":"先大量蒐集十個營隊，通通比較過","q":3,"tag":"☯ 研究選項像是勤勞，但目標早就確定，過度比較只是拖延。"},{"t":"先把營隊網頁加入書籤，想到再看","q":1,"tag":"◐ 有放在心上，但沒有排進日曆的事，等於還停在願望階段。"},{"t":"乾脆放棄報名，省得麻煩這麼多","q":4,"tag":"⚠ 因為怕麻煩丟掉真心想要的機會，這是對未來的自己毀約。"},{"t":"本週就排一小時寫自傳、約老師","q":0,"tag":"✓ 重要不緊急的事不會催你，主動給它位子，才不會變成急件。"}]},{"h":2,"text":"考前一週，同學跟你借你花整學期整理的複習筆記，還希望你每天午休幫他講解一小時，你自己的複習進度其實也很緊，他眼巴巴地看著你。","c":[{"t":"「這是雙贏啊」，把自己讀書全停掉","q":3,"tag":"☯ 雙贏的前提是不輸掉自己，賠上進度的成全是輸贏不是雙贏。"},{"t":"筆記借他，講解改約考後或縮短","q":0,"tag":"✓ 幫忙可以，但先守住自己的要事，界線畫清楚才幫得長久。"},{"t":"不好意思拒絕，每天犧牲整個午休","q":2,"tag":"被人情推著走，你的複習時間被整批搬空，最後兩個人一起緊張。"},{"t":"騙他說筆記弄丟了，躲掉這件事","q":4,"tag":"⚠ 一個謊要用十個謊圓，考後他發現筆記還在，友情就碎了。"},{"t":"答應他但每次講到一半就喊停","q":1,"tag":"◐ 想兼顧卻沒說清楚額度，對方期待落空，你也心神不寧。"}]},{"h":2,"text":"你是學藝股長，老師要你這週完成教室佈置比賽的設計圖，段考複習也在燒，你發現美術社的同學其實很會畫，正在想這件事該怎麼處理。","c":[{"t":"請他幫忙但沒說清楚需求和期限","q":1,"tag":"◐ 有交託但沒說標準，成品不能用還得重做，等於沒交託。"},{"t":"拖到最後一天，隨便交一張了事","q":4,"tag":"⚠ 班級的事被你賭掉，信任跟成績一起輸，最貴的一種省事。"},{"t":"全部自己來，熬夜也要親手完成","q":2,"tag":"什麼都自己扛看似負責，其實是把複習時間整批賠了進去。"},{"t":"邀他合作畫圖，自己排時間顧統籌","q":0,"tag":"✓ 要事第一也包括交託，把對的事放給對的人，兩頭都有位子。"},{"t":"先辦全班票選佈置風格，凝聚共識","q":3,"tag":"☯ 共識有價值，但這週的死線容不下流程秀，先出圖再優化。"}]},{"h":2,"text":"會考倒數，你想把每週兩次的籃球練習全部停掉換成讀書，但你發現最近坐不住、脾氣變差、讀十分鐘就恍神，你站在球場邊考慮要不要走。","c":[{"t":"保留一次打球，當成充電固定行程","q":0,"tag":"✓ 運動是產能投資，重要不緊急，砍掉它讀書效率反而下滑。"},{"t":"全部停掉，一分鐘都拿去讀書","q":2,"tag":"看似最拚，其實在燒機器，沒有保養的引擎跑不完一百天。"},{"t":"先幫全隊排讀書會，球友一起拚","q":3,"tag":"☯ 揪團共好立意佳，但你此刻要解的是自己的節奏，不是全隊的。"},{"t":"改成偶爾想到才去投幾顆球","q":1,"tag":"◐ 有留活動但沒有固定位子，忙起來第一個消失的就是它。"},{"t":"照常打好打滿，讀書再看情況","q":4,"tag":"⚠ 用「保養產能」當藉口照玩不誤，天平往另一邊整個翻掉。"}]},{"h":2,"text":"媽媽宣布這學期開始你要負責每天晚餐後洗碗，你覺得那正好是讀書的黃金時段，很想抗議，但她說家事本來就該分工，你在餐桌前想著怎麼辦。","c":[{"t":"答應了但常常「忘記」，讓媽媽收尾","q":4,"tag":"⚠ 用裝忘毀約，媽媽的信任被一筆一筆提領，遲早清算。"},{"t":"有讀書計畫的日子洗，沒有就跳過","q":1,"tag":"◐ 看心情履行的承諾不算承諾，家人看到的是不穩定的你。"},{"t":"把洗碗排成固定行程，讀書時段微調","q":0,"tag":"✓ 家人的承諾也是大石頭，給它固定位子，就不會天天打架。"},{"t":"先發起家庭會議，重新表決分工","q":3,"tag":"☯ 溝通管道是好的，但先做出誠意再談調整，順序反了像賴帳。"},{"t":"每天拖到被唸才心不甘情不願去洗","q":2,"tag":"事情沒少做，還天天附贈一場親子摩擦，成本最高的做法。"}]},{"h":2,"text":"兩個好朋友吵架了，各自私訊你評理，訊息一直跳，你正在複習明天小考的範圍，一邊是進度一邊是友情，你的手指停在輸入框上不知道先回誰。","c":[{"t":"立刻放下課本，兩邊輪流回到半夜","q":2,"tag":"被急迫感綁架，複習沒了，碎片式回覆也沒真的幫到誰。"},{"t":"馬上分析誰對誰錯，傳長文評理","q":3,"tag":"☯ 先診斷後開藥沒聽先判，這不是知彼解己，是火上加油。"},{"t":"邊讀邊回，一心二用兩邊都顧","q":1,"tag":"◐ 訊息斷一次思緒斷一次，安慰也只剩貼圖等級的溫度。"},{"t":"已讀不回裝沒事，等他們自己和好","q":4,"tag":"⚠ 兩個好友的求助被晾著，考完你可能同時失去兩段友情。"},{"t":"先訊息安撫，約今晚考完專心聽","q":0,"tag":"✓ 友情重要但不急在這一刻，給它一個完整時段勝過碎片安慰。"}]},{"h":2,"text":"你用電腦查分組報告的資料，首頁跳出一排你最愛的遊戲實況推薦影片，縮圖每一支都超吸引人，報告文件才打了一行標題，游標在影片上徘徊。","c":[{"t":"「先研究實況主話術，練表達力」","q":3,"tag":"☯ 磨練表達是不斷更新，但拿它包裝分心，報告不會自己長出來。"},{"t":"文件開全螢幕，查完資料再看影片","q":0,"tag":"✓ 把誘惑移出視線、讓要事佔滿畫面，環境設計贏過意志力。"},{"t":"「先看一支醒醒腦，等下更有效率」","q":2,"tag":"「先看一支」是自動播放設計好的入口，一支後面排著一百支。"},{"t":"整晚看好看滿，報告丟給組員扛","q":4,"tag":"⚠ 你的娛樂讓別人加班，組員記住的不是影片，是你的缺席。"},{"t":"影片開小視窗掛著，邊看邊打報告","q":1,"tag":"◐ 覺得有進度，其實每一段都要重讀，時間悄悄付了兩倍。"}]},{"h":2,"text":"週五晚上你列了週末待辦：訂正考卷、寫作文、幫阿公慶生、剪社團影片，週六睡醒你卻先開了手機，一滑就到中午，下午你重新拿起那張清單。","c":[{"t":"「先做最快的訂正，找回一點感覺」","q":1,"tag":"◐ 起步是好的，但先撿小事，最大的石頭可能又擠到深夜。"},{"t":"「都中午了，這週末乾脆整個放掉」","q":4,"tag":"⚠ 用「反正已經晚了」把整個週末一起賠進去，黑洞最大的一口。"},{"t":"「先躺著再滑一下，下午再開始啦」","q":2,"tag":"「等一下再開始」就是早上那個黑洞的延長線，劇本一模一樣。"},{"t":"「半天沒了，剩下的先搬最大的石頭」","q":0,"tag":"✓ 不為打翻的時間哀悼，只問剩下的時間裡最重要的是哪件。"},{"t":"「先寫反省日記，檢討自己為何墮落」","q":3,"tag":"☯ 自我覺察值得做，但現在寫兩小時檢討，等於再捐半天給黑洞。"}]},{"h":2,"text":"段考剛結束，考卷發回來你錯了一堆，放學同學都約去飲料店慶祝解脫，老師說訂正自由決定不強制，你把考卷折起來時猶豫著要不要先處理。","c":[{"t":"先花半小時訂正弄懂，再去會合慶祝","q":0,"tag":"✓ 訂正是重要不緊急的黃金投資，趁記憶最熱的時候弄懂，效益最高。"},{"t":"考都考完了，訂正等下次段考前再說","q":2,"tag":"「下次考前再說」通常等於永遠不說，同樣的錯會原封不動再考一次。"},{"t":"先寫下段考百日衝刺的宏偉藍圖","q":3,"tag":"☯ 以終為始的藍圖很勵志，但眼前的要事是把錯的弄懂，不是寫口號。"},{"t":"先去慶祝，回家再看有沒有力氣訂正","q":1,"tag":"◐ 有想到要訂正，但排在力氣用完之後的事，多半不會真的發生。"},{"t":"把考卷塞進抽屜裡，眼不見為淨","q":4,"tag":"⚠ 眼不見為淨只是把地雷埋回原地，會考的時候它會一顆一顆引爆。"}]},{"h":3,"text":"小組報告要分工，最麻煩的資料整理沒人想碰，大家開始互推，眼看氣氛越來越僵，組長看向你，等你先表態。","c":[{"t":"自己默默扛下最難的，心裡卻很委屈","q":1,"tag":"◐ 犧牲自己成全別人是損己利人，不是雙贏；長期委屈會讓合作走不遠。"},{"t":"說要事第一，先各自排好讀書計畫再談","q":3,"tag":"☯ 要事第一是管自己的時間，這裡卡住的是分工怎麼談——概念對但用錯地方。"},{"t":"提出照各人強項分工，麻煩的拆開共同扛","q":0,"tag":"✓ 雙贏不是分餅是把餅做大：讓每人做擅長的事，難題拆開共扛，全組都受益。"},{"t":"搶先挑走最輕鬆的，剩下讓別人去分","q":2,"tag":"利己損人是「我贏你輸」——這次佔了便宜，下次沒人願意跟你同組。"},{"t":"擺爛拖到最後，逼別人替你收尾","q":4,"tag":"⚠ 兩敗俱傷：報告做不好，關係也毀了——這是雙輸，傷最重的是你自己。"}]},{"h":3,"text":"段考前一週，圖書館唯一一本重點參考書你和同學同時想借，規定一次只能一人借走兩週，剛好卡住整個複習期。","c":[{"t":"商量拆成輪流借閱時段，兩人都用得到","q":0,"tag":"✓ 資源看似有限，用點巧思常能找到讓彼此都受益的安排——這就是把餅做大。"},{"t":"偷偷把書藏起來，讓對方根本借不到","q":4,"tag":"⚠ 你贏了一本書，卻輸掉人品與信任，代價比那本書貴太多了。"},{"t":"用各種理由說服對方應該讓你先拿","q":2,"tag":"一心只想自己先拿，是匱乏心態——怕別人多拿就等於自己少拿。"},{"t":"禮讓對方先借，自己乾等卻有點不甘","q":1,"tag":"◐ 退讓是善意，但心不甘情不願就不是雙贏；雙贏是兩邊都覺得好，不是一方忍。"},{"t":"說以終為始，回家先寫讀書願景圖","q":3,"tag":"☯ 以終為始談的是人生方向，眼前要解的是兩人怎麼共用一本書——答非所問。"}]},{"h":3,"text":"班際籃球賽下週開打，隔壁班實力最強，隊上有人提議去偷看他們練球、打聽戰術，甚至想辦法干擾對方準備。","c":[{"t":"偷瞄對方戰術，好讓自己佔點便宜","q":2,"tag":"把心思放在比贏對方而非讓自己更強，贏了也虛——你錯過真正變強的機會。"},{"t":"加入干擾計畫，先搞垮對方再說","q":4,"tag":"⚠ 贏得骯髒，既學不到真本事，也輸掉品格——這種勝利不值一文。"},{"t":"不參與破壞，但也提不起勁認真練","q":1,"tag":"◐ 不害人是底線，但消極不投入，等於放棄和對手互相成全、一起變強的機會。"},{"t":"專注把自己隊練到最好，光明正大對決","q":0,"tag":"✓ 把對手當磨刀石，逼自己變強——正道的競爭讓兩隊都進步，這才是雙贏精神。"},{"t":"提議先寫班隊使命宣言凝聚向心力","q":3,"tag":"☯ 使命宣言是以終為始的工具，但眼前該回應的是「要不要使壞」——沒有正面接球。"}]},{"h":3,"text":"你想用重複的遊戲卡跟同學換他多的閃卡，兩人開始談條件，他出的價你覺得虧，你出的價他也搖頭，僵在那裡。","c":[{"t":"說不斷更新，先回家練談判技巧再說","q":3,"tag":"☯ 不斷更新是磨練自己沒錯，但交易卡在眼前，逃回家練功解決不了這一局。"},{"t":"問出彼此最想要哪張，重新組合方案","q":0,"tag":"✓ 卡住時先問需求再談價碼——搞懂彼此真正想要的，常能組出雙方都賺的方案。"},{"t":"主動讓利多貼幾張，自己有點吃虧","q":1,"tag":"◐ 一味退讓是我輸你贏，不是雙贏；委屈成交的交易，下次你就不想再換了。"},{"t":"混一張假卡進去，換到手就跑","q":4,"tag":"⚠ 用欺騙換好處，贏了卡片輸了信任——被發現那天，你在班上再也換不到東西。"},{"t":"想盡辦法凹到自己這邊多佔一點","q":2,"tag":"一心只想多撈是我贏你輸的算計——這次佔了便宜，下次沒人想跟你交換。"}]},{"h":3,"text":"班際成果展的話劇要選主角，你和最好的朋友都想演同一個角色，導演的同學說再喬不攏就要直接抽籤決定了。","c":[{"t":"偷偷跟導演說他壞話，把他排擠掉","q":4,"tag":"⚠ 用抹黑把朋友踢開，贏到角色卻毀了友情與品格——這是最虧的買賣。"},{"t":"強調自己比較適合，要他讓給你","q":2,"tag":"只想著自己贏、要對方退，是把好友逼到對立面——贏了角色可能傷了感情。"},{"t":"先管好情緒，回家寫反省日記沉澱幾天","q":3,"tag":"☯ 沉澱情緒像主動積極，但抽籤期限就在眼前，躲開對話等於把結果交給運氣。"},{"t":"直接讓給好友，自己默默退出不爭","q":1,"tag":"◐ 退讓有風度，但只做到我輸你贏；雙贏是兩人都能上場，不是一方犧牲。"},{"t":"和好友一起討論，找出兩人都有舞台的安排","q":0,"tag":"✓ 與其搶同一個位子，不如一起想出雙主角或分幕輪演——把舞台做大就是雙贏。"}]},{"h":3,"text":"家裡只有一台電腦，你的報告和妹妹的作業都要今晚交，兩人同時坐到電腦前互不相讓，媽媽在旁邊皺起眉頭。","c":[{"t":"讓妹妹先用，自己熬夜撐到半夜趕工","q":1,"tag":"◐ 禮讓很體貼，但熬夜硬撐是損己利人；雙贏該是兩人的作業都做得完。"},{"t":"說要知彼解己，先聽她聊今天心情","q":3,"tag":"☯ 傾聽是好習慣，但現在要解的是「時間怎麼分」——聊心情反而拖垮兩人進度。"},{"t":"先對作業量，排出輪流時段各自做完","q":0,"tag":"✓ 花點巧思排時段，看似有限的資源也能讓兩人作業都完成——這就是第三方案。"},{"t":"用年紀大的身分壓她，要她先讓你用","q":2,"tag":"仗著身分要對方退是我贏你輸——贏了電腦，輸掉的是手足之間的信任。"},{"t":"把滑鼠藏起來，誰都別想先用","q":4,"tag":"⚠ 寧可大家都用不成也不讓步是雙輸——傷最重的是這個家今晚的氣氛。"}]},{"h":3,"text":"分組報告你熬了三個晚上做完大半內容，交件前組員討論封面掛名順序，有人主張照座號排，有人說照人緣好壞排。","c":[{"t":"提議把每人貢獻寫清楚，大家都露臉","q":0,"tag":"✓ 雙贏不是平分，是各自的付出都被看見——貢獻透明，功勞才不會變成心結。"},{"t":"威脅不改排法就把檔案刪掉重做","q":4,"tag":"⚠ 玉石俱焚的威脅是雙輸——報告毀了、信任也毀了，你什麼都沒贏到。"},{"t":"堅持自己做最多，理所當然掛頭牌","q":2,"tag":"你贏他輸的排法，這次爽了，下次沒人想跟你同組——獨贏做不了長久生意。"},{"t":"全組並列不分你我，維持表面和氣","q":1,"tag":"◐ 和氣，但讓多做的人吞下委屈——隱形的不公平，遲早在下次合作爆開。"},{"t":"說雙贏要體諒，掛名讓給人緣王換人情","q":3,"tag":"☯ 體諒不是討好：拿真貢獻換虛人情是我輸你贏——把雙贏招牌掛在退讓上。"}]},{"h":3,"text":"卡牌店限量卡只剩最後一張，你和好友同時看上，兩人湊的零用錢都剛好夠買，站在櫃檯前誰也不肯先鬆口。","c":[{"t":"趁他猶豫先掏錢結帳，手快有手慢無","q":2,"tag":"搶得到卡，搶不回交情——你贏一張卡，帳戶裡扣掉的是好幾年的信任。"},{"t":"裝作不想要，讓他愧疚主動相讓","q":4,"tag":"⚠ 用愧疚當貨幣操控朋友，買到卡賠上真誠——這筆交易從頭到尾都是提款。"},{"t":"提議合資買下，一人一半輪流保管","q":1,"tag":"◐ 妥協是各讓一步，雙贏是各進一步；輪流保管還是各拿半份，差一層。"},{"t":"談不出兩人都好的方案，就先都不買","q":0,"tag":"✓ 找不到雙贏就先不成交——寧可暫緩，也不讓任何一方吞下輸的感覺。"},{"t":"說主動積極，操之在我當然先買先贏","q":3,"tag":"☯ 主動積極是為選擇負責，不是搶先下手的藉口——概念是對的，用法歪了。"}]},{"h":3,"text":"分組報告明天要確認分工，兩位組員至今零產出、群組訊息已讀不回，其他組員私下抱怨連連，都在等組長的你出手。","c":[{"t":"說信任是情感帳戶，先請他們喝飲料存款","q":3,"tag":"☯ 情感帳戶是平日累積，不是交差前的賄賂——飲料換不到分工，先把任務講清楚。"},{"t":"開會攤開任務表，讓他們自選項目和期限","q":0,"tag":"✓ 不翻舊帳不貼標籤，給具體的事、明確期限加選擇權——台階加截止日才讓人動起來。"},{"t":"直接找老師告狀，要求把他們名字拿掉","q":1,"tag":"◐ 這是我贏你輸——出了一口氣，但接下來幾週的小組氣氛會像結冰的游泳池。"},{"t":"默默把他們的部分做完，多一事不如少一事","q":4,"tag":"⚠ 你累死，他們學到擺爛就有人收尾——這是我輸你贏，還教壞了整組。"},{"t":"在群組開嗆：有些人當這組有傭人是吧","q":2,"tag":"「有些人」一出口，對方只剩防衛和反擊——你把隊友變成敵人，事情還是沒人做。"}]},{"h":3,"text":"球隊要選新隊長，你和小傑都想當，投票前有同學起鬨要你們公開PK、輸的退出，兩邊的支持者已經開始互嗆。","c":[{"t":"私下散播小傑的壞話，讓大家別投他","q":4,"tag":"⚠ 踩著抹黑爬上的位子，隊伍遲早會知道——然後沒有人服你。"},{"t":"默默放棄，心想人緣比不過他算了","q":2,"tag":"表面大方心裡委屈，是我輸你贏——之後每次練球你都會有點酸。"},{"t":"回去寫領導使命宣言，證明自己格局大","q":3,"tag":"☯ 使命宣言是對自己的以終為始，但兩人的僵局要靠對話解，不是靠自我證明。"},{"t":"接受PK提議，靠實力光明正大分高下","q":1,"tag":"◐ 你接受了必有一方倒下的劇本；贏了頭銜，輸的那半隊帶著不甘離心。"},{"t":"先私下找小傑聊：你當隊長最想做什麼","q":0,"tag":"✓ 問「他要什麼」而不是急著贏過他——常會發現彼此想做的根本是兩件事。"}]},{"h":3,"text":"早自習你剛寫完數學作業，隔壁好友把手伸過來：「快啦，好朋友欸，借抄一下。」旁邊同學都在看你要不要遞過去。","c":[{"t":"嗆他怎麼不去抄別人的，很煩欸","q":1,"tag":"◐ 界線守住了但刀口太利——拒絕這件事，不需要連這個人一起砍。"},{"t":"說要知彼解己，先聽他為何沒寫完","q":3,"tag":"☯ 知彼解己用在化解誤會；他不是有苦衷，是想抄——先傾聽反而給了拖延的台階。"},{"t":"說抄的不借，但哪題卡住現在教你","q":0,"tag":"✓ 勇氣說不借，體諒給出路——拒絕了事情，留住了朋友，這是雙贏的平衡。"},{"t":"默默遞過去，不想把氣氛弄僵","q":2,"tag":"這不是人好，是我輸你贏——你付出風險，他學到「戳你就有」，下週還會再來。"},{"t":"開條件：借你抄，請我喝一週飲料","q":4,"tag":"⚠ 把作弊變成交易還親手定價——被抓到兩人一起零分，這筆生意虧到底。"}]},{"h":3,"text":"班會討論期末班費三千二怎麼用，烤肉派要的是全班同樂的回憶，桌遊派要的是平日下課有事做，兩邊等你提案。","c":[{"t":"提案辦披薩趴加購入桌遊，兩邊核心都保留","q":0,"tag":"✓ 不是各退一步的妥協，是各自要的本質都被滿足——這就是第三選擇的長相。"},{"t":"把錢平分給兩派，各自去花各自的","q":4,"tag":"⚠ 看似公平，其實兩邊的錢都不夠成事——硬分資源，常常是雙方都做不成。"},{"t":"私下對兇的那派說先讓步，下次都聽他們","q":2,"tag":"檯面下交易買到的安靜利息很高——下次他們會來討，而且加倍。"},{"t":"提議上下學期輪流辦，一次滿足一派","q":1,"tag":"◐ 方向對，但錢只有一份、學期只剩一個——卡在分資源，還沒拆開真正的需求。"},{"t":"說以終為始，先訂班級年度願景再討論","q":3,"tag":"☯ 以終為始很動聽，但眼前的僵局是需求沒對齊——先聽懂兩派要什麼再談願景。"}]},{"h":3,"text":"你想爭取平日晚上多用一小時手機，爸爸擔心影響睡眠和成績，抱著手臂說：「好，你說說看。」全家都在等你提案。","c":[{"t":"反問為什麼別人都可以，就我不行","q":2,"tag":"開場就控訴，對面立刻穿上盔甲——談判第一句就變成怪罪大賽。"},{"t":"說你說了算我都沒差，放棄提案","q":4,"tag":"⚠ 把方向盤整個交回去，他訂的版本你更不滿意——不提案的人沒有雙贏。"},{"t":"說那就十一點半，大家各退一步嘛","q":1,"tag":"◐ 各退一步是妥協：你少滑半小時、他多擔心半小時，兩人都拿到比較不滿意。"},{"t":"提平日十點半收機換週末十二點，試一個月","q":0,"tag":"✓ 你先讓、要的具體、還附試用期降低他的風險——設計兩邊都能贏的制度。"},{"t":"背影響圈的道理，說手機是我的影響圈","q":3,"tag":"☯ 影響圈是提醒你管好自己，不是跟爸爸搶主權的武器——概念對，戰場錯。"}]},{"h":3,"text":"晚上八點二十五分，妹妹的偶像節目八點半開播，你的球賽九點開打，兩人的手同時伸向客廳唯一的遙控器。","c":[{"t":"說要事第一，先回房讀書別看電視","q":3,"tag":"☯ 要事第一管的是你的排程，但衝突還在——明天同一時間，遙控器大戰照樣上演。"},{"t":"先對節目時刻表，看時段其實撞不撞","q":0,"tag":"✓ 把「搶」變成「對時刻表」——情緒退場、資訊上桌，很多家庭大戰就此消失。"},{"t":"說好啦給你看，憋著氣回房摔上門","q":1,"tag":"◐ 你讓了，但摔門聲出賣了你——帶著利息的委屈，會在奇怪的時機跟她算帳。"},{"t":"直接拔掉電視插頭，誰都別想看","q":4,"tag":"⚠ 為了不讓她贏連自己的球賽都犧牲——標準雙輸，還附贈一筆對妹妹的提款。"},{"t":"搶先抓住遙控器：我比較大我先看","q":2,"tag":"你贏得遙控器，她去跟媽媽哭——三分鐘後你失去遙控器，外加一頓罵。"}]},{"h":3,"text":"你發現最近老是跟媽媽要東要西又頂嘴，難怪開口借錢時她臉色很臭。你決定開始往她的情感帳戶存款，第一筆怎麼存。","c":[{"t":"先冷處理少回家吃飯，減少衝突機會","q":4,"tag":"⚠ 迴避不是存款，是停止往來——帳戶不會止血，只會慢慢結冰。"},{"t":"買一份貴的禮物，一次把虧欠補回來","q":2,"tag":"大禮像一次性還款，帳戶結構沒變——隔天照樣頂嘴，餘額立刻再見紅。"},{"t":"寫一份自我使命宣言，貼在房門給她看","q":3,"tag":"☯ 使命宣言是寫給自己的方向，不是貼給媽媽看的成績單——存款要存進她在乎的事。"},{"t":"拚一次好成績給她看，讓她驚喜","q":1,"tag":"◐ 有效但像定期大額，間隔太久——帳戶要的是天天小額：謝謝、主動、不頂嘴。"},{"t":"趁她最累的晚餐後默默洗碗，不邀功","q":0,"tag":"✓ 頂級存款：在她在乎的點上、用不求回報的方式——幾天後，你們的匯率就變了。"}]},{"h":3,"text":"你帶著開銷表跟媽媽談調高零用錢，她看完皺眉說：「漲可以談，但我怎麼知道你不會亂花？」話裡是擔心不是拒絕。","c":[{"t":"拍胸脯保證我不會亂花，你要相信我","q":1,"tag":"◐ 「相信我」是最弱的擔保品——她要的是就算你失控也有煞車的機制。"},{"t":"引用富足心態，說錢再賺就有別擔心","q":3,"tag":"☯ 富足心態是相信餅能做大，不是叫別人別管錢——她的擔心需要機制，不是口號。"},{"t":"提議漲到三百並每週記帳，兩個月後檢查","q":0,"tag":"✓ 把她的擔心變成制度：記帳加試用期——她贏得放心，你贏得調薪。"},{"t":"覺得被質疑，吼一句不給就算了走人","q":2,"tag":"談判桌被你自己掀了——下次再開這話題，難度乘以三。"},{"t":"賭氣說你不信我就算了，那都別給","q":4,"tag":"⚠ 她明明說可以談，你把擔心聽成拒絕——到手的調薪被情緒推掉了。"}]},{"h":3,"text":"好友拜託你借他手遊帳號打排位，拍著你的肩說會小心，但你練了半年的牌位可能被打掉，帳號還綁著付款資料。","c":[{"t":"明說帳號借誰都不借，約週末帶他玩分身","q":0,"tag":"✓ 清楚的不、不針對他、再給一條一起玩的路——拒絕了事情，留住了朋友。"},{"t":"開條件：你的帳號也要借我才公平","q":4,"tag":"⚠ 拿自己更不想做的事去交換——兩個帳號都進了風險，這是雙輸對賭。"},{"t":"勉強答應，叮嚀他不要亂打排位","q":2,"tag":"心裡是不、嘴巴說好——之後他每次上線你都提心吊膽，這是慢性失血。"},{"t":"騙他說自己忘記密碼了，先擋一下","q":1,"tag":"◐ 謊言是租來的盾牌，租金超貴——他哪天看到你上線，連你說的話都不能信了。"},{"t":"說先存情感帳戶，這次借他當存一筆","q":3,"tag":"☯ 存款是付出對方在乎的善意，不是交出自己的底線——勉強借用是提款不是存款。"}]},{"h":3,"text":"小安和阿哲大吵一架後互相封鎖，兩人都是你的好友。晚上小安私訊你劈頭就問：「你站哪邊？」訊息在螢幕上發亮。","c":[{"t":"回：我當然站你，阿哲那樣真的很過分","q":2,"tag":"三天後他們和好了，你罵阿哲的訊息還在——選邊的人常是戰場上最後的傷兵。"},{"t":"截圖傳給阿哲，讓他知道小安在拉票","q":4,"tag":"⚠ 搧風點火讓戰火升級——你不只選了邊，還親手把橋燒了。"},{"t":"先已讀不回，覺得好可怕想躲起來","q":1,"tag":"◐ 可以理解，但吵架敏感期的已讀會被腦補成「他不挺我」——躲得過表態躲不過誤會。"},{"t":"回：兩個都是朋友，我不罵任何一邊但可以聽你說","q":0,"tag":"✓ 拒絕門票、留下耳朵——把「選邊」換成「陪伴」，是唯一不輸的走法。"},{"t":"回：雙贏思維，我來當公親約你們調解","q":3,"tag":"☯ 找第三選擇沒錯，但兩人正在氣頭上，硬開調解會是把自己架上火線——先接住情緒。"}]},{"h":3,"text":"你在二手社團賣一雙只穿三次的球鞋，開價一千二，有學弟私訊：「八百，要不要？不要我找別人。」語氣急急的。","c":[{"t":"回以終為始，這鞋對我意義重大不減價","q":3,"tag":"☯ 以終為始是規劃人生的羅盤，不是抬價的話術——談判要對的是需求，不是情懷。"},{"t":"先問他是自己要穿嗎、什麼時候要用","q":0,"tag":"✓ 談價前先問需求——問出他急用、尺寸剛好，情報就是你最好的籌碼。"},{"t":"回一千四少一毛都不行，穿三次欸","q":1,"tag":"◐ 立場對立場硬碰硬——他真的轉身走了，也許回來，也許不會。"},{"t":"回八百？乾脆我送你算了，酸他一頓","q":4,"tag":"⚠ 用嘲諷反殺，談判桌瞬間變吵架桌——他掉頭就走，你一塊也沒賺到。"},{"t":"怕賣不掉，回好啦八百就八百","q":2,"tag":"秒答應反而讓他起疑：是不是鞋有問題——委屈了自己還嚇到對方。"}]},{"h":3,"text":"家政課做甜點，材料籃裡只剩最後一顆橘子，你和同學同時抓住不放：「我先拿到的！」「我比較需要！」老師走了過來。","c":[{"t":"力氣大的拿走，直接把橘子扯過來","q":4,"tag":"⚠ 用蠻力決定，是必有一方倒下的競技場邏輯——橘子爛了，感情也裂了。"},{"t":"提議猜拳，輸的人鬆手","q":2,"tag":"輸的人空手還帶著不甘——而你們永遠不知道，其實根本不用有人空手。"},{"t":"說知彼解己，先聊他今天心情好不好","q":3,"tag":"☯ 知彼解己是聽懂需求，不是漫無邊際地聊天——要問的是「橘子要拿來做什麼」。"},{"t":"提議切一半，一人一半最公平","q":1,"tag":"◐ 切完他的皮不夠、你的肉也不夠——公平的一半，常是雙方都不夠的同義詞。"},{"t":"先放軟問他：你拿橘子是要做什麼用","q":0,"tag":"✓ 傳說中的那一問：他要果皮做蜜餞、你要果肉裝飾——一顆橘子兩人都拿到百分百。"}]},{"h":3,"text":"園遊會你們班決定開高質感飲料店，企劃到一半有人發現隔壁班要賣雞排，全組哀號：「人潮會被搶光！」你靈光一閃。","c":[{"t":"提議避開鋒頭，改賣別種點心分散風險","q":1,"tag":"◐ 閃是閃開了，但還是讓別人的決定主導你們——差一步：能讓雞排反過來幫你們嗎？"},{"t":"說操之在我，別人賣什麼不在影響圈","q":3,"tag":"☯ 影響圈提醒你別窮擔心，但情報就在影響圈裡——看見機會也是操之在我的一部分。"},{"t":"想：排隊買雞排的人最需要什麼？飲料啊","q":0,"tag":"✓ 把對手變資源：雞排攤旁的飲料店不是敵人，是收割人潮的最佳位置——餅做大了。"},{"t":"提議去跟學校抗議，不准他們賣雞排","q":2,"tag":"力氣花在消滅對手而不是長出自己——這是獨贏思維的標準教材。"},{"t":"提議也改賣雞排，用低價跟他們拚了","q":4,"tag":"⚠ 正面價格戰，兩攤一起流血——把對手當敵人，誰都賺不到錢。"}]},{"h":3,"text":"你是籃球社招生負責人，熱舞社同學也要在班群發招生訊息，兩社說明會撞在同一天中午，你們都怕新生被對方搶走。","c":[{"t":"找對方談合辦聯合招生，把人潮做大","q":0,"tag":"✓ 富足心態：新生不是只有一批，把說明會辦成聯合嘉年華，兩社的餅一起變大。"},{"t":"在群裡暗酸熱舞社練不出成果留不住人","q":4,"tag":"⚠ 貶低對方墊高自己，新生看見的是你的格調——招生沒贏，名聲先輸。"},{"t":"搶先把訊息洗版，讓大家先看到你們","q":2,"tag":"洗版搶版面是匱乏心態——怕對方多拿就是自己少拿，結果全班都被吵到反感。"},{"t":"協調錯開時段，你們先我們後各辦各的","q":1,"tag":"◐ 錯開是不錯的安排，但只做到互不干擾——再往前一步，還能互相拉抬。"},{"t":"說要事第一，先顧好自己社課品質再說","q":3,"tag":"☯ 顧好品質是對的，但眼前的撞期不會自己消失——要事第一不是迴避協調的理由。"}]},{"h":3,"text":"學期初重新分配掃地區域，廁所這一區沒人肯選，衛生股長的你眼看抽籤時間快到，底下已經開始互相推來推去。","c":[{"t":"直接抽籤決定，聽天由命最省事","q":2,"tag":"抽籤最快，但抽中的人整學期心不甘情不願——省了討論，賠了士氣。"},{"t":"把廁所排給平常最不敢反抗的同學","q":4,"tag":"⚠ 柿子挑軟的吃是最醜的我贏你輸——他不敢說，但全班都看在眼裡。"},{"t":"自己認掃廁所，免得大家繼續吵","q":1,"tag":"◐ 你扛下來大家鼓掌，但這是損己利人——制度沒建立，委屈只會累積到下學期。"},{"t":"提出輪替制加減免條件，讓苦差有配套","q":0,"tag":"✓ 苦差配補償、大家輪著扛——把「誰倒楣」變成「怎麼公平分攤」，人人都能接受。"},{"t":"說統合綜效，開三小時班會慢慢共識","q":3,"tag":"☯ 統合綜效不等於冗長會議——掃地分配要的是簡單配套，別把小事開成大會。"}]},{"h":3,"text":"段考前你花整週做好各科重點筆記，好友開口要你直接傳給他：「反正你都整理好了，傳一下是會怎樣？」你有點猶豫。","c":[{"t":"說雙贏就是分享，再轉發給全班同學","q":3,"tag":"☯ 雙贏不是無條件放送——分享前先想彼此的付出與收穫怎麼平衡，才不會變濫好人。"},{"t":"約他一起讀，用筆記互相考對方","q":0,"tag":"✓ 筆記變共讀：他得到重點，你在講解中記得更牢——付出反而讓你更強，這是雙贏。"},{"t":"直接整份傳給他，朋友一場沒差","q":1,"tag":"◐ 大方，但你的付出被當成理所當然——白拿久了，他不會謝你，只會習慣。"},{"t":"傳一份故意漏頁的，讓他考不贏你","q":4,"tag":"⚠ 表面答應暗中使壞，是最傷信任的一種贏——被發現那天，友情直接歸零。"},{"t":"已讀不回，假裝沒看到這則訊息","q":2,"tag":"躲開了要求，也涼掉了友情——問題沒解決，下次見面只剩尷尬。"}]},{"h":3,"text":"校外教學好友拍了一堆合照，回家就要發IG限動，其中一張她拍得超美、你卻閉眼嘴歪，她已經在問要不要標記你。","c":[{"t":"等她發了再偷偷檢舉那則限動下架","q":4,"tag":"⚠ 檯面上不說、檯面下動手——她查到是你，這筆提款夠你們冷戰一個月。"},{"t":"叫她只發她單人的，合照全都不准發","q":2,"tag":"為了自己的形象要她全部不准發，是我贏你輸——她的開心瞬間被沒收。"},{"t":"說主動積極，練習不在意別人的眼光","q":3,"tag":"☯ 不在意眼光是修養，但雙贏是先溝通——明明一句話能解決，不必硬吞。"},{"t":"說隨便你，反正是你的限動你決定","q":1,"tag":"◐ 嘴上隨便心裡介意，是我輸你贏——照片掛一週，你的疙瘩也掛一週。"},{"t":"直說那張我不行，一起挑兩人都好看的","q":0,"tag":"✓ 說出自己的在乎，也顧到她想發的心情——兩人都好看的那張，就是第三選擇。"}]},{"h":3,"text":"你和同學組隊打手遊排位，兩人都最擅長也最想玩打野位，開場選角倒數三十秒，誰也不想先讓出這個位置。","c":[{"t":"說好這場你玩，下場換我，輪流","q":1,"tag":"◐ 輪流很公平，但每場都有人委屈半場——還沒問過：我們的目標是排位還是爽度？"},{"t":"說以終為始，想想十年後誰還在打電動","q":3,"tag":"☯ 以終為始拿來勸退隊友，聽起來有智慧，其實只是不想面對眼前的協調。"},{"t":"快速對強項：比誰的打野勝率高，另一人補位","q":0,"tag":"✓ 用資料代替搶奪：誰勝率高誰上，另一人練第二強位——隊伍贏面最大，兩人都受益。"},{"t":"趁倒數手快先鎖角色，先選先贏再說","q":2,"tag":"搶到位置，隊友心情輸在起跑點——這場就算贏了，下次他不想再跟你排。"},{"t":"他不讓就故意擺爛送頭，讓大家一起輸","q":4,"tag":"⚠ 要輸一起輸的擺爛是雙輸極致——牌位掉了，朋友也掉了。"}]},{"h":3,"text":"排球校隊只剩一個先發名額，教練說讓你和學姊自己討論誰上，這場是學姊國中最後一場正式比賽，但你的狀態正好。","c":[{"t":"找學姊談彼此在乎什麼，再一起跟教練提案","q":0,"tag":"✓ 先聽她在乎什麼——也許她要的是圓滿告別，先發加輪替的第三案就談得出來。"},{"t":"放話學姊狀態下滑，讓隊友幫你施壓","q":4,"tag":"⚠ 用輿論鬥掉學姊，這個先發是踩著人上去的——全隊都看在眼裡。"},{"t":"跟教練力爭自己狀態好，先發該給你","q":2,"tag":"只講自己的理由，是把隊友變成對手——贏了名額，輸了整隊的氣氛。"},{"t":"直接讓學姊上，最後一場給她圓夢","q":1,"tag":"◐ 成全很美，但沒說出口的委屈是隱形提款——真雙贏是兩人都點頭，不是你硬吞。"},{"t":"說不斷更新，回去加練體能等下一次","q":3,"tag":"☯ 精進自己永遠對，但眼前的名額要靠溝通分配——修練不能代替談判。"}]},{"h":3,"text":"暑假營隊分房，四人房只剩一個床位，你和好友都想跟那群聊得來的室友住，報名表就在眼前，只能填一個名字。","c":[{"t":"趁好友去廁所，先把自己名字填上去","q":2,"tag":"搶到床位，好友記住的是你的背叛——五天營隊，你們住在尷尬裡。"},{"t":"跟隊輔說好友會打呼，讓他被排去別間","q":4,"tag":"⚠ 造謠排擠好友，你贏了床位輸了朋友——營隊結束，這件事還會跟著你回學校。"},{"t":"猜拳決定誰住進去，乾脆又公平","q":1,"tag":"◐ 公平，但輸的人整個營隊都住在不甘心裡——先想過雙贏再退到猜拳也不遲。"},{"t":"找隊輔問能否調房，不行就一起換別間住","q":0,"tag":"✓ 先擴大選項再做決定——問過才知道還有加床或整組換房的第三條路。"},{"t":"說主動積極，先填先贏本來就合理","q":3,"tag":"☯ 主動積極是承擔責任，不是搶先下手的通行證——概念被拿來當藉口了。"}]},{"h":3,"text":"會考倒數百日，你數學強英文弱，同學剛好相反，他提議放學後互教一小時，你卻閃過念頭：教會他，他不就贏過我？","c":[{"t":"說要事第一，各自讀自己的效率最高","q":3,"tag":"☯ 效率是要事第一沒錯，但互教正是高效率的要事——概念被拿來包裝匱乏心態。"},{"t":"答應互教，他變強不會讓你變弱","q":0,"tag":"✓ 富足心態：會考不是只錄取一人，教別人是最深的複習——他變強，你也更強。"},{"t":"答應但留一手，最關鍵的解法不教他","q":1,"tag":"◐ 半開放的合作還是匱乏心態——他感覺得到你的保留，交流的品質跟著打折。"},{"t":"假裝答應，實際上教他錯誤的解題習慣","q":4,"tag":"⚠ 故意教錯是損人不利己的極致——被發現後，你失去的是全班的信任。"},{"t":"婉拒他，自己偷偷加強英文就好","q":2,"tag":"怕人贏過你而關上門，是匱乏心態——你守住的不是優勢，是孤單的讀書路。"}]},{"h":3,"text":"畢業前班聚，一半同學只能週六、另一半只能週日，群組吵了三天沒結論，主辦的你今晚就要公布日期，兩邊都在敲碗。","c":[{"t":"嗆再吵就不辦了，大家都不用聚","q":4,"tag":"⚠ 用不辦要脅全班，是雙輸的引爆鈕——你省了麻煩，賠上整班的回憶。"},{"t":"看哪邊人多就選哪天，省得再吵","q":2,"tag":"多數決最快，但一半的人帶著被忽略的感覺——分了勝負，沒解心結。"},{"t":"說知彼解己，先一對一深談每位同學","q":3,"tag":"☯ 知彼解己是好工具，但三十人一對一談到畢業都談不完——工具要配場合。"},{"t":"辦成兩攤小型聚，想來哪場就來哪場","q":1,"tag":"◐ 分兩攤照顧到所有人，但「全班最後一次同聚」的核心散掉了——再挖一層需求。"},{"t":"先問兩邊卡住的原因，也許能拆出新時段","q":0,"tag":"✓ 立場下面藏著需求——問出補習只到五點，週日晚場全班到齊，第三案就長出來。"}]},{"h":3,"text":"你和妹妹共用房間的大書桌，段考週她的美術作業攤滿整桌，顏料就壓在你的講義上，你一回房看到火氣就上來了。","c":[{"t":"忍下來去餐桌讀書，把房間讓給她","q":1,"tag":"◐ 退讓換來安靜，但段考週天天流浪，委屈會在某天爆開——那不是體諒是累積。"},{"t":"說雙贏思維，要她以後去客廳做作業","q":3,"tag":"☯ 掛著雙贏的名，行的是我贏你輸——把對方請出去不叫雙贏，叫驅逐。"},{"t":"壓下火氣，找她劃分桌面時段和地盤","q":0,"tag":"✓ 先處理心情再處理事情：分時段、劃地盤，兩人的需求都被安放——這是家裡的雙贏。"},{"t":"把她的東西全掃到床上，先搶回桌面","q":2,"tag":"先動手先贏的下場是大吵一架——桌面搶回來了，今晚誰都讀不下書。"},{"t":"偷把她的顏料藏起來，讓她做不下去","q":4,"tag":"⚠ 暗中破壞她的作業，是對家人的提款重罪——信任碎了，房間再大都嫌擠。"}]},{"h":3,"text":"熱音社和戲劇社都跟學務處申請週五放學用視聽教室，兩社成發都在下個月，兩位社長被找去協調，你是其中之一。","c":[{"t":"對彼此需求：拆時段或找替代場地都能談","q":0,"tag":"✓ 熱音要音響、戲劇要舞台——拆開需求常發現要的不是同一樣東西，雙贏就在細節裡。"},{"t":"動員社員去學務處施壓，逼對方讓步","q":4,"tag":"⚠ 用人數施壓是把協調變成戰爭——學務處看到的是兩個都不成熟的社團。"},{"t":"強調我們先申請的，按規定該給我們","q":2,"tag":"搬規定壓人，贏了教室輸了關係——下次換你們需要幫忙，門就關上了。"},{"t":"提議一週輪一次，大家機會均等","q":1,"tag":"◐ 輪流是公平的妥協，但兩社成發前都只拿到一半練習量——先問過需求再輪也不遲。"},{"t":"說以終為始，回去各寫社團十年願景","q":3,"tag":"☯ 願景要寫，但教室下週就要用——以終為始不能拿來拖延眼前的協調。"}]},{"h":3,"text":"你和同學合拍班級回顧短影音要在畢典播放，他堅持走搞笑路線，你想做催淚質感風，腳本會議吵到一半就散了。","c":[{"t":"配合他做搞笑版，懶得再吵下去","q":2,"tag":"口服心不服的配合是慢性提款——剪片過程你會一直嘆氣，成品也不會好。"},{"t":"自己偷偷剪好質感版，直接交給老師","q":4,"tag":"⚠ 繞過夥伴先斬後奏，影片播出那刻，你們的合作關係也下檔了。"},{"t":"各拍各的版本，再讓班上投票選一支","q":1,"tag":"◐ 投票能解決，但輸的人心血白費——先試著融合，比表決更接近雙贏。"},{"t":"回頭對目標：畢典想留給大家什麼感覺","q":0,"tag":"✓ 吵風格不如對目的——先笑後哭的結構讓兩種力道都到位，這才是統合綜效。"},{"t":"說統合綜效，兩種風格全塞進同一支","q":3,"tag":"☯ 綜效是一加一大於二，不是把兩坨東西硬黏——沒消化的拼盤，兩種味道都毀了。"}]},{"h":3,"text":"放學突然下起大雷雨，你和同學都沒帶傘，置物櫃只翻出你上週留的一把小摺傘，他家和你家在完全相反的方向。","c":[{"t":"說操之在我，他沒帶傘是他自己的選擇","q":3,"tag":"☯ 操之在我是管自己的選擇，不是見死不救的擋箭牌——體諒也是雙贏的一半。"},{"t":"先撐去超商看有無賣傘，沒有再想辦法","q":0,"tag":"✓ 卡住時先擴大選項——超商、公車站、等雨變小，多想一步就多一條兩全的路。"},{"t":"把傘借他，自己淋雨衝回家","q":1,"tag":"◐ 慷慨，但自己淋成落湯雞感冒三天不是雙贏——先找兩人都不淋濕的方案。"},{"t":"假裝沒看到他，先偷偷從後門溜走","q":4,"tag":"⚠ 逃避連拒絕的誠實都沒有——他明天知道了，連解釋的機會都不會給你。"},{"t":"說傘是我的，自己撐走留下他","q":2,"tag":"傘確實是你的，但見難不幫的畫面他會記很久——你保住了乾爽，流失了情誼。"}]},{"h":3,"text":"午休全校只開放一個籃球半場，你們班先到，隔壁班十分鐘後也到場邊等，人越聚越多，開始有人叫囂要你們讓場。","c":[{"t":"叫隊友故意拖時間，耗光整個午休","q":4,"tag":"⚠ 損人不利己：你們沒打好球，他們氣炸——明天開始，天天都是搶場大戰。"},{"t":"堅持先到先贏，叫他們明天請早","q":2,"tag":"規則上你沒錯，但天天結樑子會在別的地方討回來——贏了場地輸了關係。"},{"t":"說知彼解己，停球坐下聽他們的委屈","q":3,"tag":"☯ 傾聽用錯場合——午休只剩二十分鐘，此刻需要的是快速的分配提案，不是深談。"},{"t":"說好上下半場各用十五分鐘輪流","q":1,"tag":"◐ 輪流是及格的妥協，但兩班各打半場都不盡興——混著打不是更好嗎？"},{"t":"提議打混隊或三對三輪替，大家都有得打","q":0,"tag":"✓ 把「搶場地」變「一起打球」——混隊之後沒有你們我們，餅直接做大一倍。"}]},{"h":3,"text":"你提前一週預約圖書館討論室準備科展，到場卻發現另一組已坐在裡面趕明天的報告，雙方預約單的時段竟然重疊。","c":[{"t":"讓他們用，自己這組轉戰吵雜的川堂","q":1,"tag":"◐ 體諒對方很好，但整組的進度陪葬就是損己利人——先談過再退也不遲。"},{"t":"引影響圈，說系統出錯我們管不著先撤","q":3,"tag":"☯ 影響圈不是撒手不管——找館員協調就在你能影響的範圍內，別急著棄權。"},{"t":"對彼此需求急緩，一起找館員喬出方案","q":0,"tag":"✓ 他們明天就交、你們還有一週——對出急緩，換時段加借設備，雙方都保住進度。"},{"t":"拿出預約單要他們馬上收東西走人","q":2,"tag":"單據上你有理，但把趕死線的人掃地出門，你贏了房間，輸了口碑。"},{"t":"在走廊大聲嗆他們霸佔，鬧到館員來","q":4,"tag":"⚠ 把協調變成公審，兩組一起被請出圖書館——雙輸，還附贈丟臉。"}]},{"h":3,"text":"科展校隊放榜前，指導老師說最後一個名額在你和好友之間二選一，會參考你們的意願陳述，今晚就要各自交出去。","c":[{"t":"先跟好友聊各自強項，一起向老師提組隊案","q":0,"tag":"✓ 先問名額能不能變成互補的隊伍——很多「只能選一個」，其實是還沒人開口問。"},{"t":"偷改好友的意願陳述，讓他出局","q":4,"tag":"⚠ 動手腳搶名額是作弊等級的墮落——代價是名額、友情、信用全失。"},{"t":"在陳述裡放大自己、暗貶好友的弱點","q":2,"tag":"踩著好友墊高自己，就算入選，這段友情也記上一筆爛帳。"},{"t":"各自公平競爭，寫好自己的就好","q":1,"tag":"◐ 公平沒錯，但你們接受了「必有一人出局」的劇本——先試過把餅做大再競爭。"},{"t":"說要事第一，先準備段考科展隨緣","q":3,"tag":"☯ 排優先順序是好事，但拿要事第一當逃避競爭的下台階，兩頭都落空。"}]},{"h":3,"text":"週日你早就和同學約好看電影，媽媽臨時說外婆想孫子了，要你陪她回外婆家吃午餐，兩件事的時間整個撞在一起。","c":[{"t":"跟媽媽盧到底，說朋友約好了不能改","q":2,"tag":"硬碰硬只剩輸贏兩種結局——就算凹贏了，媽媽和外婆的失望你躲不掉。"},{"t":"假裝肚子痛哪裡都不去，躲回房間滑手機","q":4,"tag":"⚠ 用裝病逃避，兩邊都落空還賠上誠信——被拆穿那刻，連談判資格都沒了。"},{"t":"取消電影配合媽媽，心裡嘀咕一整天","q":1,"tag":"◐ 你去了，但臭臉全程寫在臉上——外婆看得出來，這趟陪伴的存款打了對折。"},{"t":"跟媽媽商量提早去外婆家，趕傍晚場電影","q":0,"tag":"✓ 先接住媽媽的需求，再提出兩全的時間表——午餐照吃、電影照看，這就是第三案。"},{"t":"說以終為始，親情比友情重要所以陪外婆","q":3,"tag":"☯ 排序聽起來成熟，但這題不必二選一——直接犧牲一邊，是還沒動腦的假雙贏。"}]},{"h":3,"text":"電競社要派一人參加全國賽，你和搭檔積分只差三分，社長丟下一句「你們自己決定」就走了，報名截止就在後天。","c":[{"t":"說不斷更新，兩人都棄賽回去練基本功","q":3,"tag":"☯ 精進沒有錯，但棄賽不是雙贏是雙輸——名額白白蒸發，誰都沒站上舞台。"},{"t":"研究賽制能否選手加教練，兩人一起出賽","q":0,"tag":"✓ 先讀規則再認命——很多比賽有隊職員名額，一個上場一個場邊指揮，兩人都在場上。"},{"t":"提議打三場加賽，用實力說話","q":1,"tag":"◐ 加賽公平，但仍是「必有一人留下」的劇本——先確認過沒有雙贏的路再說。"},{"t":"半夜用小號惡意檢舉他的遊戲帳號","q":4,"tag":"⚠ 惡意檢舉是最陰的損人——帳號查得回來，信任查不回來。"},{"t":"翻出積分紀錄，主張高三分的該直接去","q":2,"tag":"三分的差距撐不起獨拿的正當性——你贏了名額，之後的雙排他不會再上線。"}]},{"h":3,"text":"你們四個好友要合資買生日禮物給壽星，有人預算只有一百、有人想買八百的球衣直接除以三，群組討論瞬間安靜下來。","c":[{"t":"在小群組抱怨那個出一百的人很寒酸","q":4,"tag":"⚠ 背後嘲笑朋友的經濟狀況是最狠的提款——話傳回去那天，禮物再貴都沒意義。"},{"t":"說平分最公平，出不起的人退出就好","q":2,"tag":"用公平當刀，切掉了出不起的人——禮物買到了，友情的圈圈缺了一角。"},{"t":"說知彼解己，先問壽星想要什麼禮物","q":3,"tag":"☯ 問壽星是貼心，但現在卡住的是預算差距——先解決出多少，再談買什麼。"},{"t":"自己多貼錢補差額，別讓場面尷尬","q":1,"tag":"◐ 貼錢救了場面，但沒說出的犧牲會發酵——而且下次呢？制度比善意耐用。"},{"t":"提各出得起的數字，再依總額挑禮物","q":0,"tag":"✓ 雙贏先體諒各自的口袋深度——量力而出、心意不打折，禮物是大家的不是有錢人的。"}]},{"h":3,"text":"段考成績出來，好友第一次贏過你，整天拿著成績單到處炫耀，你心裡酸酸的，晚上他傳訊息約你一起檢討考卷。","c":[{"t":"簡短回句恭喜，但找藉口不去檢討","q":1,"tag":"◐ 禮貌有了，門卻關上了——酸意沒處理，只是延後發作。"},{"t":"說操之在我，刪好友眼不見為淨","q":3,"tag":"☯ 操之在我是選擇回應方式，不是切斷關係——刪好友刪不掉心裡的酸。"},{"t":"恭喜他並赴約，順便請教他進步的方法","q":0,"tag":"✓ 富足心態的檢定時刻：他的成功不會扣你的分——真心祝賀還能偷學他的方法。"},{"t":"已讀不回，暗自發誓下次一定電爆他","q":2,"tag":"把好友當假想敵是匱乏心態——你們本可互相拉抬，現在只剩暗自較勁。"},{"t":"到處說他這次是運氣好、猜題猜中而已","q":4,"tag":"⚠ 貶低別人的努力來止痛，痛沒止住，人品先破產——話一定會傳回他耳裡。"}]},{"h":3,"text":"班服設計投稿只會採用一件，你和同學的設計都進了決選，他私下找你：「要不要想個辦法，別讓我們變成敵人？」","c":[{"t":"試著合稿：你的主圖配他的配色與字型","q":0,"tag":"✓ 決選變合作：兩人掛名共同設計——班服品質更好，你們也從對手變戰友。"},{"t":"散布他的設計是抄網路圖的謠言","q":4,"tag":"⚠ 造謠抹黑是毀滅性提款——謠言拆穿那天，全班記得的是你的手段不是設計。"},{"t":"先發制人在班群拉票，衝高自己聲量","q":2,"tag":"把決選變成聲量戰，作品好壞反而沒人看——贏了投票，輸了作品的說服力。"},{"t":"說服自己平常心，公平投票各憑本事","q":1,"tag":"◐ 平常心很成熟，但他都主動遞出橄欖枝了——只守公平，可惜了合作的機會。"},{"t":"說要事第一，設計是小事讀書要緊退選","q":3,"tag":"☯ 讀書當然重要，但拿要事第一當退場藉口——既沒守住熱情，也沒回應他的誠意。"}]},{"h":3,"text":"國語文競賽組隊，你被抽中和害羞的轉學生同組，他作文其實很強但不敢上台，而比賽同時要比筆試和上台朗讀。","c":[{"t":"私下找老師要求換一個活潑的隊友","q":2,"tag":"急著換人是把人當成績工具——你還沒看過他的強項，就先判了出局。"},{"t":"放話抽到雷包隊友，先幫自己輸找理由","q":4,"tag":"⚠ 先貶低隊友替失敗鋪路——他聽到那天，你們連基本的合作都做不到了。"},{"t":"全部自己扛，筆試朗讀都你來比較保險","q":1,"tag":"◐ 你扛得動，但他全程當觀眾——比賽贏了，隊友的成長和參與感全輸掉。"},{"t":"按強項分工：他主筆試你主朗讀，互相補位","q":0,"tag":"✓ 雙贏是讓彼此的強項都上場——他的筆、你的聲音，一加一就大於二。"},{"t":"說統合綜效，逼他先突破自己上台朗讀","q":3,"tag":"☯ 綜效是截長補短，不是逼人硬闖弱項——把體諒抽掉的成長，只剩壓力。"}]},{"h":4,"text":"午休時，好友低著頭跟你說他最近家裡氣氛很糟、心情很悶。你腦中立刻冒出一堆建議想講，話都到嘴邊了，此刻你得決定怎麼回應他。","c":[{"t":"馬上把想到的建議全部講給他聽","q":2,"tag":"急著給答案，其實是急著被理解；他此刻要的是被聽見，不是被指導。"},{"t":"先專心聽完，重述他的感受再回應","q":0,"tag":"✓ 先診斷再開藥方：聽懂並說出他的感受，理解到位，建議才進得去。"},{"t":"勸他要事第一，先排好讀書計畫","q":3,"tag":"☯ 要事第一是好概念，但他現在需要的是被傾聽，不是一堂時間管理課。"},{"t":"安靜聽完，拍拍肩說我都在這裡","q":1,"tag":"◐ 陪伴是好的開始，但少了重述感受那一步，他不確定你真的聽懂了。"},{"t":"敷衍說想開一點，接著轉頭滑手機","q":4,"tag":"⚠ 看似省事，卻讓朋友覺得完全不被在乎——關係就是這樣一次次疏遠的。"}]},{"h":4,"text":"你想加入籃球校隊，晚餐時跟爸媽提起，他們立刻反對，說會影響功課，氣氛一觸即發。你很想證明自己有道理，開口前你得先決定怎麼談。","c":[{"t":"急著列出一堆理由，證明自己是對的","q":2,"tag":"只想被懂、不想懂人，溝通就變成各說各話——你贏了道理，輸了關係。"},{"t":"直接開雙贏條件：成績不掉就放行","q":3,"tag":"☯ 雙贏思維沒錯，但順序錯了——沒先聽懂他們擔心什麼，條件只是交易。"},{"t":"先問他們最擔心什麼，聽完再說明","q":0,"tag":"✓ 知彼解己：先理解對方在怕什麼，對話才有空間，你的想法才聽得進去。"},{"t":"點頭聽完，心裡卻完全沒打算理解","q":1,"tag":"◐ 形式上的「聽」騙不了人；沒有真心想懂，點再多次頭也通不了心。"},{"t":"摔筷子大吼你們不懂我，中斷對話","q":4,"tag":"⚠ 把唯一的溝通管道也砸斷，問題沒解決，誤會還會越積越深。"}]},{"h":4,"text":"下課後，同學偷偷告訴你，小安在別班的群組裡說你壞話。你越想越氣，明天就會在走廊遇到小安，你得決定接下來要怎麼處理這件事。","c":[{"t":"私下找小安問清楚，先了解全貌","q":0,"tag":"✓ 先求理解事實，再下判斷。很多怨恨，都源自一個沒問清楚的誤會。"},{"t":"先跟別人轉述，讓大家站你這一邊","q":2,"tag":"急著被理解、急著拉幫手，卻散播了沒查證的事——你可能正在製造傷害。"},{"t":"回到影響圈，專心讀書不理會八卦","q":3,"tag":"☯ 影響圈的概念是對的，但眼前該做的是先求證、先對話，不是迴避問題。"},{"t":"心裡先信了一半，見面卻裝作沒事","q":1,"tag":"◐ 沒求證就暗自記恨，等於讓謠言替你下結論——表面平靜，心裡已築牆。"},{"t":"當眾翻臉開罵，先發制人才不吃虧","q":4,"tag":"⚠ 誤會未明就先開戰，常把假的變成真的，親手撕裂一段可挽回的友誼。"}]},{"h":4,"text":"平常最愛講笑話的同學，今天一整天一句話都沒說，臉色很差，午休還趴著不動。你和他座位相鄰，下一節下課只有十分鐘，你想做點什麼。","c":[{"t":"想關心卻怕尷尬，最後還是沒開口","q":1,"tag":"◐ 有想理解的心是好的，但停在原地，關心就沒送到——一句你還好嗎就夠。"},{"t":"過去輕聲關心，靜靜聽他想不想說","q":0,"tag":"✓ 先給對方空間、用心聽，理解他的感受，遠比急著給意見更重要。"},{"t":"自己猜原因，還找其他同學一起討論","q":2,"tag":"沒去理解卻急著臆測張揚，事情越傳越歪——理解的第一步是問他，不是猜他。"},{"t":"傳紙條勸他以終為始，別想太多了","q":3,"tag":"☯ 以終為始用錯了地方——他現在需要的是被理解，不是一句目標喊話。"},{"t":"嫌他擺臭臉，也回敬他一張冷臉","q":4,"tag":"⚠ 不問緣由就以冷對冷，把可能需要幫助的人推更遠——誤解就是這樣加深的。"}]},{"h":4,"text":"掃地時間教室玻璃破了，老師認定是你打鬧弄破的，當著全班責備你，可是你當時人在走廊倒垃圾。全班都看著你，你得決定第一步怎麼做。","c":[{"t":"急著大聲喊冤，沒等老師把話說完","q":2,"tag":"只顧著讓自己被理解，卻不先理解老師的判斷從何而來，溝通變成各說各話。"},{"t":"當下憋著不說，回家越想越委屈","q":1,"tag":"◐ 忍住沒爆發是好的，但完全不溝通，誤會就留在那裡——理解要雙向才解得開。"},{"t":"想成這是磨練，主動積極不去計較","q":3,"tag":"☯ 主動積極不是吞下誤會不溝通；先聽懂再有禮貌地澄清，才是主動。"},{"t":"先冷靜聽完，再有禮貌地說明經過","q":0,"tag":"✓ 先聽懂對方為什麼這樣想，再清楚說明自己——這樣的澄清才聽得進去。"},{"t":"摔掃把頂撞老師，把場面鬧得更大","q":4,"tag":"⚠ 用激烈對抗回應誤會，把可澄清的事鬧成衝突，誤解沒解開，關係先壞了。"}]},{"h":4,"text":"你和最好的朋友因為借漫畫的小事吵翻，已經冷戰三天，上下學都刻意錯開。你其實很想和好，今天放學在校門口又遇到他，你決定怎麼做。","c":[{"t":"想和好卻拉不下臉，繼續僵著等他","q":1,"tag":"◐ 心裡想和好，卻被面子卡住——理解要有人先跨一步，那一步往往最珍貴。"},{"t":"到處跟同學說自己有多有道理","q":2,"tag":"忙著找人證明我才對，是只想被理解、不想理解對方——裂痕只會越拉越大。"},{"t":"主動開口，先問他那天到底在氣什麼","q":0,"tag":"✓ 放下誰先低頭就輸的較勁，先去懂對方的情緒，和好才有真正的起點。"},{"t":"寫一份雙贏協議，規定以後怎麼借書","q":3,"tag":"☯ 雙贏協議是之後的事；情緒還沒被理解之前，條款只是冷冰冰的紙。"},{"t":"散播他的糗事，狠狠地報復一波","q":4,"tag":"⚠ 用報復洩憤，等於親手燒掉這段友情——贏了一時的氣，輸掉一個朋友。"}]},{"h":4,"text":"班會討論園遊會要賣什麼，你提議賣飲料，另一位同學卻說飲料一定賠錢，主張賣雞蛋糕，語氣還有點衝。全班安靜下來，等著看你怎麼接話。","c":[{"t":"喊統合綜效，趕快舉手表決結束討論","q":3,"tag":"☯ 統合綜效的前提是先互相聽懂；跳過理解直接表決，只是快轉的假和諧。"},{"t":"馬上打斷他，一直重複自己的理由","q":2,"tag":"急著輸出立場、不給對方說完，是只求被懂——你可能正錯過更好的觀點。"},{"t":"先聽懂他為何這樣想，再說明看法","q":0,"tag":"✓ 先理解對方立場背後的理由，再說自己的——這樣的交流才有共識的可能。"},{"t":"表面上在聽，心裡早已想著怎麼反駁","q":1,"tag":"◐ 這是假裝在聽：耳朵開著、心在備稿，對方一秒就感覺得到那份心不在焉。"},{"t":"嘲笑他的想法很蠢，叫他直接閉嘴","q":4,"tag":"⚠ 用羞辱壓制不同意見，從此沒人敢對你說真話——你關上了所有理解的門。"}]},{"h":4,"text":"社團課結束，好友紅著眼眶拉住你，說他剛被學姊當眾罵，想退出熱舞社。你知道他為了成果發表已經練了半年，現在他站在你面前等你開口。","c":[{"t":"馬上安慰他別難過，退了也沒關係","q":1,"tag":"◐ 安慰是糖，但他需要的是有人懂他為什麼苦——先聽完，再決定給什麼。"},{"t":"提醒他以終為始，別忘了成發的目標","q":3,"tag":"☯ 以終為始沒有錯，但他此刻需要的是被聽懂，不是一句願景喊話。"},{"t":"立刻幫他分析退社的利弊和得失","q":2,"tag":"他還在說感受，你已經開處方——藥再對也吞不下，先聽完他的委屈。"},{"t":"說早叫你別進這社，現在後悔了吧","q":4,"tag":"⚠ 馬後炮讓你贏了預言家頭銜，卻輸掉他下一次願意找你說話的信任。"},{"t":"先聽完他的委屈，再決定要說什麼","q":0,"tag":"✓ 先診斷再開藥——被聽懂，比被說服更能救人，這就是同理心傾聽。"}]},{"h":4,"text":"午休時同學阿凱氣沖沖衝到你座位，質問你為什麼跟別人說他考試作弊，可是你根本沒說過。全班的目光都集中過來，你得決定第一句話說什麼。","c":[{"t":"回一句我只管影響圈，不理會謠言","q":3,"tag":"☯ 影響圈不是擋箭牌；眼前這個誤會，正是你能出手處理的事情。"},{"t":"先聽他從哪裡聽來的、在氣什麼","q":0,"tag":"✓ 先接住情緒再澄清事實——知彼，才有解己的機會，順序不能顛倒。"},{"t":"急著發誓自己絕對沒有說過那些話","q":1,"tag":"◐ 急著自證，火頭上的人根本聽不進——不是不能澄清，是順序錯了。"},{"t":"回嗆你憑什麼兇我，直接吵回去","q":2,"tag":"兩把火碰在一起，只會燒出更大的誤會——你回應了怒氣，沒回應問題。"},{"t":"冷處理不理他，反正清者自清","q":4,"tag":"⚠ 看似有風度，其實把誤會冷凍保鮮——它不會自己退冰，只會越凍越硬。"}]},{"h":4,"text":"你為了校隊選拔連續熬夜練球，被爸媽發現後明令禁止。你覺得他們根本不懂你的夢想，晚餐後媽媽又提起這件事，你決定怎麼回應她。","c":[{"t":"先說出他們擔心的是身體和成績","q":0,"tag":"✓ 能先說出對方的擔憂，溝通就成功了一半——這就是先知彼再解己。"},{"t":"直接保證成績不會掉，交換練球","q":1,"tag":"◐ 直接開條件跳過了理解——他們擔心的也許不只成績，先聽再談。"},{"t":"搬出要事第一，說練球就是我的要事","q":3,"tag":"☯ 要事第一是排自己的事，不是拿來壓過對方的擔憂；先聽懂再排序。"},{"t":"悶著不回應，心想反正你們不會懂","q":2,"tag":"沒有溝通的和平是假的，帳只是先掛著——預設對方不懂，門就先關了。"},{"t":"假裝早睡，等他們睡著後偷偷練","q":4,"tag":"⚠ 瞞天過海練的不是球，是說謊——被發現的那一天，信任全部歸零。"}]},{"h":4,"text":"球隊練習賽輸球，你發現隊友阿哲的防守有個明顯問題，很想給他建議，但他此刻臉超臭地坐在場邊喝水。你走過去之前，先想好要怎麼開口。","c":[{"t":"換更委婉的說法，馬上講給他聽","q":1,"tag":"◐ 修辭變了，順序沒變——還是「我要說」優先於「他準備好了嗎」。"},{"t":"先開雙贏條件：你改防守我請飲料","q":3,"tag":"☯ 雙贏思維用錯時機；他的心門還沒開，條件開得再好也送不進去。"},{"t":"心想好心被雷劈，乾脆以後都不講","q":2,"tag":"從他不想聽直接跳到我不說，中間漏掉了理解那一步——問問他怎麼了。"},{"t":"先問他現在想不想聽人講幾句話","q":0,"tag":"✓ 建議送達前先敲門——心門沒開，說什麼都是噪音；先問，再說。"},{"t":"在班群公開檢討他防守出的問題","q":4,"tag":"⚠ 把私下的話變成公審，建議再正確，也已經變成傷人的武器。"}]},{"h":4,"text":"同學上台報告被老師當眾罵到臉色發白，下台後他繃著臉坐回你旁邊，一句話也不說。你知道他為這份報告足足準備了兩個星期，你決定開口。","c":[{"t":"說「準備那麼久還被唸，超嘔的吧」","q":0,"tag":"✓ 不給意見、不給安慰，先把他的感覺說出來——被接住，情緒才會退潮。"},{"t":"安慰他「老師罵每個人都很兇啦」","q":1,"tag":"◐ 你想安慰，但這句翻譯過來是你的感覺不重要——他會把心門關小一半。"},{"t":"馬上分析他的報告哪裡可以改進","q":2,"tag":"他剛被老師打完分數，你又補一刀——他現在要的不是第二個評審。"},{"t":"勸他不斷更新，去操場跑兩圈散心","q":3,"tag":"☯ 不斷更新是平時的保養；此刻他需要的是感受先被接住，不是處方。"},{"t":"搶著講自己上次被罵更慘的故事","q":4,"tag":"⚠ 他才剛難過，麥克風就被你搶走——他的氣，只好自己吞回去。"}]},{"h":4,"text":"你熬夜完成的作文被老師叫去辦公室，她把作文放在桌上問：「你自己說，這是不是你寫的？」你確定每個字都是自己寫的，現在換你開口了。","c":[{"t":"大聲喊就是我寫的，憑什麼說我抄","q":2,"tag":"你是冤枉的，但這句話一出，戰場就從作文變成態度——你從原告變被告。"},{"t":"先問老師哪些段落看起來不像我寫的","q":0,"tag":"✓ 被指控的人先聽指控的內容——先聽懂疑點在哪，才知道要解釋哪裡。"},{"t":"委屈地說隨便，你要當我抄的就抄的","q":1,"tag":"◐ 委屈到放棄溝通可以理解，但擺爛式投降會讓誤會直接定案。"},{"t":"說我會主動積極，回去再寫十篇證明","q":3,"tag":"☯ 行動力可嘉，但眼前要解的是誤會——先理解她的疑點，再談證明。"},{"t":"叫老師自己去問全班，別再來煩我","q":4,"tag":"⚠ 把球踢給別人，自己沒接住這場對話——老師要的是你的回應。"}]},{"h":4,"text":"班上的轉學生小宇來了兩週，下課總是一個人趴著，沒人知道他在想什麼。你的座位就在他旁邊，這節下課，你想試著跟他建立一點連結。","c":[{"t":"當面問他幹嘛都不理人，很怪欸","q":2,"tag":"把大家的評論直接砸在他臉上——這不是關心，是轉述攻擊，殼會更厚。"},{"t":"邀他訂讀書計畫，用要事第一衝成績","q":3,"tag":"☯ 工具再好，也要先有信任才遞得出去——對陌生的心，先有連結。"},{"t":"直接問他是不是有心事，可以跟我說","q":1,"tag":"◐ 出於好意，但挖心事對不熟的人是壓力——門要讓他自己開。"},{"t":"從請教小事開場：這題你會寫嗎","q":0,"tag":"✓ 對緊閉的殼，請教比關心溫柔——它不要求對方敞開，只邀請他伸手。"},{"t":"跟同學打賭，看誰能讓他開口說話","q":4,"tag":"⚠ 把一個人的沉默當成遊戲籌碼——被他知道的那天，殼會永遠鎖上。"}]},{"h":4,"text":"相處幾週後，轉學生小宇某天忽然小聲說：「其實我之前的學校，發生了一些事。」然後就停住，眼神飄向別處，好像在試探你的反應。","c":[{"t":"連珠炮追問發生什麼事、誰欺負你","q":1,"tag":"◐ 關心是真的，但連珠炮讓水溫瞬間變燙——追問會關門，等待才開門。"},{"t":"說過去就讓它過去，新學校新開始","q":2,"tag":"一句正能量，把他剛遞出來的鑰匙拍掉了——他點點頭，再也不提。"},{"t":"點頭安靜陪著，讓他決定要不要說","q":0,"tag":"✓ 他需要的不是被問出來，是確定說了也安全——你給了他安全感。"},{"t":"鼓勵他主動積極，別被過去綁住了","q":3,"tag":"☯ 概念沒錯，但他正在遞出信任，此刻該做的是安靜接住，不是喊話。"},{"t":"轉頭跟別人說小宇以前學校有八卦","q":4,"tag":"⚠ 把他最脆弱的試探變成八卦——他要的是被一個人接住，不是被圍觀。"}]},{"h":4,"text":"分組討論時，阿芸剛提到「問卷」兩個字，就被大嗓門的阿豪打斷，他滔滔不絕講自己的計畫。你注意到阿芸低下頭不再說話，你決定出手。","c":[{"t":"直接嗆阿豪你很吵欸，都是你在講","q":2,"tag":"你保護了阿芸，但用的是打斷打斷者——暴力沒離開，只是換人使用。"},{"t":"算了讓阿豪講完，他講的也有道理","q":1,"tag":"◐ 討論順利結束了，但阿芸從此只負責點頭——你們失去了一個腦袋。"},{"t":"提議統合綜效，馬上表決用誰的方案","q":3,"tag":"☯ 沒讓每個聲音被聽完就表決，綜效只是快轉出來的假和諧。"},{"t":"攔一下：阿芸剛講到問卷，然後呢","q":0,"tag":"✓ 擋下打斷卻不羞辱人，再把麥克風還給她——附上被吞掉的關鍵字。"},{"t":"也跟著搶話，反正大聲的才會被聽到","q":4,"tag":"⚠ 你加入搶話的行列——三個人在搶，阿芸更不可能開口了。"}]},{"h":4,"text":"分組討論繼續，阿豪興奮地主張用街頭訪問收資料，因為最快，但你發現這個方案完全沒考慮下雨天。他正講得起勁，你想提出這個漏洞。","c":[{"t":"先複誦他的理由，再問下雨怎麼辦","q":0,"tag":"✓ 先讓他確定你聽懂了，防禦就卸下——你的質疑聽起來就是幫忙。"},{"t":"先不講，等報告出包他自然就會懂","q":1,"tag":"◐ 讓他自己學教訓聽起來很酷，但報告是全組的——他出包，你陪葬。"},{"t":"馬上打斷說不對不對，你這樣有漏洞","q":2,"tag":"你變成了阿豪——被打斷的他立刻反擊護航，兩人搶答，零人思考。"},{"t":"引用以終為始，要求重新檢討目標","q":3,"tag":"☯ 拉回目標聽起來高明，卻沒接住他的方案本身——答非所問。"},{"t":"當面不說，私下跟別人嫌方案很爛","q":4,"tag":"⚠ 背後說、當面不說，是最傷團隊的路——氣氛壞了，問題還在。"}]},{"h":4,"text":"深夜你還在滑手機，媽媽進房念了一長串：快段考了還不睡、黑眼圈都出來了、手機收起來。你聽出她話裡其實藏著別的訊息，你決定怎麼回。","c":[{"t":"回「妳在擔心我齁，寫完了馬上睡」","q":0,"tag":"✓ 直接回應底層訊息——擔心第一次被聽見，碎念引擎就熄火了。"},{"t":"嗯一聲繼續滑，等她念完自動離開","q":1,"tag":"◐ 已讀模式混過今晚，但擔心持續未接聽——未接來電會累積成連環扣。"},{"t":"回「知道了啦」，先應付過去再說","q":2,"tag":"你回應了念的表層，沒接住擔心的底層——明天她會加倍奉還。"},{"t":"背要事第一給她聽，證明自己有規劃","q":3,"tag":"☯ 她要的不是時間管理報告，是「我的擔心有被聽見」的一句回應。"},{"t":"吼回去妳每次都念，到底煩不煩啊","q":4,"tag":"⚠ 回擊念的形式，沒碰到底層的擔心——她只會把音量調得更高。"}]},{"h":4,"text":"晚餐時爸爸難得吐了工作上的苦水，講完之後氣氛回暖不少。你原本今晚要開口要週末營隊的五百元費用，現在你得判斷這件事什麼時候提最好。","c":[{"t":"今晚先不提，明早他狀態好再開口","q":0,"tag":"✓ 知彼也包含知道現在不是時候——隔天開口，他反而爽快答應。"},{"t":"就是現在提，趁氣氛好直接說要五百","q":1,"tag":"◐ 時機比平常好，但剛倒完苦水就被要錢，陪伴瞬間變得像鋪陳。"},{"t":"把要錢包進超長的活動介紹裡鋪陳","q":2,"tag":"大人對鋪陳超長的請求有雷達——有事直說，永遠比話術乾淨。"},{"t":"先提雙贏協議：做家事來交換費用","q":3,"tag":"☯ 雙贏可以談，但此刻該先接住他的疲憊，別急著端出交易條件。"},{"t":"心想他正心軟，趁機多要一點零用","q":4,"tag":"⚠ 把對方吐露的脆弱當下手時機，是把陪伴變算計——被看穿就全毀。"}]},{"h":4,"text":"讀小六的妹妹紅著眼眶回家，哭著說最要好的朋友今天故意把午餐座位坐滿，不讓她坐。她抽抽噎噎地看著你，等你這個當哥哥的說話。","c":[{"t":"氣得說明天就去她們班上討公道","q":2,"tag":"你的怒火是替她燒的，但火一大，她反而得回頭來滅你的火。"},{"t":"說「被最好的朋友這樣，超難過吧」","q":0,"tag":"✓ 情緒像浪，被接住的浪會自己退；被堵住的浪，才會變成海嘯。"},{"t":"教她主動積極，明天先去搭話破冰","q":3,"tag":"☯ 她沒做錯什麼；先接住眼淚，行動建議等她平靜之後再給。"},{"t":"說「這種朋友不要也罷，別理她們」","q":1,"tag":"◐ 邏輯也許對，但對小六生，好朋友是半個世界——別叫她不准難過。"},{"t":"說「妳一定也講錯什麼，先檢討自己」","q":4,"tag":"⚠ 她剛被排擠，你又把矛頭轉回她身上——她要的不是第二個審判。"}]},{"h":4,"text":"你想跟爸媽提買筆電，前幾次一開口就被轉移話題，完全談不下去。這次你決定認真準備，打算週末開談，現在你先想第一步該做什麼。","c":[{"t":"列出十二點需要筆電的理由並背熟","q":1,"tag":"◐ 你只準備了解己的部分——不知道對方在怕什麼，進攻再華麗都是亂槍。"},{"t":"直接開口，看他們說什麼再見招拆招","q":2,"tag":"見招拆招在沒準備的人身上叫被招拆——一句再說吧你就回房了。"},{"t":"先想他們每次轉移話題是在怕什麼","q":0,"tag":"✓ 他們不是反對筆電，是怕筆電的用途——先弄懂擔憂，戰術全變。"},{"t":"用以終為始寫願景：三年後的自己","q":3,"tag":"☯ 願景動人，但談不下去的原因是沒先聽懂他們的擔心——順序錯了。"},{"t":"先斬後奏，用壓歲錢偷偷買回家再說","q":4,"tag":"⚠ 你買到了筆電，賠上的是信任——被發現那天，連談的資格都沒了。"}]},{"h":4,"text":"深夜好友打電話來，說他被喜歡一年的人拒絕了，講一講就哭，有時罵，有時沉默很久。此刻電話那頭又安靜下來，你決定怎麼面對這段沉默。","c":[{"t":"急著講笑話，想辦法把沉默填滿","q":1,"tag":"◐ 沉默讓你慌了——但那是他的沉默，他正在整理，你一打岔就得重來。"},{"t":"陪著沉默，偶爾嗯一聲表示還在線","q":0,"tag":"✓ 陪伴的最高級形式，有時候是在場的安靜——他知道你在就夠了。"},{"t":"勸他不斷更新，明天去球場流個汗","q":3,"tag":"☯ 運動是好習慣，但此刻他需要的是有人陪著痛，不是保養菜單。"},{"t":"說別難過，那種人不值得，下個更好","q":2,"tag":"不要難過等於叫流血的人別流血——值不值得，輪不到此刻的你來判。"},{"t":"不耐煩地催他：講話啊，都不出聲","q":4,"tag":"⚠ 把他療傷的沉默當斷線來催——沉默不是冷場，是他需要的空間。"}]},{"h":4,"text":"失戀的好友講到後來，忽然說：「我是不是很沒用？大家都說國中生的感情不算什麼，可是我真的好痛。」電話這一頭，換你接話了。","c":[{"t":"提醒他要事第一，先把會考顧好比較實在","q":3,"tag":"☯ 會考當然重要，但感受沒被接住之前，任何提醒聽起來都像否定。"},{"t":"說「你認真喜歡過，痛就代表是真的」","q":0,"tag":"✓ 幫他的痛苦取得合法資格——被允許痛的人，才有辦法開始好起來。"},{"t":"連聲說你超好的，是對方不會看人啦","q":1,"tag":"◐ 護主心切，但一直罵對方會讓他更亂——他得在你和回憶之間選邊。"},{"t":"說以後回頭看，就會覺得沒什麼了啦","q":2,"tag":"也許是真的，但對正在痛的人，這句話等於說你的現在不重要。"},{"t":"笑他哭成這樣很丟臉，趕快振作一點","q":4,"tag":"⚠ 他最痛的時候你管哭的樣子——他會把眼淚和真心一起收起來。"}]},{"h":4,"text":"放學路上，好友踢著石頭說：「反正我怎麼讀都讀不贏人家，不想讀了。」你知道他這次段考，已經是第三次沒達到自己訂下的目標了。","c":[{"t":"打氣說你只是還沒找到方法，加油","q":1,"tag":"◐ 正能量沒有錯，只是太快——傷口還沒被看過，就先被貼上OK繃。"},{"t":"嚇他：不讀是要幹嘛，你爸媽會氣炸","q":2,"tag":"他本來想講心裡話，你用現實恐嚇把門撞上——他只好說開玩笑的啦。"},{"t":"糾正他要以終為始，目標要訂清楚","q":3,"tag":"☯ 目標管理是後話；他話底下那個「好累」，還沒有人聽見。"},{"t":"接住他：一直追不到，真的會累吧","q":0,"tag":"✓ 不反駁不想讀，先接住它底下的累——對話的門，就這樣開了。"},{"t":"附和說對啊讀書沒用，一起擺爛啊","q":4,"tag":"⚠ 你不是接住他，是拉著他一起往下掉——附和絕望不是同理。"}]},{"h":4,"text":"睡前你滑到同學的限時動態：黑畫面配一行字「如果我消失了，應該也沒人發現吧」。已經四十七個人看過，卻沒有任何人回應。你盯著螢幕。","c":[{"t":"按一個哭哭表情，表示自己看到了","q":1,"tag":"◐ 比沉默好，但深夜發這種話的人，需要的是一個人，不是一個表情。"},{"t":"想說只是深夜emo文，明天就好了","q":2,"tag":"也許只是emo，但這種句子賭不起也許——寧可多看一眼再確認。"},{"t":"回她要主動積極一點，心態決定一切","q":3,"tag":"☯ 這時丟心態雞湯，等於把一封求救訊號，當成了態度問題來糾正。"},{"t":"截圖傳到別的群組，問大家她怎麼了","q":4,"tag":"⚠ 把她最脆弱的求救變成群組八卦——她要的是被接住，不是被圍觀。"},{"t":"私訊她：我看到了，我在，要聊聊嗎","q":0,"tag":"✓ 那則限動是瓶中信——四十七人看過，你是唯一打開的人。"}]},{"h":4,"text":"同學跟你聊了很多心事，還提到不只一次「不想活」的念頭，最後叮嚀你：「不要跟任何人講，連老師都不行。」你答應不出口，因為你真的不放心。","c":[{"t":"告訴她：這個我接不住，得找輔導老師","q":0,"tag":"✓ 保密與保命衝突時，保命贏——真傾聽不是當樹洞到底，是懂得求援。"},{"t":"嚇到慢慢減少回覆，假裝自己在忙","q":1,"tag":"◐ 會怕很正常，但淡出會讓她確認果然沒有人——把不安帶去找大人。"},{"t":"答應她保密，畢竟都答應人家了嘛","q":2,"tag":"義氣是真的，但這個秘密重到不該由兩個國中生扛——愛她就別遵守。"},{"t":"傳七個習慣的筆記給她，要她自己想開","q":3,"tag":"☯ 工具再好也接不住生命議題；此刻唯一正解是牽她去找更有力的手。"},{"t":"說妳想太多了，不會有事的早點睡","q":4,"tag":"⚠ 她說了不想活，你用想太多帶過——這是把紅燈關掉假裝沒看見。"}]},{"h":4,"text":"輔導課上，老師請大家演練同理心傾聽，你抽到的情境是：同學來訴苦成績退步、爸媽失望。上台前老師問你：「你打算怎麼聽？」你想了想。","c":[{"t":"聽完先複誦和接住感受，再問要建議嗎","q":0,"tag":"✓ 最後那一問是王牌——有時人家只要被聽，不要被修理，問了才知道。"},{"t":"對方講什麼，都先回一句我懂我懂","q":1,"tag":"◐ 我懂說太快反而可疑——懂是要被驗證的，不是用宣告的。"},{"t":"邊聽邊準備建議，聽完馬上開藥方","q":2,"tag":"這是裝填式傾聽——邊聽邊上膛，你聽到的只是給建議的空檔。"},{"t":"先幫他用以終為始訂出下次的目標","q":3,"tag":"☯ 訂目標是他自己的功課；傾聽者的工作是先把耳朵完整借出去。"},{"t":"默默聽完全程零回應，當一塊石頭","q":4,"tag":"⚠ 全程零回應，對方會覺得你根本沒在聽——要讓他知道你接到了。"}]},{"h":4,"text":"傍晚球場上，好友邊投籃邊抱怨：「學校超煩，老師只會管人，我講什麼都被罵。」你知道他最近常被記警告，但以前的他不是這樣。你接話。","c":[{"t":"跟著罵對啊老師超煩，我也看不爽","q":2,"tag":"一起罵很爽，但你把他的訊號彈當成同樂會——真正的事說不出口了。"},{"t":"勸他回到影響圈，管好自己就好了","q":3,"tag":"☯ 影響圈說得沒錯，但他正在發訊號——先聽見那個「他變了」。"},{"t":"說「你以前不太這樣，發生什麼事了」","q":0,"tag":"✓ 不評論嗆老師對不對，先指出你變了這個觀察——門就開了一條縫。"},{"t":"提醒他上次那樣嗆老師是有點過分","q":1,"tag":"◐ 你說的是事實，但太快——他剛開門，你就塞了一張評分表進去。"},{"t":"說老師管你是為你好，別太愛計較","q":4,"tag":"⚠ 他才剛開口，你就站到老師那邊——他要的是被聽，不是被勸。"}]},{"h":4,"text":"球場上，好友投了幾球後忽然說：「我爸最近都不回家，我媽每天哭。」他抱著球看向籃框，不再說話。你知道真正的事情來了，你決定怎麼接。","c":[{"t":"連問要離婚了嗎、你之後會跟誰住","q":2,"tag":"連珠炮像記者會——他還在流血，你在採訪，他只會把球抱得更緊。"},{"t":"說家家有本難念的經，讓大人處理","q":1,"tag":"◐ 想幫他放下，但他根本還沒放上過——遞出來的重量沒人接。"},{"t":"好奇追問那你家會搬走嗎、要轉學嗎","q":4,"tag":"⚠ 你的好奇蓋過他的痛——他說媽媽每天哭，你關心的卻是轉學。"},{"t":"教他寫個人使命宣言，穩住自己內心","q":3,"tag":"☯ 使命宣言救不了此刻；他需要的是有人看見他正在硬撐。"},{"t":"走到他旁邊問：這件事你扛多久了","q":0,"tag":"✓ 這句話的意思是：我看見的不是你的家事，是你這個人。"}]},{"h":4,"text":"晚上班群突然炸鍋，負責統整報告的小婷連發好幾則語音，罵大家都不交資料、只有她一個人在做。你是組長，訊息一直跳，全組都在等你反應。","c":[{"t":"先私訊她：妳一個人撐很久了齁","q":0,"tag":"✓ 先接住她的委屈，火才會退——群組裡的事，先從一個人開始修。"},{"t":"馬上在群組重新分工，貼出新表格","q":1,"tag":"◐ 分工是對的，但先開藥後診斷——她的委屈沒落地，表格沒人理。"},{"t":"回「大家都有苦衷，妳別這麼兇嘛」","q":2,"tag":"各打五十大板看似公平，其實誰都沒被理解——火只會燒得更旺。"},{"t":"在群組宣導雙贏思維，叫大家互相體諒","q":3,"tag":"☯ 口號滅不了火；她的委屈被聽見之前，講什麼都只是噪音。"},{"t":"已讀不回關通知，等她自己氣消","q":4,"tag":"⚠ 你把她的求救當噪音靜音了——明天的組會，只會更難開。"}]},{"h":4,"text":"補習班下課，同學小賢說他快撐不住了，這週想翹課去打球，還要你幫他跟老師打掩護。你看得出他最近真的很疲憊，你決定先說什麼。","c":[{"t":"先問他撐不住的是哪一塊，聽他說完","q":0,"tag":"✓ 翹課是表層，撐不住才是底層——先診斷，才知道他真正需要什麼。"},{"t":"約他週末打一場球，但沒問他怎麼了","q":1,"tag":"◐ 陪伴有到位，理解沒跟上——他的累還在原地，只是暫時被蓋住。"},{"t":"訓他一頓：翹課是想毀掉自己嗎","q":2,"tag":"你回應了翹課這個行為，沒聽見行為底下的求救——他下次不會再說。"},{"t":"搬出要事第一，幫他重排讀書順序","q":3,"tag":"☯ 他不是不會排程，是快斷電了——先聽懂疲憊，再談優先順序。"},{"t":"直接答應掩護，還約他一起翹課去","q":4,"tag":"⚠ 這不是義氣，是拉著他一起躲——問題原封不動，還多了說謊。"}]},{"h":4,"text":"園遊會前一週，負責畫海報的阿妤突然說她不做了，東西一丟就趴在桌上。組員面面相覷，有人翻白眼說隨便她。身為同組的你，走了過去。","c":[{"t":"勸她：都到最後一週了，忍一下嘛","q":2,"tag":"你急著讓進度復工，卻沒問她為什麼炸——人沒修好，海報也不會好。"},{"t":"蹲下來輕聲問她：發生什麼事了嗎","q":0,"tag":"✓ 先理解那聲不做了底下的委屈——被聽懂的人，常常自己就站起來。"},{"t":"說沒關係我幫妳做完，妳休息就好","q":1,"tag":"◐ 你接走了海報，卻沒接住她——下一次她還是會在某個地方炸掉。"},{"t":"提議統合綜效，重新投票分配工作","q":3,"tag":"☯ 流程再公平，也代替不了先聽她說為什麼突然撐不住了。"},{"t":"跟著翻白眼說隨便她，不做就拉倒","q":4,"tag":"⚠ 你把一個快滅頂的組員直接推開——組散了，才是真的做不完。"}]},{"h":4,"text":"社團練習時，學長當眾罵哭了國一的學弟，罵完就走。學弟一個人蹲在角落抹眼淚，其他人都裝作沒看見。你是他認識的少數學長姊之一。","c":[{"t":"立刻教他下次怎麼做才不會被罵","q":2,"tag":"他還在流眼淚，你已經在上課——藥再對，現在也吞不下去。"},{"t":"馬上說學長就是那樣，你別放在心上","q":1,"tag":"◐ 想安慰，但別放心上等於說你的難過不必要——先讓他難過完。"},{"t":"要他用雙贏思維，去跟學長談條件","q":3,"tag":"☯ 雙贏是之後的事；先接住眼淚，才輪得到坐上談判桌。"},{"t":"拍下他哭的樣子，傳到社團群組裡","q":4,"tag":"⚠ 把別人的脆弱當笑料——這一下，傷的比學長的罵更深。"},{"t":"蹲到他旁邊陪著，等他想說再開口","q":0,"tag":"✓ 先給空間再給耳朵——他需要的是有人站在他這邊，不是教練。"}]},{"h":4,"text":"好友私下跟你說，隔壁班有人跟她告白，她不喜歡對方，卻不知道怎麼拒絕，已經失眠兩天。她說完看著你：「你說，我到底該怎麼辦？」","c":[{"t":"先問她最卡住、最擔心的是什麼","q":0,"tag":"✓ 她開口要答案，但先聽懂她的為難——弄清楚問題，答案才會準。"},{"t":"直接給答案：就傳訊息拒絕就好啦","q":1,"tag":"◐ 方向也許對，但沒先弄懂她卡在哪——她失眠的點可能不是方法。"},{"t":"興奮地追問對方是誰、長得帥不帥","q":2,"tag":"她在說失眠的困擾，你在收集八卦——她會後悔跟你開口。"},{"t":"教她主動積極，感情的事自己作主","q":3,"tag":"☯ 口號沒接到重點；她要的是先被聽懂那份為難，不是精神喊話。"},{"t":"轉頭把這件事當八卦，講給別人聽","q":4,"tag":"⚠ 她給你的是信任，你回她的是流量——這段友誼會當場報廢。"}]},{"h":4,"text":"掃地時間，同組的阿明連續一週躲在樓梯間滑手機，外掃區每次都是你們幫他掃完。組員推派你去講，你走向樓梯間，先想好第一句話。","c":[{"t":"先問他最近怎麼了，怎麼都沒來掃","q":0,"tag":"✓ 先了解缺席的原因，再談責任——也許他正卡在你不知道的事裡。"},{"t":"客氣但直接要求他明天開始來掃地","q":1,"tag":"◐ 溫和堅定是好的，但少了先問一句怎麼了——他聽到的只有指責。"},{"t":"撂狠話：再不掃就登記名字給老師","q":2,"tag":"威嚇也許有效三天——但你們之間，從同學變成了警察與犯人。"},{"t":"講以終為始：掃地是為了品格目標","q":3,"tag":"☯ 大道理砸過去只會被翻白眼；先弄懂他為何缺席，再談意義。"},{"t":"號召全組冷凍他，誰都不准跟他講話","q":4,"tag":"⚠ 排擠是最傷的武器——地掃乾淨了，人也徹底掃出去了。"}]},{"h":4,"text":"假日連線打手遊，同班的阿隆連輸五場後在語音裡爆氣狂罵隊友，還說要刪遊戲。你知道他最近段考也考砸了，情緒明顯不對勁。你按下開麥。","c":[{"t":"打完這場先下，私下問他最近還好嗎","q":0,"tag":"✓ 他炸的不是遊戲，是最近的挫敗——把人跟情緒帶離戰場再聽。"},{"t":"約他明天去打球，先不提今天的事","q":1,"tag":"◐ 轉移陣地是好意，但沒讓此刻的情緒先被聽見——火還悶在裡面。"},{"t":"開始分析他哪裡操作失誤，教他戰術","q":2,"tag":"你在修他的操作，他壞掉的是心情——修錯地方，越修越炸。"},{"t":"勸他要不斷更新，先去睡覺別打了","q":3,"tag":"☯ 建議本身沒錯但太快；先接住那句想刪遊戲底下的挫敗感。"},{"t":"錄下他罵人的音檔，傳到班群笑他","q":4,"tag":"⚠ 把人最失控的一刻公開處刑——他記住的會是你，不是輸贏。"}]},{"h":4,"text":"你滑到好友小蓁的限動：「有些人真的很假，虧我把她當朋友。」你越看越覺得是在說你，因為昨天你才婉拒陪她去逛街。你的手指停在螢幕上。","c":[{"t":"馬上截圖問共同朋友，是不是在說我","q":2,"tag":"你在找證據，不是找理解——問來問去，誤會反而先傳開了。"},{"t":"先按讚裝沒事，觀察她幾天再決定","q":1,"tag":"◐ 不衝動是好的，但只觀察不對話，心裡的疙瘩會自己長大。"},{"t":"私訊問她怎麼了，想聽她親口說清楚","q":0,"tag":"✓ 對限動猜心一百次，不如直接問一次——先理解，再決定受不受傷。"},{"t":"回到影響圈，取消追蹤來眼不見為淨","q":3,"tag":"☯ 這不是縮小影響圈，是切斷理解的線——先問清楚，再談界線。"},{"t":"也發一則影射她的限動，反擊回去","q":4,"tag":"⚠ 限動互射只會讓全班吃瓜——你們都被看熱鬧，沒人被理解。"}]},{"h":4,"text":"會考前一個月，好友小語說她每天躺到半夜兩點都睡不著，一直夢到考砸，成績卻越模擬越差。她苦笑著說：「我是不是完蛋了？」你接話。","c":[{"t":"說「撐到怕成這樣，很辛苦吧」再聽","q":0,"tag":"✓ 先接住恐懼，再談方法——被聽懂的焦慮，才有機會鬆開來。"},{"t":"馬上分享自己的讀書方法，要她照做","q":1,"tag":"◐ 你給的是好方法，但她現在缺的是被理解，不是另一份計畫表。"},{"t":"說「大家都嘛焦慮，妳這樣很正常啦」","q":2,"tag":"用大家都一樣安慰人，等於說妳的痛不特別——她只會笑笑閉嘴。"},{"t":"教她要事第一，把讀書時間表排滿","q":3,"tag":"☯ 排程解不了恐懼；她的害怕還沒有人願意先聽完一遍。"},{"t":"嚇她：再睡不著下去，妳真的會完蛋","q":4,"tag":"⚠ 對溺水的人喊你快沉了——她的焦慮只會再往上疊一層。"}]},{"h":4,"text":"你在營隊當小隊輔，第一晚就寢前，國小的小隊員躲在棉被裡啜泣，說想回家。旁邊的孩子開始騷動，你走到他床邊，決定第一句要說什麼。","c":[{"t":"馬上轉移話題，說明天有超好玩的活動","q":1,"tag":"◐ 轉移有時有效，但他的想念沒被接住——半夜常常會哭第二輪。"},{"t":"輕聲說「第一次離開家，會想家很正常」","q":0,"tag":"✓ 先讓他的情緒合法——被允許想家的孩子，反而哭一哭就睡著了。"},{"t":"說「你是男子漢，不可以哭哭喔」","q":2,"tag":"你堵住的不是眼淚，是他對你的信任——他學到的是哭要躲起來。"},{"t":"教他以終為始，想想結業時的成長","q":3,"tag":"☯ 對想家的孩子談願景太遙遠；先讓此刻的想念被接住。"},{"t":"嫌他吵到別人，命令他忍住不准哭","q":4,"tag":"⚠ 用權威壓住哭聲，孩子表面安靜了，心也對你關上了。"}]},{"h":4,"text":"爸媽晚上大吵一架之後，媽媽走進你房間，看到桌面有點亂就開始用很衝的口氣念你。你心裡明白，她的火其實不是為了桌面。你決定怎麼回應。","c":[{"t":"回她雙贏思維，吵架解決不了事情","q":3,"tag":"☯ 對情緒中的人講道理像火上澆油——先懂她的累，再談溝通。"},{"t":"先不頂嘴，想想她的火是從哪裡來的","q":0,"tag":"✓ 聽懂她罵的是桌面、痛的是別的——不接錯火，就不會被燒到。"},{"t":"委屈反駁：我又沒做錯什麼，幹嘛罵我","q":2,"tag":"你回應了字面，沒看見她背後的疲憊——兩個人的委屈撞在一起。"},{"t":"默默把桌面整理好，什麼話都不說","q":1,"tag":"◐ 不火上加油是對的，但她的難受沒人接——一句媽妳還好嗎更暖。"},{"t":"甩門吼回去，跑去同學家過夜避風頭","q":4,"tag":"⚠ 家裡已經有一場火，你又點了第二場——回家只會更難。"}]},{"h":4,"text":"當風紀股長的好友跟你抱怨，他只是照規定登記上課講話的人，就被同學罵抓耙子，還被排擠。他問你：「我到底做錯了什麼？」你想著怎麼接。","c":[{"t":"先聽他說完，重述他兩邊為難的苦","q":0,"tag":"✓ 他卡在職責與友誼之間——先把這份兩難說出來，他才覺得被懂。"},{"t":"出主意：以後就睜一隻眼閉一隻眼","q":1,"tag":"◐ 你急著給解法，但他問的其實不是方法，是我是不是壞人。"},{"t":"幫腔罵那些同學幼稚，不用理他們","q":2,"tag":"跟著罵很痛快，但他明天還要跟那些人同班——罵完問題還在。"},{"t":"教他統合綜效，開班會重訂新規則","q":3,"tag":"☯ 制度面可以談，但先讓他的委屈落地，人才有力氣改制度。"},{"t":"笑他活該，誰叫他那麼愛登記別人","q":4,"tag":"⚠ 他被全班推開，最後連你也踹了一腳——這句話他會記很久。"}]},{"h":4,"text":"老師公布分組名單，好友因為沒跟你同組而不高興，下課冷冷地丟一句：「反正你跟新朋友一組比較開心嘛。」語氣酸酸的，你決定怎麼接。","c":[{"t":"急著解釋分組根本不是我能決定的","q":1,"tag":"◐ 解釋是事實，但他酸的不是分組，是怕被取代——先接住那份不安。"},{"t":"接住他：沒同組讓你覺得被丟下了齁","q":0,"tag":"✓ 聽懂酸話底下的失落——情緒被說中的瞬間，酸就化掉一半了。"},{"t":"回酸他：你這樣講話真的很幼稚欸","q":2,"tag":"你回應了語氣，沒回應心情——兩句酸話交換，友誼各扣一分。"},{"t":"跟他說分組是關注圈，別浪費情緒","q":3,"tag":"☯ 圈圈分類正確卻答非所問；他要的是友情被確認，不是理論。"},{"t":"從此不理他，覺得他根本無理取鬧","q":4,"tag":"⚠ 他用酸話試探你在不在乎，你用冷漠回答不在乎——他收到了。"}]},{"h":4,"text":"晚餐後，弟弟因為數學考三十八分被爸爸罵了一頓，躲回房間反鎖，媽媽敲門他也不應。半小時後，你站在他房門口，想著要怎麼開口。","c":[{"t":"隔門說：被罵很受傷吧，我就在門口","q":0,"tag":"✓ 先接住難堪，不急著開門——被理解的人，會自己把鎖打開。"},{"t":"敲門說我來教你數學，下次考回來","q":1,"tag":"◐ 幫忙是真心的，但他此刻需要的是安慰，不是第二堂數學課。"},{"t":"喊他快出來吃水果，別想那麼多了","q":2,"tag":"用轉移話題略過他的難過——門也許開了，心還是關著的。"},{"t":"塞紙條要他以終為始，訂讀書目標","q":3,"tag":"☯ 目標是之後的事；他現在需要的是有人懂那份難堪。"},{"t":"隔門嗆他考這麼爛被罵剛好，活該","q":4,"tag":"⚠ 他已經在谷底，你又往下踩一腳——手足的信任就這樣碎的。"}]},{"h":5,"text":"班會討論校慶擺攤方案，你想賣雞蛋糕、康樂股長想辦遊戲攤，兩派各有人支持，討論陷入僵局，主席看向身為提案人的你，等你表態下一步。","c":[{"t":"堅持自己的版本，拉更多人來支持","q":2,"tag":"用聲量壓過差異看似有效率，卻把另一派腦袋裡更好的可能整個浪費掉了。"},{"t":"提議把兩案優點合成新的第三方案","q":0,"tag":"✓ 統合綜效：把兩派的好處揉成誰都沒想過的新案，這就是一加一大於二。"},{"t":"提醒大家要事第一，先讀書別辦活動","q":3,"tag":"☯ 要事第一是好概念，但此刻的要事正是把方案談出來，不是逃回書桌。"},{"t":"先投票表決，少數服從多數就散會","q":1,"tag":"◐ 投票能收尾卻只是取捨；被否決那一派的好點子，就這樣被丟進垃圾桶了。"},{"t":"放話不合作，誰的案過了誰自己辦","q":4,"tag":"⚠ 用退出威脅全班，是把班級活動綁在你的情緒上，損人也不利己。"}]},{"h":5,"text":"自然課分組報告，老師把你和做事風格完全相反的同學分在同一組：你愛先規劃、他愛邊做邊改，第一次討論你們就互看不順眼，報告兩週後要交。","c":[{"t":"跟老師哭訴要求換組，不然就擺爛","q":4,"tag":"⚠ 遇到差異就想逃或擺爛，等於宣告你只能跟自己的影子合作。"},{"t":"說服他照你的流程走，比較有效率","q":2,"tag":"要對方變成另一個你，就消滅了差異的價值——綜效要的是互補，不是統一。"},{"t":"回家寫個人使命宣言，釐清自我價值","q":3,"tag":"☯ 以終為始沒有錯，但此刻要處理的是兩人的差異，不是你的人生藍圖。"},{"t":"找出彼此長處，規劃和應變分工互補","q":0,"tag":"✓ 統合綜效：你的縝密加他的靈活正好互補，整體就會大於各自相加。"},{"t":"勉強合作，但各寫各的部分少交流","q":1,"tag":"◐ 這是「合而不作」：人湊在一起、想法沒交會，自然激不出綜效的火花。"}]},{"h":5,"text":"數學段考複習時，一道幾何題你想了半節課還是卡住，隔壁同學剛好是數學小老師，正好寫完自己的進度在休息，你猶豫著要不要開口。","c":[{"t":"自己硬撐到底，不想被當成學不會","q":2,"tag":"一味硬扛、拒絕交流，看似有骨氣，其實白白錯過了更快更好的解法。"},{"t":"偷瞄他的答案抄上去，假裝自己會","q":4,"tag":"⚠ 抄來的既不懂也不誠實，是最空的一種「完成」，段考當場現形。"},{"t":"請教他並交換想法，一起找出解法","q":0,"tag":"✓ 統合綜效：結合彼此所知，常能想出單靠一個人怎麼都到不了的解法。"},{"t":"請他報答案，聽完沒問為什麼就過","q":1,"tag":"◐ 拿到答案卻沒交流思路，一加一只等於一——少了碰撞，就少了綜效。"},{"t":"先去操場跑兩圈，不斷更新再回來","q":3,"tag":"☯ 不斷更新能養精神，但眼前缺的是想法的碰撞，不是體力的充電。"}]},{"h":5,"text":"社會科專題，你想做街訪影片，組員想做問卷統計，兩套構想都很完整，誰也說服不了誰，期限只剩兩週，今晚視訊會議就得定案開工。","c":[{"t":"融合兩案：問卷找趨勢、街訪補故事","q":0,"tag":"✓ 統合綜效：數據加故事的第三案，比任何一邊的原案都更完整動人。"},{"t":"各自主動積極，兩案都做交給老師選","q":3,"tag":"☯ 主動積極很好，但雙倍工作不是綜效，是把整合的功課丟給老師。"},{"t":"堅持用自己的版本，要求組員配合","q":2,"tag":"用自己的方案壓過對方，看似果斷，卻把對方腦中的好點子整個浪費了。"},{"t":"嗆他的案子很爛，逼他自己退出","q":4,"tag":"⚠ 貶低對方換來的不是勝利，是一個心死的隊友和更爛的成果。"},{"t":"投票決定用誰的，另一案直接放掉","q":1,"tag":"◐ 投票是取捨不是綜效；被放掉的那案，也許正藏著最關鍵的一塊拼圖。"}]},{"h":5,"text":"英文課分組，你和一位成績常墊底的同學一組，其他人偷偷投來同情眼神，你心裡也嘀咕「這下全要自己扛了」，第一次討論即將開始。","c":[{"t":"先問他擅長什麼，找他能發揮的分工","q":0,"tag":"✓ 統合綜效：每個人都有長處，看見並善用差異，整體就大於各自相加。"},{"t":"自己包辦重點部分，簡單的丟給他","q":1,"tag":"◐ 你扛大局他打雜，看似安全，卻沒讓兩人的力量真正咬合出火花。"},{"t":"先傾聽他的家庭故事，做到知彼解己","q":3,"tag":"☯ 知彼解己是好耳朵，但現在要聽的是他能貢獻什麼，不是他的身世。"},{"t":"跟老師抱怨要求換人，別拖累成績","q":4,"tag":"⚠ 公開嫌棄隊友，傷了人也堵死了發現他長處的所有機會。"},{"t":"全程盯著他做，每一步都照你的來","q":2,"tag":"把人當工具遙控，他的想法進不來，你得到的只是另一雙手，不是夥伴。"}]},{"h":5,"text":"園遊會你們班和隔壁班合辦攤位，但你對他們班印象不好，總覺得會被拖累，第一次跨班籌備會議明天登場，班長指定你當代表出席。","c":[{"t":"開場先立規矩，要求全照我們班的","q":2,"tag":"凡事要別人聽你的，是壟斷不是協作——對方的長處全被你壓了下去。"},{"t":"會議上放話：出了包全是你們班的錯","q":4,"tag":"⚠ 先劃清界線再合作，等於先點火再蓋房子，攤位還沒開就先散了。"},{"t":"以終為始，先幫兩班寫好共同願景稿","q":3,"tag":"☯ 願景要有，但單方面寫好塞給對方，正好違背了一起長出來的綜效。"},{"t":"表面客氣合作，重要的事實際自己來","q":1,"tag":"◐ 客氣是好的開始，但心防沒開，兩班的力量始終沒有真正接上。"},{"t":"先了解對方班的專長，再協調分工","q":0,"tag":"✓ 統合綜效：先認識彼此能做什麼，再讓不同的人各司其職，合力做大。"}]},{"h":5,"text":"你是康樂股長，班級才藝表演要出節目，你習慣自己想好再宣布，去年就被同學抱怨過「都你決定」，今年的籌備會議十分鐘後開始。","c":[{"t":"先徵詢意見，但其實只想大家點頭","q":1,"tag":"◐ 開會卻只要大家蓋章背書是假討論——人到了、聲音沒進來，綜效從何而來。"},{"t":"宣布要事第一，直接分配工作省時間","q":3,"tag":"☯ 效率是美德，但跳過想法碰撞的分工，只是把去年的抱怨再演一次。"},{"t":"開放腦力激盪，讓不同點子互相碰撞","q":0,"tag":"✓ 統合綜效：讓想法彼此撞擊，往往蹦出一個人怎麼想都想不到的好點子。"},{"t":"嗆大家沒建設性，點子爛就別出聲","q":4,"tag":"⚠ 羞辱發言的人，以後再也沒有人肯開口，你將永遠只剩自己一顆腦袋。"},{"t":"只採納跟自己想法接近的幾個意見","q":2,"tag":"只聽得進和自己一樣的聲音，等於把差異全濾掉，激不出任何新東西。"}]},{"h":5,"text":"合唱比賽練習時，一位愛饒舌的同學提議在副歌後加一段饒舌，全班安靜了三秒，有人皺眉有人偷笑，擔任指揮的你必須當場做出回應。","c":[{"t":"試編一小段看效果，好就留不好就收","q":0,"tag":"✓ 統合綜效敢試：合唱加饒舌可能難聽，也可能是全場唯一的記憶點。"},{"t":"當眾笑他很中二，讓全班跟著笑一團","q":4,"tag":"⚠ 嘲笑提案的人，殺掉的不只這個點子，是以後所有人開口的勇氣。"},{"t":"合唱就該像合唱，請他別標新立異","q":2,"tag":"把「不一樣」當成冒犯，這個團隊就永遠只會有一種安全的聲音。"},{"t":"請他主動積極，自己回家練好再說","q":3,"tag":"☯ 主動積極沒錯，但把他的點子推出團隊，就斷了合出新編曲的可能。"},{"t":"傳統唱法穩穩比完，先求不要出錯","q":1,"tag":"◐ 穩是優點，但「不出錯」的天花板就是平庸，離驚豔永遠差一步。"}]},{"h":5,"text":"小組裡有個同學，你說東他偏說西，每次開會都跟你唱反調，這次專題又被分在同組，朋友勸你先想好怎麼「處理」他，討論明天開始。","c":[{"t":"努力說服他，讓全組想法保持一致","q":2,"tag":"把不同磨成相同，團隊就只剩一顆腦袋——想的都一樣，有一個就是多餘。"},{"t":"尊重他的意見，但重要決定避開他","q":1,"tag":"◐ 容忍差異只走到一半；願意慶祝差異、借他的眼睛，才有綜效。"},{"t":"開會前先串通其他人，用人數壓他","q":4,"tag":"⚠ 用人數輾壓異見，贏了會議，輸了那雙幫你看見盲點的眼睛。"},{"t":"把他當寶：他常看見我沒想到的盲點","q":0,"tag":"✓ 珍視差異是綜效的起點：唱反調的人，往往是你免費的品質檢驗員。"},{"t":"跟他簽雙贏協議：開會互不吐槽對方","q":3,"tag":"☯ 雙贏思維是地基，但約好互不碰撞等於關掉交鋒，綜效的火花也熄了。"}]},{"h":5,"text":"兩班聯合擺攤賣飲料，對方班的備料流程和你們完全不同，彩排時兩套做法撞在一起，現場一片混亂，攤位明天上午十點就要正式開張。","c":[{"t":"嘴上答應統一，明天照舊各做各的","q":4,"tag":"⚠ 假配合是合作的毒藥——明天現場再亂一次，信任也一起賠光。"},{"t":"互相觀摩優點，合出一套新的流程","q":0,"tag":"✓ 統合綜效：差異是原料不是障礙，混血的流程常常是最強的那套。"},{"t":"要求對方配合我們，我們比較熟練","q":2,"tag":"把合作做成併吞，對方流程裡的優點，你一項也拿不到。"},{"t":"先擱置流程，帶大家寫攤位使命宣言","q":3,"tag":"☯ 使命給方向感，但明早就開張，此刻該整合的是流程，不是口號。"},{"t":"各用各的流程，收攤前再對帳整合","q":1,"tag":"◐ 尊重了差異，卻沒讓差異交手——事後整合常常變成硬拼裝。"}]},{"h":5,"text":"分組報告開工會議上，阿樂力推做開場影片，你認為簡報就夠了，兩邊各拉到兩票，吵了半節課進度全卡住，老師已經走過來看了一眼。","c":[{"t":"先問阿樂：你最想要影片帶來什麼","q":0,"tag":"✓ 先挖出他真正要的——也許是開場的驚豔，那簡報動畫也能做到。"},{"t":"用經驗壓他：影片太花時間聽我的","q":2,"tag":"你用經驗碾壓了熱情，報告四平八穩交出去，評語卻是中規中矩。"},{"t":"冷嘲他就是愛出風頭，讓他自討沒趣","q":4,"tag":"⚠ 人身攻擊讓討論變戰場，他從此閉嘴，全組損失一顆願意想的腦袋。"},{"t":"宣布你們吵，我先主動把簡報做完","q":3,"tag":"☯ 操之在己是美德，但單飛不是負責，是把全組的腦力晾在一邊。"},{"t":"投票表決三比二，輸的一方配合做","q":1,"tag":"◐ 投票切的是輸贏不是問題，最有創意的人剛好被切到輸的那邊。"}]},{"h":5,"text":"教室佈置比賽，質感派想要黑白極簡風，回憶派想貼滿全班照片牆，兩派在班群吵了一整晚，明天放學就要開工，你是佈置總負責人。","c":[{"t":"人多的派贏：照片牆派人多就聽他們","q":2,"tag":"人數不等於正義；輸的那派整個佈置週「剛好都很忙」，人力先賠一半。"},{"t":"以極簡為主，照片印小張貼角落點綴","q":1,"tag":"◐ 能交差，但回憶派心知自己只是點綴，那個更好的方案擦肩而過了。"},{"t":"兩派各佈置半間教室，看誰被笑再撤","q":4,"tag":"⚠ 把合作改成淘汰賽，輸的那派白忙一場，還結下整學期的樑子。"},{"t":"極簡框架當底，放全班黑白照片進格","q":0,"tag":"✓ 兩派同時喊出「可以欸」——比原案更高級也更動人，這就是綜效的長相。"},{"t":"先知彼解己，輪流訪談每人童年回憶","q":3,"tag":"☯ 傾聽方向對了，但要聽的是兩派對佈置的需求，不是童年故事。"}]},{"h":5,"text":"專題分組你被排到全班公認愛擺爛的同學，第一次討論他果然遲到十分鐘，還邊滑手機邊聽，你的白眼快翻到後腦勺，但報告還是得一起做。","c":[{"t":"送他一本七個習慣，勸他先培養主動","q":3,"tag":"☯ 推薦好書是好意，但綜效要先找到他的著力點，不是先改造他這個人。"},{"t":"全程臭臉冷戰，讓他知道你有多不爽","q":4,"tag":"⚠ 你用臭臉開場、他用敷衍回敬，兩週都在比誰更不爽，什麼都沒產出。"},{"t":"先問他：這主題哪部分你其實有興趣","q":0,"tag":"✓ 也許他很會訪談，剛好長在你最怕的短板上——差異就是這樣變成禮物。"},{"t":"先訂界線：再擺爛就找老師談拆組","q":1,"tag":"◐ 界線可以有，但開場就亮刀，他整個專題都在防你——刀先別出鞘。"},{"t":"算了全部自己做，讓他掛個名就好","q":2,"tag":"你接下來兩週爆肝他全程納涼，而且永遠不會發現他身上有什麼你沒有的。"}]},{"h":5,"text":"週末爸爸想全家去爬山，媽媽想去逛街買鞋，你只想在家耍廢，餐桌上爸爸開始講「全家就是要一起活動」，媽媽臉一沉，火藥味越來越濃。","c":[{"t":"提議這週各自行動，互不勉強最省事","q":1,"tag":"◐ 偶爾分開是可以的，但每次都這樣，全家會變成住同間房子的室友。"},{"t":"搬出要事第一，說學生就該在家讀書","q":3,"tag":"☯ 要事第一被你拿來當擋箭牌了——家人的關係本身就是重要的事。"},{"t":"說「我都可以」，其實心裡只想留在家","q":2,"tag":"「都可以」的代價是沒有人真的開心——你全程臭臉，爸媽也掃興。"},{"t":"直接擺臉色摔門回房，讓他們自己吵","q":4,"tag":"⚠ 摔門把對話徹底關掉，三個願望連攤開的機會都沒有了。"},{"t":"請大家先各說出行程裡最想要的部分","q":0,"tag":"✓ 需求出土：爸要流汗同行、媽要買鞋吃好料、你要耍廢時段——第三案有救了。"}]},{"h":5,"text":"資訊社做班級網站，美術擔當小米嫌地圖頁太醜想全部重畫，工程擔當阿光說重畫就要重切座標、工作量翻倍，兩個專業當場對撞僵住。","c":[{"t":"叫兩人各做一版，輸的那版就當白做","q":4,"tag":"⚠ 把對齊變成淘汰賽，輸的人白做還傷感情——專業要合鑄，不是比刀。"},{"t":"說能動就好別再改，先交出去再說","q":2,"tag":"「能動就好」澆熄了兩個專業者的火花，網頁也就真的只是能動而已。"},{"t":"問小米最想改哪裡、阿光哪種改法省工","q":0,"tag":"✓ 換配色加重畫圖示不動底圖：視覺升級八成、工程量一成——搭橋就有火花。"},{"t":"要兩人先各自不斷更新，練好再合作","q":3,"tag":"☯ 磨利鋸子是好習慣，但眼前的僵局要靠搭橋整合，不是各自進修。"},{"t":"裁決這次美觀優先，請阿光全力配合","q":1,"tag":"◐ 單邊裁決：地圖變美了，阿光切座標到半夜，從此再也不提新點子。"}]},{"h":5,"text":"班遊地點討論了三次班會，兩派需求都攤開了、整合流程也都跑過了，第三選擇還是生不出來，報名截止只剩兩天，全班都看著主持的你。","c":[{"t":"宣布開會開到生出共識為止，不散會","q":2,"tag":"深夜的會議室裡不會有綜效，只有想回家的人質；硬擠的共識明天就翻。"},{"t":"承認這次沒有綜效，退回好好的妥協","q":0,"tag":"✓ 大師知道綜效不是百發百中；誠實退回雙贏備案，比硬掰假綜效高級。"},{"t":"搬出以終為始，改帶全班寫畢業願景","q":3,"tag":"☯ 願景很美，但報名只剩兩天，此刻需要的是收尾的決定，不是遠方。"},{"t":"怪大家不配合，放話這次班遊你不去","q":4,"tag":"⚠ 用缺席懲罰全班，把三次會議累積的善意一次燒光。"},{"t":"回投票前最後再問一次兩邊要什麼","q":1,"tag":"◐ 可以投票，但宣布前的最後一問值得做——很多死局在這裡才解開。"}]},{"h":5,"text":"會考倒數，你數學強英文弱，好友剛好相反，你們想組讀書小組互相支援，另一個同學卻笑「兩個半吊子湊一起能幹嘛」，你聽了有點動搖。","c":[{"t":"照樣組隊，互相當對方弱科的小老師","q":0,"tag":"✓ 統合綜效：你的數學加他的英文，互補出兩個人單獨都到不了的高度。"},{"t":"被笑到放棄，還是自己讀比較實在","q":2,"tag":"因為一句酸話放棄互補，等於把身邊現成的免費家教推出門外。"},{"t":"先寫讀書使命宣言，儀式感滿滿再開始","q":3,"tag":"☯ 以終為始能定方向，但小組的力量在互補教學，不在寫文件。"},{"t":"回嗆那位同學，叫他滾遠一點別酸","q":4,"tag":"⚠ 把力氣花在回嗆，小組還沒開始就先樹敵，一題都還沒複習到。"},{"t":"組是組了，但各讀各的只是一起自習","q":1,"tag":"◐ 人在一起、腦沒交流，這是併桌不是綜效——互教那一步才是關鍵。"}]},{"h":5,"text":"班群裡為了園遊會要賣雞蛋糕還是手作飲料吵翻，兩派互貼梗圖嘲諷，訊息瞬間九十九加，明天班會就要定案，你是會議主持人。","c":[{"t":"在群裡力挺自己想賣的，先搶下聲量","q":2,"tag":"主持人先選邊，另一派立刻閉嘴——你聽不到的那半，正是綜效的原料。"},{"t":"明天直接舉手表決，快刀斬亂麻收場","q":1,"tag":"◐ 表決能止血，但沒先攤需求就切輸贏，好點子跟著輸的那派陪葬。"},{"t":"請兩派先各講訴求，找出能整合的新案","q":0,"tag":"✓ 也許能賣「雞蛋糕配特調飲料套餐」——先聽訴求，第三案就有空間。"},{"t":"把帶頭吵的兩人踢出群組，眼不見為淨","q":4,"tag":"⚠ 踢人只是把衝突掃到地毯下，明天班會火只會燒得更大。"},{"t":"勸大家主動積極，先各自回家做功課","q":3,"tag":"☯ 做功課是好事，但少了把想法撞在一起的設計，明天仍是各說各話。"}]},{"h":5,"text":"班際籃球賽開打前，控球的你主張快攻，中鋒學長堅持打陣地戰，練球時兩人互不相讓，隊友夾在中間不敢說話，比賽就在後天下午。","c":[{"t":"嗆學長觀念過時，叫他跟上時代","q":4,"tag":"⚠ 嗆完學長，後天球場上你會發現沒有人幫你擋人——輸球又輸人。"},{"t":"賽前先知彼解己，輪流分享打球初衷","q":3,"tag":"☯ 傾聽初衷很暖，但後天就開打，要整合的是戰術，不是心路歷程。"},{"t":"各退一步，上下半場輪流用兩種打法","q":1,"tag":"◐ 輪流是妥協的中間值，兩種打法沒有真正咬合，威力各打了折。"},{"t":"研究依對手切換兩種戰術的混合打法","q":0,"tag":"✓ 快攻搶節奏、陣地穩局面，看對手切換——比任何單一戰術都難防。"},{"t":"球在我手上，比賽時照自己的意思打","q":2,"tag":"控球權不等於決定權；你贏了主導，卻輸掉中鋒的身高和整隊的心。"}]},{"h":5,"text":"你們的掃區檢查老是最後過關，有人想先掃再拖地、有人想先倒垃圾，每天為了順序吵，衛生股長把重新安排流程的任務交給了你。","c":[{"t":"帶大家把流程攤開，重新設計新動線","q":0,"tag":"✓ 統合綜效：把每個人卡住的點攤開重組，常能長出誰都沒想過的順序。"},{"t":"照你自己的習慣排，大家照做就對了","q":2,"tag":"你的習慣不一定是全組的最佳解；沒經過碰撞的安排，抱怨只會換人講。"},{"t":"擺爛不管，反正被扣分是全組一起扣","q":4,"tag":"⚠ 把任務晾著，全組陪你一起墊底——這不是瀟灑，是拖人下水。"},{"t":"先開反思會，請每人檢討主動積極度","q":3,"tag":"☯ 反省態度沒錯，但問題出在流程設計，不是誰不夠主動——開錯藥了。"},{"t":"折衷單雙日輪流，用誰的順序各一半","q":1,"tag":"◐ 輪流照顧了面子，卻沒回答哪種順序真的快——問題只是被排班掉。"}]},{"h":5,"text":"你和朋友組手遊戰隊報名校內電競賽，選角時他堅持雙輸出陣容，你認為必須有坦克保護，語音裡吵到快翻臉，報名表今晚十二點截止。","c":[{"t":"提議先去睡覺不斷更新，明天再討論","q":3,"tag":"☯ 休息能降火氣，但報名今晚截止，該做的是把差異談成陣容。"},{"t":"堅持己見，畢竟你的排位比他高很多","q":2,"tag":"段位是資歷不是真理；用位階壓人，他的戰術眼光就進不了隊伍。"},{"t":"拆解彼此戰術邏輯，測試混編新陣容","q":0,"tag":"✓ 半坦半輸出的混編也許正好剋場上主流——差異碰撞就是新戰術的礦。"},{"t":"不改陣容就退隊，讓他自己去找人","q":4,"tag":"⚠ 用退隊當籌碼，就算他讓步，這支隊伍的信任也已經先陣亡。"},{"t":"一人讓一步，第一場用他的下場換你的","q":1,"tag":"◐ 輪流是公平的妥協，但兩套陣容都沒磨合，等於每場都用半成品。"}]},{"h":5,"text":"班級成果發表要做宣傳貼文，小組裡有人會拍片、有人會剪輯、你擅長寫文案，但三個人都想主導整體風格，第一次開會半小時就卡住。","c":[{"t":"爭取當總監，風格統一起來比較好看","q":2,"tag":"搶著當唯一的腦，另外兩顆腦就休眠了——統一換來的是平庸的整齊。"},{"t":"輪流主導：三支貼文一人各負責一支","q":1,"tag":"◐ 輪流保住了和氣，但三支各唱各的調，系列感和綜效都沒長出來。"},{"t":"建議先各自經營小帳，練好個人品牌","q":3,"tag":"☯ 經營自己沒有錯，但任務是合力宣傳成發，不是各自圈粉。"},{"t":"誰不服就退出，反正你一個人也能做","q":4,"tag":"⚠ 趕走夥伴等於親手砍掉拍片和剪輯，文案再好也只是純文字。"},{"t":"先盤點各自強項，讓三種專業互補","q":0,"tag":"✓ 拍攝、剪輯、文案各司其職再互相回饋，成品是三個人都做不出的等級。"}]},{"h":5,"text":"畢旅自由活動時間，你的兩個好友一個想衝遊樂設施、一個想逛紀念品街，兩人吵著要你選邊站，三人站在園區地圖前僵住，氣氛降到冰點。","c":[{"t":"問出兩人最在意的點，排出新路線","q":0,"tag":"✓ 也許是「刺激」對「挑禮物」——上午衝設施、下午逛街，第三案成形。"},{"t":"偷偷選跟自己比較要好的那個朋友","q":2,"tag":"選邊站是最直覺的解，但你解決的是站位，不是兩個人的需求。"},{"t":"引用習慣一說：你們的心情操之在己","q":3,"tag":"☯ 情緒自主是真理，但當下需要的是幫兩人搭橋，不是講一堂課。"},{"t":"嫌他們幼稚，丟下兩人自己去玩","q":4,"tag":"⚠ 一走了之最輕鬆，但畢旅回來，你可能同時失去兩個朋友。"},{"t":"提議乾脆分開行動，約好集合時間見","q":1,"tag":"◐ 分開可行卻可惜——畢旅只有一次，差一步就能找出都盡興的走法。"}]},{"h":5,"text":"家裡只有一台電腦，你今晚要查分組報告的資料，弟弟吵著要打他約好的排位賽，兩人在房門口互不相讓，媽媽丟下一句「你們自己想辦法」。","c":[{"t":"跟他說要事第一，訓他少打一點電動","q":3,"tag":"☯ 要事第一是管理自己的尺，不是拿來量別人、壓弟弟的棍子。"},{"t":"攤開各自需求，一起排出使用時段表","q":0,"tag":"✓ 他的排位九點開打、你查資料一小時就好——攤開需求，時段自己長出來。"},{"t":"搬出哥哥身分，功課當然比遊戲重要","q":2,"tag":"用位階裁決看似合理，但弟弟的需求沒被聽見，明晚同一場仗再打一次。"},{"t":"猜拳決定誰先用，輸的人等一小時","q":1,"tag":"◐ 猜拳公平卻靠運氣；先問清楚各自要用多久，常常根本不必分輸贏。"},{"t":"趁他上廁所搶先登入，把密碼改掉","q":4,"tag":"⚠ 偷跑加鎖人，贏了今晚，輸掉的是兄弟間僅存的信任。"}]},{"h":5,"text":"暑假營隊的小隊之夜，隊上一半人想演搞笑短劇、一半人想跳舞，排練時間只剩一個下午，隊輔把決定權交給身為小隊長的你，全隊等你開口。","c":[{"t":"選練起來比較快的，時間緊別想太多","q":2,"tag":"求快是直覺，但被放棄那一半人的心也涼了，排練從此只出一半力。"},{"t":"合成歌舞劇：用舞蹈開場、短劇收尾","q":0,"tag":"✓ 統合綜效：兩派的熱情都上台，還混出全營唯一的歌舞劇記憶點。"},{"t":"讓兩派各排各的，上台前再比誰能上","q":4,"tag":"⚠ 內部淘汰賽讓一半人白練一下午，小隊之夜還沒開始就先分裂。"},{"t":"兩案抽籤決定，抽到什麼就練什麼","q":1,"tag":"◐ 抽籤快又公平，但輸的那派只是服氣了規則，沒有服氣這個節目。"},{"t":"先帶小隊圍圈知彼解己，聊參加初衷","q":3,"tag":"☯ 交心是好事，但只剩一個下午，該整合的是節目，不是心情。"}]},{"h":5,"text":"會考衝刺班裡，你習慣做筆記整理架構、同桌靠大量刷題練手感，他笑你抄心安的、你嫌他不求甚解，嗆完之後兩人已經一週沒講話。","c":[{"t":"主動破冰交換方法，筆記換他的題感","q":0,"tag":"✓ 你的架構加他的手感正好互補——珍視差異，兩人都多了一種武器。"},{"t":"寫一份使命宣言送他，勸他以終為始","q":3,"tag":"☯ 送宣言像在說教；綜效是先承認他的刷題裡，也有你缺的東西。"},{"t":"懶得理他，反正成績會證明誰是對的","q":2,"tag":"把同桌當對手是最自然的反應，但你們本可以是彼此的免費教練。"},{"t":"先道歉和好，但讀書方法還是各走各","q":1,"tag":"◐ 和好修復了關係，卻停在互相尊重——差一步交換，綜效沒發生。"},{"t":"在同學面前酸他假認真，扳回一城","q":4,"tag":"⚠ 公開羞辱讓裂痕變成斷崖，會考前少了戰友，多了敵人。"}]},{"h":5,"text":"熱音社成發想在中庭辦快閃演出，學務主任以安全為由打算取消，社長氣得想直接跟主任開嗆，身為副社長的你被推派去和主任溝通。","c":[{"t":"覺得大人都這樣，摸摸鼻子宣布取消","q":2,"tag":"把主任當成不可能溝通的牆，其實你連他真正擔心什麼都還沒問過。"},{"t":"引影響圈之說，勸社長別管改不了的","q":3,"tag":"☯ 影響圈用反了——去溝通、找第三案，正是你能影響的範圍。"},{"t":"號召社員連署施壓，把主任洗版到底","q":4,"tag":"⚠ 施壓把對話變對抗，就算辦成了，社團也上了學務處的黑名單。"},{"t":"先問主任具體擔心什麼，再設計新方案","q":0,"tag":"✓ 也許他怕的是人群推擠——控管入場加動線設計，快閃就有機會復活。"},{"t":"提議縮小規模改到禮堂，先求能辦","q":1,"tag":"◐ 退一步能保住演出，但還沒問過主任的顧慮，也許根本不必退。"}]},{"h":5,"text":"轉學生提出值日生輪班方式可以改良，有同學不屑地說「我們一直都這樣做」，班長私下問你這個風紀股長的意見，你其實覺得他講得有道理。","c":[{"t":"公開支持試行一週，新舊做法取長補短","q":0,"tag":"✓ 新視角是綜效的養分——試行讓差異被驗證，而不是被輩分否決。"},{"t":"維持原做法，畢竟大家都已經習慣了","q":2,"tag":"「一直都這樣」是舒適圈的口頭禪，也是新點子最常死掉的地方。"},{"t":"私下跟班長說不錯，但別公開挺他","q":1,"tag":"◐ 你看見了價值卻不敢站出來，好點子少了支持，多半胎死腹中。"},{"t":"勸轉學生先融入，主動積極多做雜事","q":3,"tag":"☯ 主動積極不是叫人閉嘴多做事；他的差異正是班上缺的視角。"},{"t":"跟著起鬨，讓他知道新來的別想出頭","q":4,"tag":"⚠ 打壓新聲音，班上從此只會複製舊答案，還多了一個孤立的同學。"}]},{"h":5,"text":"科展組隊，你熱愛動手做實驗，隊友卻只想窩在圖書館查文獻，你嫌他紙上談兵、他嫌你瞎忙，指導老師要你們自己先解決分歧再來找他。","c":[{"t":"科展就是要動手，拉著他一起進實驗室","q":2,"tag":"把他拖進你的主場，他的文獻功力就荒廢了——你少了最強的理論後盾。"},{"t":"跟老師告狀他都不動手，要求換隊友","q":4,"tag":"⚠ 告狀換不到好隊友，只換到一個記恨的同學和重新磨合的成本。"},{"t":"文獻定方向、實驗來驗證，兩線並進","q":0,"tag":"✓ 統合綜效：他找的文獻讓你少走彎路，你的數據讓他的理論站起來。"},{"t":"各自先產出成果，繳交前再統整雙贏","q":3,"tag":"☯ 雙贏不是各做各的再拼裝；少了過程的碰撞，就只是兩份作業。"},{"t":"時間對半切，一半查資料一半做實驗","q":1,"tag":"◐ 對半分看似公平，但兩人都做不擅長的那半，互補的力量沒用上。"}]},{"h":5,"text":"國文報告可以自選主題，你想做流行歌詞裡的修辭，組員想做古典詩詞之美，討論了兩節課沒有結果，老師提醒再不定案就要開始扣分。","c":[{"t":"折衷各分一半篇幅，前古典後流行","q":1,"tag":"◐ 各半是妥協的中間值，兩塊內容沒有對話，報告像兩份作業釘在一起。"},{"t":"誰查的資料多就用誰的，先搶先贏","q":2,"tag":"比快比多是直覺的公平，但主題的價值不在誰先查，在能不能撞出新意。"},{"t":"合出新題：古典詩詞如何活在流行歌裡","q":0,"tag":"✓ 統合綜效：老靈魂遇上新旋律，這題目比任何一邊的原案都有意思。"},{"t":"提議先擱置主題，排好要事優先進度表","q":3,"tag":"☯ 排程是好工具，但主題還沒定，進度表排的只是空氣。"},{"t":"放話不用你的題就拆組，各自求生","q":4,"tag":"⚠ 用拆組威脅對方，主題還沒定，team 已經先散了。"}]},{"h":5,"text":"班會討論班費結餘，一派想訂做畢業紀念外套，一派想加碼畢業班遊基金，兩派吵到面紅耳赤，班導點名身為班長的你出面處理這件事。","c":[{"t":"提議金額對半分，兩邊都做小規模版","q":1,"tag":"◐ 對半分息事寧人，但外套訂不齊、班遊加不了菜，兩邊都只拿到半套。"},{"t":"直接舉手表決，輸的一派請多多包涵","q":2,"tag":"表決是最快的收場，但「請包涵」安慰不了輸的那派整學期的疙瘩。"},{"t":"宣布統統不花，儲蓄才是要事第一","q":3,"tag":"☯ 節制是美德，但班費的「要事」是全班的共同回憶，不是存簿數字。"},{"t":"偷偷跟班導說照外套派，人多好交代","q":4,"tag":"⚠ 繞過討論走後門，等真相曝光，你賠上的是班長的公信力。"},{"t":"先問兩派背後想要什麼，再找整合案","q":0,"tag":"✓ 也許都是「留下紀念」——印班服風外套當班遊制服，一筆錢兩個願望。"}]},{"h":5,"text":"英語話劇比賽排練中，編劇堅持大量台詞展現文采，主演抱怨根本背不完、想改用肢體和道具說故事，兩人在排練場上吵翻，你是這齣的導演。","c":[{"t":"引雙贏思維，安排兩人分頭做兩齣劇","q":3,"tag":"☯ 各演各的不是雙贏，是把一齣戲的資源硬拆成兩齣半成品。"},{"t":"威脅再吵就把兩人都換掉，你自己演","q":4,"tag":"⚠ 恐嚇能讓排練場安靜，但安靜的排練場生不出好戲。"},{"t":"編劇最大，請主演回家把台詞背熟","q":2,"tag":"劇本至上看似專業，但演員的身體語言被浪費，戲只剩一半的生命。"},{"t":"保留關鍵金句，其餘改用肢體來呈現","q":0,"tag":"✓ 文采濃縮成金句、肢體撐起敘事——這齣混血的戲，兩人都想不到。"},{"t":"台詞砍半肢體加半，兩邊各讓一步","q":1,"tag":"◐ 各讓一步是折衷不是融合；砍到哪、加在哪，還是沒人真正對過話。"}]},{"h":5,"text":"資訊課要交一支班級介紹短影音，你負責腳本、同學負責運鏡，他嫌你的腳本沒梗，你嫌他的運鏡晃到讓人頭暈，交件期限只剩三天。","c":[{"t":"互看對方作品的亮點，逐段對齊調整","q":0,"tag":"✓ 他的鏡頭語言配你的文字節奏，對齊之後，梗和畫面才會互相加分。"},{"t":"上社群發文抱怨雷隊友，先討拍再說","q":4,"tag":"⚠ 公審隊友換來按讚，也換來他徹底擺爛——三天後交白卷的是你們兩個。"},{"t":"先照你的腳本拍，運鏡的事之後再說","q":2,"tag":"先搶主導看似止血，但他的專業被晾著，畫面問題只是延後爆炸。"},{"t":"停工一天去戶外走走，鋸子磨利再拍","q":3,"tag":"☯ 更新自己是長期功課，但死線前三天，先把兩人的專業接起來。"},{"t":"各自負責到底，互不干涉對方領域","q":1,"tag":"◐ 分工明確卻零交流，成品會是好腳本配晃鏡頭——各自及格，整體不及格。"}]},{"h":5,"text":"爸爸想幫你報數學補習班，你想用線上課程自學省下通勤時間，晚餐桌上他說「我是為你好」，你回「你都不懂我」，空氣瞬間凝結。","c":[{"t":"先聽他的擔心，再一起設計混合方案","q":0,"tag":"✓ 他怕的是沒人盯進度——線上課加每週成績回報，第三案就談成了。"},{"t":"搬出主動積極：我的學習我自己負責","q":3,"tag":"☯ 自主沒有錯，但拿習慣一當擋箭牌拒絕溝通，就長不出第三案。"},{"t":"拗不過就先答應，反正吵不贏大人","q":2,"tag":"表面順從、心裡不服，補習費繳了、效果歸零，兩邊都輸。"},{"t":"摔筷子回房鎖門，用冷戰逼爸爸讓步","q":4,"tag":"⚠ 冷戰就算贏了，也是用親子關係當代價換來的慘勝。"},{"t":"答應先補一期試試，換取他的信任","q":1,"tag":"◐ 讓步換信任是可行的起手式，但你的需求還沒被聽見，只完成一半。"}]},{"h":5,"text":"家政課分組做創意料理評比，組內一人堅持做台式滷肉飯、一人想挑戰義大利麵，材料預算只夠做一道菜，下週上課就要實作評分。","c":[{"t":"選評審比較可能喜歡的，穩穩拿分數","q":2,"tag":"猜評審口味是安全牌，但安全牌滿場都是，「創意」兩個字就輸了。"},{"t":"腦力激盪出融合菜：滷肉醬義大利麵","q":0,"tag":"✓ 統合綜效：台魂義體的混血料理，正是創意評比最想看到的第三案。"},{"t":"建議雙贏各做一道，預算之後再想辦法","q":3,"tag":"☯ 雙贏不是把預算問題晾著各做各的；先整合，資源才會夠用。"},{"t":"猜拳決定主菜，贏的做菜輸的做擺盤","q":1,"tag":"◐ 猜拳分了工，但輸的人只是認命不是認同，創意也沒有交會。"},{"t":"嗆組員的味覺有問題，不聽就退出","q":4,"tag":"⚠ 人身攻擊加威脅退組，菜還沒下鍋，這一組已經先燒焦了。"}]},{"h":5,"text":"段考結束全班想訂飲料慶祝，半數要手搖茶、半數要現打果汁，兩家店的滿額外送門檻都是三十杯，全班只有二十八人，你是負責訂購的總務。","c":[{"t":"這次先訂茶，下次段考換果汁補回來","q":1,"tag":"◐ 輪流是常見的公平，但這次想喝果汁的人，快樂已經先被延期了。"},{"t":"找一家茶和果汁都有的店，一單搞定","q":0,"tag":"✓ 跳出二選一，重新定義問題——第三選擇常常藏在選項清單的外面。"},{"t":"催大家快點決定，反正訂哪家都差不多","q":2,"tag":"「都差不多」是懶得整合的口頭禪；差的那一點，就是有人不開心。"},{"t":"宣布知彼解己，先聽每個人的飲料史","q":3,"tag":"☯ 傾聽用錯了地方——需要的是盤點需求找交集，不是聽人生故事。"},{"t":"只統計同派的，另一派要喝自己想辦法","q":4,"tag":"⚠ 總務只服務半個班，慶功還沒開始，班就先分成兩國了。"}]},{"h":5,"text":"擔任圖書股長的你想在讀書週辦好書交換，資訊股長想辦電子書體驗，老師說讀書週活動企劃只能報一案，你們在辦公室門口僵持不下。","c":[{"t":"合成一案：交換實體書加掃碼聽書展","q":0,"tag":"✓ 紙本的溫度加數位的便利，這案比任何一邊的原案都完整——綜效現身。"},{"t":"誰先想到誰優先，你提的當然報你的","q":2,"tag":"先來後到是直覺的規則，但企劃的價值不在誰先講，在誰更好。"},{"t":"說要事第一，讀書週不如拿去複習段考","q":3,"tag":"☯ 複習很重要，但用要事第一逃掉眼前的整合題，是概念的錯置。"},{"t":"搶先把企劃表交出去，先斬後奏再說","q":4,"tag":"⚠ 偷跑毀掉的不是這次活動，是你們兩個股長整學期的合作關係。"},{"t":"今年用你的案，明年再換他的案上場","q":1,"tag":"◐ 輪流有誠意，但你們畢業前只剩這一次讀書週——整合才不留遺憾。"}]},{"h":5,"text":"童軍露營搭帳篷，你照課本學的標準流程來，同小隊的同學用他爸教的野營快速法，兩人各搭一半卡在中間，教練抱著手在旁邊看好戲。","c":[{"t":"課本才是正規做法，堅持照標準流程","q":2,"tag":"課本是前人的整理，不是差異的終點站；他的土法裡可能藏著更快的訣竅。"},{"t":"先停手畫搭帳心智圖，以終為始規劃","q":3,"tag":"☯ 規劃是好事，但帳篷卡在眼前，兩套實作的碰撞才是解方。"},{"t":"比對兩套方法的優點，合出更快搭法","q":0,"tag":"✓ 標準流程的穩加野營法的快，混出來的第三套，也許連教練都想學。"},{"t":"尊重差異這次照標準，下次再試他的","q":1,"tag":"◐ 有尊重但沒交手，兩套方法擦肩而過，下次多半也不會有下次。"},{"t":"放手讓他自己搭，倒了正好看他笑話","q":4,"tag":"⚠ 等隊友失敗來證明自己，帳篷倒的那一刻，全小隊一起淋雨。"}]},{"h":5,"text":"桌遊社要自製一款校園主題桌遊去參賽，老社員想沿用經典的大富翁式玩法，新社員想加入即時對戰機制，設計會議上吵成新舊兩派。","c":[{"t":"經典玩法得過獎，照老社員的準沒錯","q":2,"tag":"靠過去的成功公式最安心，但評審看過的東西，不會再給第二次驚豔。"},{"t":"請新社員先知彼解己，多聽學長姐的","q":3,"tag":"☯ 知彼解己是雙向的橋，單方面要新人閉嘴聽，就變成輩分壓制。"},{"t":"資歷說話，表決時動員老社員輾壓","q":4,"tag":"⚠ 用人數碾壓新聲音，新社員下學期就退光，社團跟著老化。"},{"t":"做原型測試混搭機制，用回饋來決定","q":0,"tag":"✓ 別用嘴吵，用玩家的笑聲投票——混搭原型讓差異在桌上直接對話。"},{"t":"主體用經典玩法，對戰做成擴充包","q":1,"tag":"◐ 擴充包保住了和平，但新機制被關在盒子外，火花隔著一層塑膠膜。"}]},{"h":5,"text":"美術課全班合作走廊壁畫，一組想畫寫實校景、一組想畫奔放的塗鴉風，牆面只有一面，美術老師把整合構圖的任務交給身為藝術股長的你。","c":[{"t":"牆面切兩半，左寫實右塗鴉各畫各的","q":1,"tag":"◐ 切半保住了兩派，卻切斷了對話——一面牆變成兩張互不相干的圖。"},{"t":"寫實比較安全，塗鴉會被主任唸吧","q":2,"tag":"替別人的反對先投降，是最常見的自我審查——塗鴉的能量還沒上牆就死了。"},{"t":"設計融合稿：寫實校景長出塗鴉翅膀","q":0,"tag":"✓ 寫實打底、塗鴉點睛，兩種筆觸在同一面牆對話——這就是第三選擇。"},{"t":"先請全班寫藝術使命宣言再開始動筆","q":3,"tag":"☯ 宣言寫得再美，兩種風格還是沒交會；先讓畫風彼此對話吧。"},{"t":"偷偷先打好你要的底稿，造成既成事實","q":4,"tag":"⚠ 用偷跑逼全班接受，牆上畫的是圖，同學心裡記的是帳。"}]},{"h":5,"text":"校慶班級進場表演，一派想走整齊隊形的傳統路線，一派想搞爆笑仿妝惡搞，班會表決前兩邊都來找你拉票，你手上這一票還沒決定投給誰。","c":[{"t":"看哪派人多就挺哪派，別得罪多數","q":2,"tag":"跟風多數最安全，但你放棄的是手上這票能促成整合的關鍵位置。"},{"t":"提第三案：整齊隊形中藏爆笑彩蛋","q":0,"tag":"✓ 隊形本身變成梗——秩序與爆笑同台，比兩派原案都更有記憶點。"},{"t":"提醒大家以終為始：會考才是真終點","q":3,"tag":"☯ 終點沒有錯，但拿會考否定眼前的合作課題，是離題的正確。"},{"t":"建議前段走傳統、後段再放惡搞橋段","q":1,"tag":"◐ 前後拼接是折衷，兩段各演各的，少了讓全場「哇」出來的化學反應。"},{"t":"兩派都酸一輪，說進場表演本來就無聊","q":4,"tag":"⚠ 冷嘲熱諷澆熄所有人的熱情，最後全班真的隨便走完，無聊成真。"}]},{"h":5,"text":"生活科技課的機器人比賽，你設計的機構穩定但速度慢，隊友的版本快卻常掉零件，測試賽後兩人各自堅持自己的設計，正式賽下週登場。","c":[{"t":"比賽求穩，堅持用自己那台比較保險","q":2,"tag":"求穩是直覺，但對手都在進化，只守著自己的版本，名次也會很穩——穩穩墊底。"},{"t":"說雙贏：兩台都報名，各自比各自的","q":3,"tag":"☯ 規則一隊只能一台；硬套雙贏來迴避整合，反而兩台都不夠強。"},{"t":"偷改他的參數讓它出包，逼他放棄","q":4,"tag":"⚠ 暗中搞破壞是最徹底的墮落——贏了設計權，輸掉整個人。"},{"t":"初賽用穩的保晉級，決賽再換快的","q":1,"tag":"◐ 分階段是聰明的排程，但兩台始終沒合體，天花板還是原來的高度。"},{"t":"拆解兩版優點，合體出穩又快的三代","q":0,"tag":"✓ 你的結構加他的傳動，第三代機是兩人單獨都造不出來的作品。"}]},{"h":5,"text":"你的兩個好友因為限時動態標註漏了誰而冷戰，各自跑來跟你抱怨對方小氣，明天三個人本來約好一起去看電影，票都已經買好了。","c":[{"t":"勸兩邊各退一步，小事情別放在心上","q":2,"tag":"「別計較」是最順口的和事佬台詞，但沒被聽見的委屈不會自己消失。"},{"t":"分別聽完在意的點，約兩人當面說開","q":0,"tag":"✓ 也許都是「怕被忽略」——把真心話攤開，友情反而比冷戰前更牢。"},{"t":"教他們刺激與回應之間有選擇空間","q":3,"tag":"☯ 道理是對的，但冷戰中的人需要的是一座橋，不是一堂哲學課。"},{"t":"把兩人的抱怨截圖互傳，看戲比較有趣","q":4,"tag":"⚠ 搧風點火讓冷戰升級成絕交，你也從朋友變成了戰犯。"},{"t":"當傳聲筒幫忙傳話，避免正面衝突","q":1,"tag":"◐ 傳話有心意，但隔著你的轉述，兩人真正的在意永遠對不到頻。"}]},{"h":6,"text":"段考剩三天，你已連續兩晚讀到凌晨兩點，白天上課頭昏腦脹、寫題頻頻粗心，效率明顯變差，今晚你要怎麼安排讀書與睡眠。","c":[{"t":"提早一小時上床，其他照舊硬讀","q":1,"tag":"◐ 方向對了但只補一小時，欠兩晚的睡眠債，鋸子還是鈍的——更新要補到位。"},{"t":"先重排讀書計畫，把進度塞更滿","q":3,"tag":"☯ 要事第一是好概念，但你現在缺的不是計畫是睡眠——鋸子鈍了，排再滿也砍不動。"},{"t":"今晚十一點前睡，養足精神再讀","q":0,"tag":"✓ 身體是最重要的那把鋸子——睡飽再讀，吸收遠勝昏沉硬撐，休息是投資不是偷懶。"},{"t":"多買兩罐提神飲料，繼續撐下去","q":2,"tag":"用透支換短效像借高利貸——眼前撐住了，身體的帳單之後會連本帶利討回來。"},{"t":"乾脆整夜不睡，考完再一次補眠","q":4,"tag":"⚠ 燃燒健康換進度是最不划算的交易——垮掉一次，要花更長的時間才補得回來。"}]},{"h":6,"text":"為了拚會考，你把運動、畫畫和找朋友的時間全砍掉，只剩讀書，兩個月下來成績沒起色，人卻越來越悶、越讀越沒勁。","c":[{"t":"連睡眠也一起砍，悶就是不夠拚","q":4,"tag":"⚠ 把失衡當成不夠努力，只會加速崩潰——繃太緊的弦，永遠斷得最快。"},{"t":"排回運動與朋友時間，均衡更新","q":0,"tag":"✓ 身體、心智、情感、心靈四面向都要磨，人才有續航力——均衡不是分心，是充電。"},{"t":"覺得再撐一下，考完自然就好了","q":2,"tag":"「考完就好」是最常見的自我安慰——沒有更新的硬撐，撐到考前就先垮了。"},{"t":"重寫目標宣言，用大夢想逼自己","q":3,"tag":"☯ 以終為始很熱血，但你的問題是四面向失衡——目標再大，沒電的引擎也跑不動。"},{"t":"週末勉強留半天，平日照樣全讀","q":1,"tag":"◐ 有留時間是進步，但四面向的更新要規律進行，不是週末施捨自己半天。"}]},{"h":6,"text":"你這學期學了不少筆記法和英文單字，卻從沒回頭整理複習，段考前打開課本才發現幾乎全忘，等於整學期白學一遍。","c":[{"t":"考前再一次狂背，平常不管它們","q":2,"tag":"臨時填鴨不是更新——硬塞進去的東西考完就漏光，留不下真正屬於你的能力。"},{"t":"想到才隨手翻翻，沒有固定時間","q":1,"tag":"◐ 有翻總比沒翻好，但不排進固定時段，回顧永遠會被新的作業擠掉。"},{"t":"忘了就算了，反正以後也用不到","q":4,"tag":"⚠ 永遠在原地重學，等於丟掉前面所有力氣——沒有累積，再勤奮也走不遠。"},{"t":"每週固定排時間，回顧整理筆記","q":0,"tag":"✓ 定期回顧是磨利心智之刀——知識經過整理，才會從「學過」變成「擁有」。"},{"t":"先立誓下次段考要衝進前三名","q":3,"tag":"☯ 以終為始沒錯，但少了定期回顧的機制，目標喊得再響，知識照樣流光。"}]},{"h":6,"text":"你放學回家就坐在書桌前，假日整天窩著滑手機，最近肩頸痠痛、上課常打瞌睡，體育課跑兩圈就喘到不行。","c":[{"t":"先把讀書計畫排好，身體先忍忍","q":3,"tag":"☯ 要事第一被你用反了——身體是所有計畫的本錢，保養它正是第二象限的要事。"},{"t":"買痠痛貼布貼一貼，繼續坐著讀","q":2,"tag":"貼布只是壓住警報聲——儀表板亮燈不處理，引擎遲早在最關鍵的時刻熄火。"},{"t":"想到才伸展兩下，沒有固定習慣","q":1,"tag":"◐ 有動總比沒動好，但身體這把鋸子要定期磨——偶爾保養，鈍的速度追不回來。"},{"t":"能不動就不動，讀書比較要緊啦","q":4,"tag":"⚠ 完全放棄身體換讀書，是拿本錢去換零錢——體力垮了，成績跟著一起垮。"},{"t":"每天固定運動半小時，練回體力","q":0,"tag":"✓ 規律運動是身體面向的更新——體力回來了，讀書才坐得久、撐得穩、吸收得快。"}]},{"h":6,"text":"最近功課和班上人際都不順，你把煩悶全悶在心裡，晚上睡不好、上課常放空，越來越不想跟任何人講話。","c":[{"t":"找信任的人聊聊，或動筆寫下來","q":0,"tag":"✓ 情感面的更新，是主動替情緒找健康出口——說出來或寫下來，心才不會悶出病。"},{"t":"把火氣發在家人身上，摔門大吼","q":4,"tag":"⚠ 拿親近的人當情緒垃圾桶，傷了關係也傷了自己——這不是抒發，是擴大傷害。"},{"t":"告訴自己要主動積極，不准難過","q":3,"tag":"☯ 主動積極是選擇回應方式，不是壓抑情緒——硬壓下去的悶，會連本帶利反撲。"},{"t":"打算找人聊聊，但一直沒開口","q":1,"tag":"◐ 有想到出口是第一步，但遲遲不開口，情緒只會越積越滿——更新需要行動。"},{"t":"狂滑手機打遊戲，把感覺蓋過去","q":2,"tag":"用刺激暫時蓋住情緒是逃避不是更新——壓力沒被處理，只是被埋得更深。"}]},{"h":6,"text":"老師示範了一套更有效率的複習法，試過的同學都說有用，但你嫌改變麻煩，想繼續用自己熟悉的老方法讀下去。","c":[{"t":"收下講義想試試，卻一直沒開始","q":1,"tag":"◐ 有意願卻遲遲不動手，新方法永遠停在「聽過」——更新，要真的用過一次才算。"},{"t":"等哪次考差了，再來考慮要不要改","q":2,"tag":"非得撞牆才被動調整，是把更新拖到最後——主動精進的人，不等失敗才換方法。"},{"t":"嗆同學是跟風仔，堅決死守舊方法","q":4,"tag":"⚠ 拒絕一切新事物、還攻擊嘗試的人——世界在前進，停在原地就是退步。"},{"t":"挑一科先試新方法，比較後再調整","q":0,"tag":"✓ 小規模試用、比較、再調整——持續精進心智這把刀，效率才會一路往上疊。"},{"t":"覺得反正目標一樣，用哪套都沒差","q":3,"tag":"☯ 以終為始講的是方向，不是替懶得升級找理由——同樣的終點，鈍鋸子走得加倍慢。"}]},{"h":6,"text":"你的行事曆從早自習排到晚上補習，連下課十分鐘都拿來寫作業，最近卻常常恍神，讀什麼都進不了腦袋裡。","c":[{"t":"覺得恍神是不夠拚，把表排得更滿","q":2,"tag":"把當機當懶惰醫，只會越修越壞——沒有留白的腦袋，塞再多也進不去。"},{"t":"每天留十分鐘放空、散步或發呆","q":0,"tag":"✓ 心靈面的更新就是定期留白——每天一小段安靜，人才清醒，不被瑣事淹沒。"},{"t":"拿出計畫本，把待辦分四象限重排","q":3,"tag":"☯ 四象限是好工具，但你缺的不是排序是喘息——留白本身，就是第二象限的要事。"},{"t":"乾脆熬夜補進度，用時間硬換分數","q":4,"tag":"⚠ 拿睡眠填進度是雙重透支——恍神會更嚴重，你在用明天的腦付今天的債。"},{"t":"知道該留白，卻總被作業擠掉","q":1,"tag":"◐ 把留白排在最後，最後就沒了——不主動守住那段安靜，它一定會被吃掉。"}]},{"h":6,"text":"連續三天段考終於結束，整個人像被掏空，週末兩天完全自由，你想好好充電，讓自己滿血迎接下週的新進度。","c":[{"t":"手遊馬拉松，連打到凌晨三點","q":4,"tag":"⚠ 看似放鬆其實透支——用更累的方式「休息」，是假期裡最甜也最貴的陷阱。"},{"t":"運動、看課外書、找朋友換著來","q":0,"tag":"✓ 身、腦、心輪流保養——四個面向都磨到，鋸子才真的利，下週才真的滿血。"},{"t":"立刻開始預習下一範圍，不敢停","q":2,"tag":"不休息的勤勞是慢性折舊——鋸子越鋸越鈍，你只是用低效率感動自己。"},{"t":"整個週末睡掉，睡飽就算充電了","q":1,"tag":"◐ 身體充了電，腦和心還空著——只磨一面的鋸子，下週還是提不起勁。"},{"t":"開整天檢討會，逐科分析失分點","q":3,"tag":"☯ 檢視回饋是上進螺旋的一環，但時機錯了——先讓身心回血，檢討才有品質。"}]},{"h":6,"text":"你打籃球半年，最近投籃命中率卡關，怎麼練都沒進步，隊友一個個超越你，你開始懷疑自己是不是不適合打球。","c":[{"t":"回頭磨基本動作，並加強體能訓練","q":0,"tag":"✓ 停下來磨鋸子，比咬牙硬鋸更快——基本功就是你的鋸齒，鈍了就回頭磨。"},{"t":"認定天分就到這裡，練了也是白練","q":2,"tag":"把卡關判成天花板，成長型思維直接下線——瓶頸是訊號，不是判決書。"},{"t":"加倍苦練同一招，用時間硬堆上去","q":1,"tag":"◐ 精神可嘉，但用鈍鋸子加倍鋸只會加倍累——先檢查方法，再談苦練。"},{"t":"只找弱的人單挑，贏球找回面子","q":4,"tag":"⚠ 贏來的爽感是止痛藥不是治療——關卡原地等你，逃避只會讓它更高。"},{"t":"找隊友談雙贏，請他們多傳球給你","q":3,"tag":"☯ 雙贏思維用錯地方了——隊友讓球治標不治本，你缺的是回頭更新基本功。"}]},{"h":6,"text":"你最近一點小事就爆氣，同學借筆晚點還就翻臉，連媽媽多問一句都嫌煩，事後想想連你自己都嚇了一跳。","c":[{"t":"提醒自己忍住，別再對人亂發脾氣","q":1,"tag":"◐ 願意克制是好事，但壓住的火沒有熄——不處理源頭，改天連本帶利燒回來。"},{"t":"逐一去道歉存情感帳戶，其他照舊","q":3,"tag":"☯ 情感帳戶要存沒錯，但源頭是你的電量見底——不先保養自己，存了又會扣。"},{"t":"檢查最近的睡眠、運動和心情狀態","q":0,"tag":"✓ 暴躁是儀表板亮燈不是人格缺陷——回頭盤點四個面向，找出沒充到電的那格。"},{"t":"覺得是別人太煩，跟自己沒有關係","q":2,"tag":"把警示燈貼起來，引擎照樣過熱——怪罪別人最輕鬆，也最修不好問題。"},{"t":"上網開小帳，把氣出在陌生人身上","q":4,"tag":"⚠ 把火倒到網路上，火沒熄還可能延燒回自己——傷人的紓壓，代價最貴。"}]},{"h":6,"text":"好友約你每天七點到操場晨跑養成習慣，你其實很想改善體力，但擔心自己根本爬不起來，站在操場邊猶豫要不要答應。","c":[{"t":"先寫運動目標宣言，貼滿整面牆再說","q":3,"tag":"☯ 以終為始不是寫完就結束——沒有明天七點的那一步，貼再多宣言都是壁紙。"},{"t":"答應他，並約好每天互打電話叫醒","q":0,"tag":"✓ 運動練身、承諾練心、同伴暖情——一個晨跑約定，同時磨了三個面向的鋸子。"},{"t":"直接拒絕，反正早上一定起不來","q":2,"tag":"還沒開始就投降，更新的門連推都沒推——你拒絕的不是晨跑，是變強的機會。"},{"t":"不敢答應，想說在家自己跳繩就好","q":1,"tag":"◐ 能動就是好事，但少了同伴的力量，習慣常常撐不過第一個下雨天。"},{"t":"爽快答應，然後天天放他鴿子睡死","q":4,"tag":"⚠ 承諾了卻擺爛，賠上的是信用——健康沒練到，情感帳戶還被大筆提款。"}]},{"h":6,"text":"午休鐘響，你眼皮重到抬不起來，好友卻傳來一支超好笑的影片喊你快看，而下午第一節就要考數學小考。","c":[{"t":"回他考完再看，設好鬧鐘趴下午睡","q":0,"tag":"✓ 二十五分鐘的午睡是合法外掛——下午的你像換一顆腦袋，回報率最高的投資。"},{"t":"點開來看，想說笑一笑也算休息啊","q":2,"tag":"「好笑」跟「休息」是兩回事——前者是刺激，後者是修復，下午會用瞌睡付帳。"},{"t":"先看那一支就好，剩的時間再趴睡","q":1,"tag":"◐ 影片一支接一支，等回神只剩十分鐘——半套的休息，換來半當機的下午。"},{"t":"硬撐不睡狂刷題，考前就是拚要事","q":3,"tag":"☯ 要事第一沒教你透支——用三成電量的腦袋刷題，讀進去的趨近於零。"},{"t":"看影片看到睡著，考爛再怪題目難","q":4,"tag":"⚠ 放掉休息又放掉準備，最後把責任推給題目——雙輸還學不到教訓。"}]},{"h":6,"text":"你作業其實九點半就寫完，卻滑手機滑到十二點半才睡，隔天上課猛打瞌睡，媽媽關心地問你是不是作業太多了。","c":[{"t":"承認是滑手機，跟她約定十一點就寢","q":0,"tag":"✓ 誠實面對「報復性熬夜」是改變的第一步——用明天的電量買今晚的自由，利息是兩倍。"},{"t":"說要主動積極，靠意志力撐過白天","q":3,"tag":"☯ 主動積極是改變原因，不是硬扛結果——真正的選擇權，在昨晚的手機上。"},{"t":"含糊說作業多，心想明天早點睡就好","q":1,"tag":"◐ 「明天早點睡」是熬夜者的口頭禪——沒有具體的就寢線，明天只會重播今天。"},{"t":"覺得晚上是唯一自由，捨不得睡覺","q":2,"tag":"白天被排滿，夜裡捨不得放掉自由——心情可以理解，但帳單由隔天的你付。"},{"t":"怪老師作業出太多，繼續照樣熬夜","q":4,"tag":"⚠ 把責任推出去，自己一點都不用改——最輕鬆的答案，通常最沒有用。"}]},{"h":6,"text":"連上四節課你的腦袋已經當機，下一節是最難的理化，下課只有十分鐘，你想好好把握，但整個人昏昏沉沉。","c":[{"t":"繼續趕別科作業，能省一點是一點","q":2,"tag":"把唯一的散熱時間也拿去運轉——過熱的機器不會變勤勞，只會當得更徹底。"},{"t":"翻出計畫本，重排今天的要事順序","q":3,"tag":"☯ 排要事是好習慣，但此刻的要事就是讓腦袋散熱——先充電，計畫才跑得動。"},{"t":"離開座位到走廊看遠方、深呼吸裝水","q":0,"tag":"✓ 腦袋跟肌肉一樣，收縮與放鬆交替才會強——十分鐘的真休息，換一節課的清醒。"},{"t":"趴著硬睡三分鐘，被鐘聲嚇醒更暈","q":1,"tag":"◐ 太短的睡來不及修復，只會打斷精神——要嘛睡滿二十分鐘，要嘛起來走動。"},{"t":"乾脆下節課趴整節，回家自己再讀","q":4,"tag":"⚠ 放掉最難的一節課，回家要花三倍時間補——逃避的成本，永遠比面對高。"}]},{"h":6,"text":"整週上課加補習，週五晚上你累到不想動，週六一整天完全空白，你想好好安排這天，讓下週能夠滿血開場。","c":[{"t":"排滿讀書進度，下週有考試不敢停","q":2,"tag":"連轉十三天的陀螺不會變勤勞，只會變鈍——假讀十小時，吸收不到兩成。"},{"t":"通宵打電動，反正週六可以睡整天","q":4,"tag":"⚠ 用更耗電的方式慶祝放假，等於預支下週的電——最貴的娛樂是熬夜。"},{"t":"睡到自然醒、下午打球、晚上看小說","q":0,"tag":"✓ 主動的休息讓四個面向輪流回血——週日的你電量九成，效率是平常的一倍半。"},{"t":"寫下週目標清單，密密麻麻寫三頁","q":3,"tag":"☯ 以終為始不是拿放假日寫作文——此刻該做的更新是充電，不是再產一份焦慮。"},{"t":"躺床滑手機一整天，當作是放鬆","q":1,"tag":"◐ 滑手機是低耗電待機不是充電——身體沒動、腦沒停、心沒亮，躺完反而更累。"}]},{"h":6,"text":"連假最後一晚，明天開學要發段考考卷、還要上新進度，你捨不得假期結束，很想再瘋最後一夜當作紀念。","c":[{"t":"提早上床，卻躺著滑手機到半夜","q":1,"tag":"◐ 人到床上、心還在螢幕——沒把手機隔開，早睡的好意只是換個姿勢熬夜。"},{"t":"十一點前睡，把生理時鐘調回上學","q":0,"tag":"✓ 收假前一晚早睡，是送給明天自己的禮物——全班當殭屍時，你是唯一的活人。"},{"t":"想說分數在關注圈，乾脆放空到爽","q":3,"tag":"☯ 分數確實不由你控制，但「今晚睡飽」正是影響圈的事——概念不是放縱的藉口。"},{"t":"熬到三點，最後一夜才對得起假期","q":2,"tag":"用假期最後一夜預支開學第一週的電——最後的瘋狂，永遠是最貴的。"},{"t":"通宵狂趕假期作業，用爆肝來贖罪","q":4,"tag":"⚠ 拖到最後一夜再自我懲罰，身體付雙倍代價——這不是負責，是惡性循環。"}]},{"h":6,"text":"凌晨一點，你第五次跟自己說「看完這支就睡」，忽然發現自己其實一點都不快樂，只是手指停不下來而已。","c":[{"t":"再滑十分鐘，湊到一點半整數再睡","q":2,"tag":"「湊整數」是拖延的萬能藉口——時間永遠有下一個整數，一點半會變兩點十分。"},{"t":"打開筆記寫人生反省，寫到兩點多","q":3,"tag":"☯ 反思是心靈更新沒錯，但凌晨一點的要事是睡覺——用對時機，概念才有用。"},{"t":"怪演算法太強大，自己也沒辦法啊","q":1,"tag":"◐ 演算法確實強，但「沒辦法」是放棄選擇——手機放哪裡充電，就在你的影響圈。"},{"t":"把手機拿去書桌充電，起身回床睡","q":0,"tag":"✓ 你看穿了它的設計目標不是讓你快樂，是讓你無法離開——看穿的人才有得選。"},{"t":"反正都這麼晚了，乾脆滑到天亮吧","q":4,"tag":"⚠ 用「已經很晚」把整夜賠進去，是熬夜最後的滑坡——差的是明天一整顆腦袋。"}]},{"h":6,"text":"你下定決心處理熬夜滑手機的問題，想從幾個方法裡挑一個對「凌晨的螢幕」最有效、最不依賴意志力的做法。","c":[{"t":"立規則：十一點後手機放客廳充電","q":0,"tag":"✓ 凌晨一點的你是意志力最弱的你，別派他上場——物理隔離讓戰爭開打前就結束。"},{"t":"下載自律軟體，設定使用時間提醒","q":1,"tag":"◐ 有幫助，但按掉提醒的還是凌晨最不可靠的那個你——軟體防線不如物理防線。"},{"t":"發誓從今晚開始，靠意志力戒掉它","q":2,"tag":"這種誓言的平均壽命是兩天——環境設計贏過意志力，是自我管理的鐵律。"},{"t":"相信主動積極，靠選擇的自由硬扛","q":3,"tag":"☯ 主動積極是先改環境再談選擇——聰明人設計環境，不跟最強的誘惑硬碰硬。"},{"t":"改成躲進棉被滑，爸媽抓不到就好","q":4,"tag":"⚠ 問題不是被抓到，是睡眠被吃掉——躲起來熬夜，騙過爸媽騙不過黑眼圈。"}]},{"h":6,"text":"逛書店時你被一本天文圖鑑吸住，站著翻了半小時停不下來，但它跟考試完全無關，零用錢也剛好只夠買下它。","c":[{"t":"覺得又不會考，買了浪費錢和時間","q":2,"tag":"「會不會考」是學校的計分板，不是大腦的——只為考試進食的腦，畢業就停止生長。"},{"t":"想起要事第一，錢應該花在參考書","q":3,"tag":"☯ 要事第一不是考科優先——自選的學習正是心智更新的活水，它就是第二象限。"},{"t":"買下它，自己選的學習吸收率最高","q":0,"tag":"✓ 大腦不討厭學習，只討厭被指定——自選的知識是充電，被塞的知識才耗電。"},{"t":"放回去，想說考完段考後再來買","q":1,"tag":"◐ 「考完再說」之後永遠還有下一個考——眼睛發光的當下，最禁不起一拖再拖。"},{"t":"偷偷拍下整本內頁，回家慢慢看","q":4,"tag":"⚠ 侵犯著作權還騙過自己——那股翻到停不下來的興致，到家早就涼掉了。"}]},{"h":6,"text":"這天你莫名心情低落，明明沒發生什麼事卻整個人悶悶的，提不起勁寫作業，也完全不想跟任何人說話。","c":[{"t":"訓話自己要主動積極，不准耍憂鬱","q":3,"tag":"☯ 主動積極不是罵走情緒——對下雨的天空生氣，雨不會停，你還多一層傷。"},{"t":"硬撐著寫作業，想說忙起來就忘了","q":1,"tag":"◐ 轉移注意有點用，但沒被看見的情緒只是暫存——它會挑更累的時候回來。"},{"t":"承認今天就是低，做件小小喜歡的事","q":0,"tag":"✓ 「承認＋小事」是情緒的標準充電流程——不跟低氣壓打架，它反而走得比較快。"},{"t":"滑手機滑整晚，把低氣壓蓋過去","q":2,"tag":"蓋是蓋掉了——手機一放，低氣壓原封不動，還加贈浪費一晚的懊悔。"},{"t":"找家人吵一架，把悶氣全倒出去","q":4,"tag":"⚠ 把沒來由的低氣壓倒在別人身上——氣沒消，情感帳戶還被大筆提款。"}]},{"h":6,"text":"你家的晚餐餐桌總是安靜，大家各自扒飯滑手機，你想跟爸媽多一點連結，卻完全不知道該怎麼開口才自然。","c":[{"t":"等爸媽先開口，大人應該要先起頭吧","q":1,"tag":"◐ 他們也在等你——面對青春期小孩，大人跟你一樣不知所措，先動的人先贏。"},{"t":"覺得開口就會被念，乾脆繼續沉默","q":2,"tag":"「開口＝被念」是舊經驗——但你試過成績以外的話題嗎？頻道要自己換。"},{"t":"提議全家開會議，制定家庭使命宣言","q":3,"tag":"☯ 家庭使命宣言是好東西，但冷掉的餐桌要先用小故事暖機，不是直接開大會。"},{"t":"問媽媽國中都在玩什麼，聽她的故事","q":0,"tag":"✓ 問「他們的故事」是重啟大人最快的開關——連結從好奇開始，不從報告成績開始。"},{"t":"扒完飯就回房間，戴上耳機隔絕全家","q":4,"tag":"⚠ 連開機鍵都沒按就關電源——家人這口泉不是乾了，是一直沒人去打水。"}]},{"h":6,"text":"餐桌聊開之後，爸爸難得多講了幾句，他說「你長大了，都不知道你在想什麼」，語氣聽起來竟然有一點落寞。","c":[{"t":"尷尬地回「都馬一樣啦」，把話帶過","q":1,"tag":"◐ 門開了一條縫，你輕輕把它帶上——記住那個落寞，它是爸爸版的已讀不回。"},{"t":"回嗆「你們也不知道要跟我聊什麼」","q":2,"tag":"內容是事實，語氣是反擊——同一句話換個說法，就是橋而不是牆。"},{"t":"提議每週一次「不談功課」的晚餐","q":0,"tag":"✓ 固定的、小小的、有點好笑的家庭儀式——關係的保養靠這個，不靠大和解。"},{"t":"默默分析爸爸的關注圈和影響圈","q":3,"tag":"☯ 圈圈是拿來檢視自己的，不是拿來歸類爸爸——他要的是被接住，不是被分析。"},{"t":"回「長大本來就這樣」，把他推開","q":4,"tag":"⚠ 一句「正常啦」把落寞輕輕推開——橋遞到面前還轉身，下次橋就不來了。"}]},{"h":6,"text":"好友每晚打電話跟你倒心事，一講就到半夜，你白天精神越來越差，今晚九點，她的來電又在螢幕上亮起。","c":[{"t":"接起說「我聽到九點半，這段認真聽」","q":0,"tag":"✓ 有時限的傾聽反而更有品質——界線不是拒絕，是讓「我願意聽」可以永續。"},{"t":"不接不回，明天在學校再裝作沒事","q":1,"tag":"◐ 突然消失的樹洞會讓她腦補一百種劇情——誠實說今天沒電，比失蹤溫柔。"},{"t":"想說知彼解己，聽到幾點都該奉陪","q":3,"tag":"☯ 知彼解己沒教你無限傾聽——乾掉的樹洞連「嗯」都心不在焉，對她也不公平。"},{"t":"嘆口氣接起來，又被講到十一點半","q":2,"tag":"不好意思拒絕，就用自己的睡眠付帳——次次透支的友情，遲早兩敗俱傷。"},{"t":"接起來開擴音，邊打遊戲邊敷衍她","q":4,"tag":"⚠ 人在線、心不在——她感覺得到，你也沒休息到，兩個人的時間一起浪費。"}]},{"h":6,"text":"你是班上公認的傾聽高手，大家心情差都來找你，某天你自己心情跌到谷底，卻發現竟然想不出可以打給誰。","c":[{"t":"覺得自己消化就好，不必麻煩別人","q":1,"tag":"◐ 「都自己扛」聽起來很強——但幫全世界充電、自己沒有充電線的人，先沒電。"},{"t":"盤點誰認真聽過你說話，試著開口","q":0,"tag":"✓ 健康的友情要雙向流動——真朋友會接住你；接不住的，你也該早點知道。"},{"t":"覺得示弱很丟臉，發限動反串沒事","q":4,"tag":"⚠ 「示弱沒面子」正是讓你乾涸的咒語——只出不進的帳戶，最後一定破產。"},{"t":"想不出名字，就當作沒這回事算了","q":2,"tag":"想不出名字，本身就是答案——這不丟臉，這是一次重要的人際盤點。"},{"t":"繼續當最好的樹洞，多存情感帳戶","q":3,"tag":"☯ 情感帳戶不是單向存款——只供水不取水的泉，乾的會是你自己。"}]},{"h":6,"text":"好友阿哲天天熬夜打手遊，氣色越來越差，你想拉他一起去運動，但又怕開口像爸媽在說教，反而被他嗆回來。","c":[{"t":"直接勸他要多運動，熬夜對身體不好","q":2,"tag":"你說的全對——而「全對的說教」是全世界最沒用的東西，只會換來一句你是我媽喔。"},{"t":"約他陪跑最後一圈，跑完請吃鹹酥雞","q":0,"tag":"✓ 拉人充電的秘訣：把泉水包在他想要的東西裡——鹹酥雞永遠贏過健康講座。"},{"t":"先知彼解己，約他深談熬夜的根源","q":3,"tag":"☯ 知彼解己是好功夫，但他會覺得被審問——先用邀約讓身體動起來，談心自然發生。"},{"t":"尊重他的選擇，各人造業就各人擔","q":1,"tag":"◐ 尊重沒有錯，但「邀請」跟「說教」是兩回事——遞一次充電線，被拒絕也不虧。"},{"t":"在班群公開虧他黑眼圈，想用激將法","q":4,"tag":"⚠ 公開羞辱不是激勵——他只會更防備你，友情跟健康一起賠進去。"}]},{"h":6,"text":"阿哲跑出興趣後反過來揪你報名路跑，比賽當天清晨卻下起大雨，他傳訊息說「下雨欸……不然我們算了？」","c":[{"t":"回「是你揪我的欸，自己先落跑喔」","q":2,"tag":"指責讓他更不想去——他需要的是一個雨天也想去的理由，不是罪惡感。"},{"t":"回「雙贏嘛，改天天晴我們再補跑」","q":3,"tag":"☯ 這不是雙贏是雙輸——剛萌芽的習慣最怕第一次找到藉口，下次的雨會變成風。"},{"t":"回「好喔那算了」，心裡有點失落","q":1,"tag":"◐ 取消了也沒怎樣——只是你知道，藉口的門一開，之後會越開越大。"},{"t":"回「小雨而已，跑完一起去喝熱湯」","q":0,"tag":"✓ 共同的傻事是友情最高純度的泉水——雨中跑完的這一場，你們會記得很多年。"},{"t":"回「隨便你，反正我自己跑我的」","q":4,"tag":"⚠ 一句帶刺的隨便你，把他推回沙發——最後一哩要給台階，不是給臉色。"}]},{"h":6,"text":"班群一天幾百則訊息，你怕漏掉重要通知整天緊盯，晚上讀書每五分鐘就忍不住點開看，越來越沒辦法專心。","c":[{"t":"把群組調成靜音，但還是會一直點開","q":1,"tag":"◐ 靜音只關了鈴聲沒關牽掛——手還會自己伸過去，要配上時段規則才有效。"},{"t":"繼續緊盯著，怕漏訊息會被大家排擠","q":2,"tag":"用整晚的專注力換「即時已讀」，是最虧的交易——真正重要的事會再說一次。"},{"t":"想擴大影響圈，勸全班改掉洗版習慣","q":3,"tag":"☯ 全班的發言習慣在你的關注圈——你能掌握的，是自己的通知設定和節奏。"},{"t":"乾脆邊滑邊讀，自認兩邊都不耽誤","q":4,"tag":"⚠ 一心二用是雙倍浪費——書沒讀進去，訊息也沒真的看，兩頭空。"},{"t":"約定時段看群組，讀書時開勿擾模式","q":0,"tag":"✓ 分批處理訊息是心智的斷捨離——重要通知不會跑掉，專注力跑掉就回不來。"}]},{"h":6,"text":"你發現自己除了課本，已經整整一年沒讀過任何課外書，寫作文老是擠不出東西，講話也覺得腦袋空空沒材料。","c":[{"t":"覺得課內都讀不完，哪有空看閒書","q":2,"tag":"把課外書當「閒」書，是最常見的誤會——它正是讓課內讀得更快的磨刀石。"},{"t":"想以終為始，只讀會考的作文範文","q":3,"tag":"☯ 以終為始被用成「只為考試而讀」——心智更新要自選的活水，不是又一份考科。"},{"t":"每天睡前讀二十分鐘自己選的書","q":0,"tag":"✓ 閱讀是心智的日常保養——每天一小段自選的養分，一年後就是別人追不上的差距。"},{"t":"買了三本新書，放在床頭一直沒翻","q":1,"tag":"◐ 買書的成就感最會偽裝成進步——書到了，人沒到，更新還沒有發生。"},{"t":"用短影音代替，看過片段就算讀過","q":4,"tag":"⚠ 三十秒的碎片疊不成理解——你得到的是「看過的錯覺」，不是能用的材料。"}]},{"h":6,"text":"你常常一週過完就想不起自己做過什麼，煩惱總在腦中打轉理不清，老師建議你試著每天睡前寫幾行日記。","c":[{"t":"每晚睡前寫三行，記下想法和心情","q":0,"tag":"✓ 書寫是心靈的更新——煩惱寫下來就從腦中搬到紙上，人生也開始留下軌跡。"},{"t":"買了漂亮的日記本，只寫了第一天","q":1,"tag":"◐ 儀式感開了頭，習慣才是主角——把門檻降到三行，比買十本日記本有用。"},{"t":"覺得寫日記很像小學生，懶得動筆","q":2,"tag":"把反思當幼稚，是把最強的工具留在倉庫——寫下來的人生，才追蹤得到成長。"},{"t":"想說要事第一，時間應該留給讀書","q":3,"tag":"☯ 要事第一不等於只有讀書——每天幾分鐘的反思正是不急但重要的第二象限。"},{"t":"改成睡前滑手機，回顧別人的一天","q":4,"tag":"⚠ 看別人的精彩代替整理自己的生活——滑完更空虛，還賠上睡眠。"}]},{"h":6,"text":"媽媽想幫你再加一科補習，但你的週間晚上已經全被補習班填滿，連好好吃晚餐和準時睡覺的時間都被壓縮了。","c":[{"t":"提議加補新科，但用熬夜補寫作業","q":3,"tag":"☯ 這不是雙贏——雙贏是不犧牲任何一方，拿睡眠當籌碼，輸掉的是你自己。"},{"t":"心裡很不願意，但不敢說就先答應","q":1,"tag":"◐ 不敢說出口，行程就替你說了——被塞爆的時間表，最後用成績單抗議。"},{"t":"想說大家都在補，多補總比少補好","q":2,"tag":"把補習當保險買心安——沒有消化時間的課，上再多也只是坐在那裡。"},{"t":"跟媽媽大吵，摔門喊你根本不懂我","q":4,"tag":"⚠ 訴求可能是對的，方式毀了它——摔上的門，把溝通的路也一起關了。"},{"t":"跟媽媽談，保留消化吸收和休息時間","q":0,"tag":"✓ 學習要有留白才吸收得了——敢跟媽媽談自己的節奏，是替鋸子爭取磨刀時間。"}]},{"h":6,"text":"掃地時間你負責外掃區，總覺得很浪費時間，想躲回教室趕作業，但你其實已經連續坐著讀了一整個上午。","c":[{"t":"想說要事第一，作業當然比掃地重要","q":3,"tag":"☯ 要事第一沒教你偷懶——久坐後的活動正是保養身體的要事，它也是大石頭。"},{"t":"認真掃完，順便活動筋骨曬曬太陽","q":0,"tag":"✓ 十五分鐘的勞動是免費的更新——身體動了、腦袋醒了，回教室讀得更快。"},{"t":"躲回教室趕作業，時間能省則省","q":2,"tag":"看似賺到十五分鐘，其實用僵掉的身體讀下午——省小條賠大條。"},{"t":"隨便掃兩下，站在原地發呆等結束","q":1,"tag":"◐ 至少離開了座位——但同樣的十五分鐘，伸展曬太陽的回血量差好幾倍。"},{"t":"拗同學幫你掃，自己躲回去補眠","q":4,"tag":"⚠ 把自己的責任丟給別人——省了力氣，賠了信用，情感帳戶默默扣款。"}]},{"h":6,"text":"會考剩一百天，全班瀰漫緊繃氣氛，你想維持每週打一次球的習慣，同學卻笑你都要考試了竟然還敢去玩。","c":[{"t":"減成兩週打一次，心裡有點捨不得","q":1,"tag":"◐ 有保留就是好事，但更新的頻率一降，效果常常跟著斷——規律比份量重要。"},{"t":"被笑到心虛，乾脆跟著大家停掉","q":2,"tag":"用別人的焦慮決定自己的節奏——全班都不磨鋸子，不代表鈍鋸子是對的。"},{"t":"照打不誤，運動讓讀書更有效率","q":0,"tag":"✓ 越是長期抗戰越要磨鋸子——每週流一次汗，是給後面九十九天的體力存款。"},{"t":"想知彼解己，先說服全班一起去打","q":3,"tag":"☯ 概念是好的，但你不需要全班同意才能保養自己——影響圈先顧好自己的節奏。"},{"t":"表面停掉，改成半夜偷躲被窩打手遊","q":4,"tag":"⚠ 把健康的出口換成傷身的出口——運動被沒收，睡眠也一起陪葬。"}]},{"h":6,"text":"你對剪影片很有興趣，暑假有整整兩個月的空檔想自學剪輯，但又怕爸媽覺得你只是在找藉口整天玩電腦。","c":[{"t":"想想還是算了，暑假拿去補習保險","q":2,"tag":"把發光的興趣讓位給「比較安全」——大腦最想學的時刻，就這樣被退貨了。"},{"t":"引用主動積極，先斬後奏不必多說","q":3,"tag":"☯ 主動積極不是繞過溝通——少了爸媽的理解，你的學習隨時會被整組沒收。"},{"t":"偷偷亂剪著玩，沒有系統地學習","q":1,"tag":"◐ 有動手就是好開始，但沒有計畫的摸索，兩個月後容易只剩一堆半成品。"},{"t":"排出每日練習表，跟爸媽說明後開始","q":0,"tag":"✓ 自選的學習加上透明的計畫——心智更新最強的組合，爸媽也會從阻力變後援。"},{"t":"騙爸媽說在寫作業，實際整天摸電腦","q":4,"tag":"⚠ 用謊言換來的學習時間，被拆穿那天連信任一起賠——最貴的學費。"}]},{"h":6,"text":"你和最要好的朋友升上不同班之後，只剩下課擦肩打個招呼，你感覺這段友情正在變淡，心裡有一點慌。","c":[{"t":"想約又怕尷尬，只默默按讚他的限動","q":1,"tag":"◐ 按讚是打卡不是連結——牽掛已經有了，差的只是開口的那一步。"},{"t":"覺得變淡很正常，一切就隨緣吧","q":2,"tag":"感情確實會變，但「隨緣」常常是「不想努力」的漂亮說法——泉水要有人打。"},{"t":"背熟情感帳戶概念，等他先來存款","q":3,"tag":"☯ 帳戶概念記得牢，但存款要自己先動手——雙方都在等的帳戶，只會歸零。"},{"t":"故意冷回他訊息，測試他在不在乎你","q":4,"tag":"⚠ 用冷戰測感情，是拿友情玩剪刀石頭布——測出來的只有互相受傷。"},{"t":"主動約每週五放學，一起走路回家聊","q":0,"tag":"✓ 關係靠固定的小儀式維持——每週一段路的深聊，比一百個讚都更能保鮮。"}]},{"h":6,"text":"爸爸提議週日全家去爬山，你原本計畫整天在家打電動放鬆，覺得爬山又累又無聊，正想找個理由拒絕他。","c":[{"t":"答應同行，運動和家人時光一次補足","q":0,"tag":"✓ 一趟山路同時充了身體和情感兩座電——這種一舉兩得的更新，錯過最可惜。"},{"t":"提雙贏方案：他們去爬山，我看家","q":3,"tag":"☯ 這叫各過各的，不叫雙贏——你躲掉的，正是身體與親情兩個面向的泉水。"},{"t":"拒絕，放假就是要耍廢才叫做放鬆","q":2,"tag":"把「癱著」當唯一的放鬆——電動打完的空虛感，比爬山的鐵腿消失得更慢。"},{"t":"勉強跟去，但全程戴耳機自己走","q":1,"tag":"◐ 人到了心沒到——身體有動到，但同行的意義少了一半，可惜了這趟山。"},{"t":"擺爛賴床裝睡，讓全家出發不了","q":4,"tag":"⚠ 用擺爛綁架全家的週日——你多睡兩小時，賠掉的是全家人的興致。"}]},{"h":6,"text":"你最近看黑板越來越模糊，眼科檢查說近視又加深一百度，醫生要你減少手機時間、每半小時記得看遠方休息。","c":[{"t":"覺得反正配一副新眼鏡就解決了","q":2,"tag":"眼鏡解決「看不清」，沒解決「繼續壞」——治標的方便，最容易養出大問題。"},{"t":"訂用眼三十分鐘就休息五分鐘的規則","q":0,"tag":"✓ 眼睛是用一輩子的配備——固定的休息規則，就是替它做最基本的定期保養。"},{"t":"想說度數在關注圈，一切隨緣就好","q":3,"tag":"☯ 度數變化你無法直接控制沒錯，但用眼習慣百分百在影響圈——概念不是擺爛藉口。"},{"t":"有想到才休息，多半還是滑到整晚","q":1,"tag":"◐ 「想到才做」的保養等於沒有系統——沒有規則撐著，好意撐不過三天。"},{"t":"繼續躲被窩關燈滑，反正已經近視了","q":4,"tag":"⚠ 「反正已經壞了」是自暴自棄的邏輯——一百度之後，還有下一個一百度。"}]},{"h":6,"text":"學校招募圖書館志工，每週只要服務一小時，你有點心動，但同學笑說當志工又沒加分，根本是浪費讀書時間。","c":[{"t":"心動但怕被笑，決定先觀望一陣子","q":1,"tag":"◐ 讓別人的眼光替你按暫停——想做的事排隊排太久，心動就過期了。"},{"t":"沒加分就不做，時間拿去多讀點書","q":2,"tag":"用「有沒有加分」過濾人生，會漏掉最重要的東西——不是每種收穫都印在成績單。"},{"t":"報名參加，服務的意義感就是充電","q":0,"tag":"✓ 為別人做點事，是心靈面最深層的更新——意義感給的電，讀書給不了。"},{"t":"想要事第一，志工排不進我的大石頭","q":3,"tag":"☯ 要事不是只有考試——滋養心靈的事正是第二象限的大石頭，不急，但重要。"},{"t":"報了名卻常常放鴿子，讓館員空等","q":4,"tag":"⚠ 半途而廢還連累別人——志工沒當成，反而先透支了自己的信用。"}]},{"h":6,"text":"你平日只睡六小時，假日睡到中午想補回來，結果每到週一早上反而最累，上課恍神得像時差沒調過來一樣。","c":[{"t":"說這就是磨鋸子，睡越多磨得越利","q":3,"tag":"☯ 磨鋸子講的是規律保養，不是報復式狂睡——亂掉的生理時鐘，越補越鈍。"},{"t":"覺得假日補眠天經地義，繼續睡到午","q":2,"tag":"週末狂睡等於幫身體倒時差——補的是心理安慰，付的是週一的恍神。"},{"t":"平日提早半小時睡，假日照睡到中午","q":1,"tag":"◐ 平日有改善是好事，但假日一亂，節奏又歸零——差的就是最後那一步。"},{"t":"平日假日固定時間睡醒，穩住節奏","q":0,"tag":"✓ 睡眠要的是規律不是總量——穩定的生理時鐘，是身體更新最便宜的方法。"},{"t":"乾脆週日通宵，想說反正已經睡飽了","q":4,"tag":"⚠ 「睡飽了所以能熬」是最危險的算術——通宵一晚，毀掉整週的節奏。"}]},{"h":6,"text":"段考成績出來，你的數學比上次進步了十分，你很開心，隱約覺得這次換的讀書方法好像真的有一點用。","c":[{"t":"開心慶祝一番，方法沒特別記下來","q":1,"tag":"◐ 慶祝值得，但沒記下有效的方法，下次就只能重新猜一次——經驗白白蒸發。"},{"t":"記下有效的做法，微調後下次再用","q":0,"tag":"✓ 檢視、修正、再行動——上進的螺旋就是這樣轉的，每一圈都比上一圈高。"},{"t":"覺得只是運氣好，下次再看著辦吧","q":2,"tag":"把進步歸給運氣，等於把方向盤交給機率——十分的證據，值得認真對待。"},{"t":"想以終為始，直接立志下次考滿分","q":3,"tag":"☯ 大目標很熱血，但螺旋是靠檢視和修正墊上去的——跳過整理，口號撐不住。"},{"t":"拿成績去嗆退步的同學，炫耀一波","q":4,"tag":"⚠ 用別人的低潮墊高自己——十分還沒站穩，人緣先掉了二十分。"}]},{"h":6,"text":"你從小學就開始學吉他，上國中後爸媽建議停課專心讀書，但彈琴一直是你最重要的紓壓出口和開心的來源。","c":[{"t":"跟爸媽談，保留每週固定彈琴的時間","q":0,"tag":"✓ 為自己的充電來源談判——說得出「彈琴讓我讀得更穩」的人，最有說服力。"},{"t":"引用以終為始：目標是會考，先犧牲","q":3,"tag":"☯ 以終為始的「終」是完整的人生，不是一場考試——砍掉充電來源，續航更短。"},{"t":"聽話全部停掉，讀書當然比較重要","q":2,"tag":"看似懂事，其實把壓力的出口堵死了——沒有出口的水庫，遲早從別處潰堤。"},{"t":"停了課但偶爾自己彈，越彈越少","q":1,"tag":"◐ 火還沒滅但沒人添柴——沒有固定時段保護的興趣，會安靜地熄掉。"},{"t":"表面答應停課，偷拿補習費去上吉他","q":4,"tag":"⚠ 用欺騙保住興趣，拆穿那天連吉他一起沒收——誠實談判才是長久之道。"}]},{"h":6,"text":"你每天花兩小時看短影音，覺得也吸收了不少冷知識，但要你講出上週到底看過什麼，腦中卻是一片空白。","c":[{"t":"覺得有看有學到，放鬆順便長知識","q":2,"tag":"「有看過」和「學到了」差一整個檔次——講不出來的知識，等於沒有。"},{"t":"引統合綜效，多開幾個平台一起刷","q":3,"tag":"☯ 綜效是深度合作產生一加一大於二，不是多開視窗——碎片再多，疊不成理解。"},{"t":"改追一個主題，看完寫兩行心得","q":0,"tag":"✓ 從亂餵到定食，從滑過到留下——加上輸出的那一步，資訊才變成你的東西。"},{"t":"繼續看但先收藏，想說以後再整理","q":1,"tag":"◐ 收藏夾是資訊的墳墓——「以後整理」的以後，通常永遠不會來。"},{"t":"熬夜刷到凌晨兩點，自稱自主學習","q":4,"tag":"⚠ 拿學習當熬夜的遮羞布——賠了睡眠又沒留下東西，雙重虧損。"}]},{"h":6,"text":"會考複習是一場長達八個月的長跑，你看到同學一開學就天天熬夜猛衝，你越看越焦慮，猶豫該不該跟著衝。","c":[{"t":"跟著猛衝，怕慢人一步就輸在起點","q":2,"tag":"用別人的焦慮設定自己的油門——八個月的賽道上，最先燒完的是猛衝的人。"},{"t":"訂讀四十五分、休十分的穩定節奏","q":0,"tag":"✓ 能跑完八個月的是懂配速的人——攻擊與充電交替，電量才穩得住整場。"},{"t":"先跟著衝一陣子，撐不住的話再調","q":1,"tag":"◐ 「撐不住再調」通常是垮掉才調——節奏要在開跑前設計，不是崩潰後補救。"},{"t":"引主動積極，操得越兇代表越主動","q":3,"tag":"☯ 主動積極是選有效的行動，不是自虐式硬撐——把自己操壞，是最被動的結局。"},{"t":"覺得反正還早，前半年先耍廢再說","q":4,"tag":"⚠ 從一個極端盪到另一個極端——長跑輸給猛衝的不多，輸給棄賽的最多。"}]}];
window.DUEL_QS=window.DUEL_QS_JR;
